-- Poems batch 142
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b6d645ec-63b8-47a4-ae4c-05743cf031df','過樟木鎮晚晴二首  其一','朱熹','宋','宋诗','song-poetry','','[]','朝晴遣我看薌林，頃刻浮雲萬里陰。',32,'全唐诗/poet.song.148000.json','["朝晴遣我看薌林，頃刻浮雲萬里陰。", "拂袖凌風三十里，依然寒日照長吟。"]'),
('0049f460-5ddb-4555-9555-be89659a01ad','過樟木鎮晚晴二首  其二','朱熹','宋','宋诗','song-poetry','','[]','飛雲極目疑梅嶺，落日回頭夢橘洲。',32,'全唐诗/poet.song.148000.json','["飛雲極目疑梅嶺，落日回頭夢橘洲。", "從此不愁東路永，祇應西望轉悠悠。"]'),
('5d84ec05-d7a0-4d05-8abe-996be439eb8a','赤岡頭望遠山作','朱熹','宋','宋诗','song-poetry','','[]','曉起清江弄小舟，晚風吹過赤岡頭。',32,'全唐诗/poet.song.148000.json','["曉起清江弄小舟，晚風吹過赤岡頭。", "遠峰自作脩眉歛，萬里那知客子愁。"]'),
('b389238c-d6bd-44fa-8ebe-7fc3889b4b3a','次韻擇之發臨江','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','千里烟波一葉舟，三年已是兩經由。',32,'全唐诗/poet.song.148000.json','["千里烟波一葉舟，三年已是兩經由。", "今宵又過豐城縣，依舊長江直北流。"]'),
('fb6f41f8-fa7b-465d-a07d-45d280fef292','次韻擇之漫成','朱熹','宋','宋诗','song-poetry','','[]','落日晴江更遠山，遠山猶在有無間。',32,'全唐诗/poet.song.148000.json','["落日晴江更遠山，遠山猶在有無間。", "不須極目傷懷抱，且看漁船近往還。"]'),
('4b356d37-2e55-492c-942a-65dfc2df2fea','竹節灘','朱熹','宋','宋诗','song-poetry','','[]','船下清江竹節灘，長烟漠漠水漫漫。',32,'全唐诗/poet.song.148000.json','["船下清江竹節灘，長烟漠漠水漫漫。", "人家斷岸斜陽好，客子中流薄暮寒。"]'),
('38d95860-7c2e-4070-a9ca-3081ae113faa','舟中晚賦','朱熹','宋','宋诗','song-poetry','','[]','長風一萬里，披豁暮雲空。',48,'全唐诗/poet.song.148000.json','["長風一萬里，披豁暮雲空。", "極浦三年夢，扁舟二子同。", "離離浮遠樹，杳杳沒孤鴻。", "若問明朝事，西山晻靄中。"]'),
('6253a1d1-dff5-4145-bb96-bc7e3a4bb437','次韻擇之將近豐城有作','朱熹','宋','宋诗','song-poetry','','[]','老矣身如萬斛舟，長風破浪若爲收。',32,'全唐诗/poet.song.148000.json','["老矣身如萬斛舟，長風破浪若爲收。", "江山若有逢迎意，到處何妨爲少留。"]'),
('9da67925-1fc1-4d5f-8d3e-2c73d9029a92','過豐城作','朱熹','宋','宋诗','song-poetry','','[]','渺渺豐城縣，回頭憶舊遊。',48,'全唐诗/poet.song.148000.json','["渺渺豐城縣，回頭憶舊遊。", "晴江羅遠樹，宿莽亂中洲。", "寶劍今鱗甲，神光尚斗牛。", "他年還記得，此夜一扁舟。"]'),
('9451ad20-1dda-492a-b35a-8acb6c029bd2','舟中見新月伯崇擇之二友皆已醉卧以此戲之','朱熹','宋','宋诗','song-poetry','','[]','舟中見新月，烟浪不勝寒。',48,'全唐诗/poet.song.148000.json','["舟中見新月，烟浪不勝寒。", "與問醉眠客，豈知行路難。", "殘陽猶水面，孤鴈更雲端。", "篷底今宵意，天邊芳歲闌。"]'),
('3738b8bb-5e6c-48a7-aa65-3c931e9c36df','次韻擇之舟中有作二首  其一','朱熹','宋','宋诗','song-poetry','','[]','一江烟水浩漫漫，昨夜扁舟寄此間。',32,'全唐诗/poet.song.148000.json','["一江烟水浩漫漫，昨夜扁舟寄此間。", "共向船頭望南北，不知何處是家山。"]'),
('b6d4ba9d-1b2a-497a-8f6e-10cf98dddf73','次韻擇之舟中有作二首  其二','朱熹','宋','宋诗','song-poetry','','[]','一席三人抵項眠，心知篷外水如天。',32,'全唐诗/poet.song.148000.json','["一席三人抵項眠，心知篷外水如天。", "起來却怪天如水，月落烏啼浦樹邊。"]'),
('e0fa24ce-063d-409a-9689-3d9b808f4265','自東湖至列岫得二小詩  其一','朱熹','宋','宋诗','song-poetry','','[]','孺子高風何處尋，東湖臺觀水雲深。',32,'全唐诗/poet.song.148000.json','["孺子高風何處尋，東湖臺觀水雲深。", "生芻一束人如玉，此日凄凉萬古心。"]'),
('56186ee4-2e42-495d-9c38-51943594d54a','自東湖至列岫得二小詩  其二','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昨日來時萬里陰，長江雪後玉千岑。',32,'全唐诗/poet.song.148000.json','["昨日來時萬里陰，長江雪後玉千岑。", "蒼茫不盡登臨意，重對晴天豁晚襟。"]'),
('0ecb4549-07d9-445d-8d39-a8160c44fab2','列岫望西山最正殆無毫髮遺恨滕王秋屏皆不及也因作此詩二首  其一','朱熹','宋','宋诗','song-poetry','','[]','城中望西山，拄頰空朝暮。',24,'全唐诗/poet.song.148000.json','["城中望西山，拄頰空朝暮。", "不到列岫亭，詎知親切處。"]'),
('3737c911-2097-4860-8e2b-277cf6efcee0','列岫望西山最正殆無毫髮遺恨滕王秋屏皆不及也因作此詩二首  其二','朱熹','宋','宋诗','song-poetry','','[]','東西水平分，南北山中判。',24,'全唐诗/poet.song.148000.json','["東西水平分，南北山中判。", "妙處毫髮間，商略無遺算。"]'),
('263fed57-0c65-482e-b4f9-266233486f2b','晚飲列岫','朱熹','宋','宋诗','song-poetry','','[]','危亭披豁對蒼霞，策杖重來日未斜。',32,'全唐诗/poet.song.148000.json','["危亭披豁對蒼霞，策杖重來日未斜。", "滿目江山一尊酒，哦詩莫遣太雄誇。"]'),
('38895671-d9b6-4091-860d-cd5cf13ca363','觀上藍賢老所藏張魏公手帖次王嘉叟韻','朱熹','宋','宋诗','song-poetry','','[]','火風吹散旱天雲，膚寸空餘翰墨新。',32,'全唐诗/poet.song.148000.json','["火風吹散旱天雲，膚寸空餘翰墨新。", "拭淚相看渺今古，堂堂那復有斯人。"]'),
('8a27b7c4-b319-4035-9bb4-bfd7595d4b59','次韻伯崇登滕王閣感舊蓋聞往時延閣公拜疏於此云','朱熹','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','金闕銀臺夢想中，樓前拜舞皂囊空。',32,'全唐诗/poet.song.148000.json','["金闕銀臺夢想中，樓前拜舞皂囊空。", "十年殄瘁無窮恨，歎息今人少古風。"]'),
('0aec230f-b498-4aa6-bddc-c365564edcde','觀西山懷嶽麓以爲莫能相上下也聊賦此云','朱熹','宋','宋诗','song-poetry','','[]','風月平生意，江湖自在身。',48,'全唐诗/poet.song.148000.json','["風月平生意，江湖自在身。", "年華供轉徙，眼界得清新。", "試問西山雨，何如湘水春。", "悠然一長嘯，妙絕兩無倫。"]'),
('1ac167a2-c4cb-46aa-a6af-ea2248a9ee4c','進賢道中','朱熹','宋','宋诗','song-poetry','','[]','往辭湘水曲，今過豫章城。',48,'全唐诗/poet.song.148000.json','["往辭湘水曲，今過豫章城。", "改歲無多日，到家才幾程。", "晝憐春意迫，夜喜月華清。", "此去無淹軌，前塗似掌平。"]'),
('6af0fab0-8676-4494-9d0b-82456128802b','野望','朱熹','宋','宋诗','song-poetry','','[]','登高立馬瞰晴川，四面平林接暝烟。',32,'全唐诗/poet.song.148000.json','["登高立馬瞰晴川，四面平林接暝烟。", "東望不堪頻極目，歸心已度鳥飛前。"]'),
('09f5cc7b-b5e2-40fd-b755-4c59d2a5d7a1','次韻擇之進賢道中漫成五首  其一','朱熹','宋','宋诗','song-poetry','','[]','白酒頻斟當啜茶，何妨一醉野人家。',32,'全唐诗/poet.song.148000.json','["白酒頻斟當啜茶，何妨一醉野人家。", "據鞍又向岡頭望，落日天風鴈字斜。"]'),
('7a2aa904-8b70-45b2-8fd0-f0c043055940','次韻擇之進賢道中漫成五首  其二','朱熹','宋','宋诗','song-poetry','','[]','笑指斜陽天外山，無端長作翠眉攢。',32,'全唐诗/poet.song.148000.json','["笑指斜陽天外山，無端長作翠眉攢。", "豈知男子桑蓬志，萬里東西不作難。"]'),
('27dc4196-7fa1-498c-ad4a-cda77679f113','次韻擇之進賢道中漫成五首  其三','朱熹','宋','宋诗','song-poetry','','[]','夜宿林岡月滿川，歸期屈指正茫然。',32,'全唐诗/poet.song.148000.json','["夜宿林岡月滿川，歸期屈指正茫然。", "也知地脈無贏縮，只把陰晴更問天。"]'),
('39f6ff2a-0ada-4688-bfcf-35a4efd901eb','次韻擇之進賢道中漫成五首  其四','朱熹','宋','宋诗','song-poetry','','[]','誰作窗間擁鼻聲，更哦樂府短歌行。',32,'全唐诗/poet.song.148000.json','["誰作窗間擁鼻聲，更哦樂府短歌行。", "從教永夜清無寐，只恐晨雞不肯鳴。"]'),
('e8211ac6-8575-4f2a-8e55-f3a82167f484','次韻擇之進賢道中漫成五首  其五','朱熹','宋','宋诗','song-poetry','','[]','日暮重岡上，人勞馬亦饑。',24,'全唐诗/poet.song.148000.json','["日暮重岡上，人勞馬亦饑。", "不妨隨野雀，容易宿寒枝。"]'),
('a7b770c6-aa73-46e3-a18b-f864917bacee','次韻擇之夜宿進賢客舍','朱熹','宋','宋诗','song-poetry','','[]','白日照寒野，緬然千里平。',60,'全唐诗/poet.song.148000.json','["白日照寒野，緬然千里平。", "馳暉一以沒，浩蕩驚飆生。", "露彩林表見，月華波上明。", "同行魯狂士，忽發商歌聲。", "洗耳金石奏，信知塵累輕。"]'),
('dc1c85ed-3428-446c-ba04-75bc8328829d','次韻擇之潤陂有作','朱熹','宋','宋诗','song-poetry','','[]','我行欲安適，莽莽窮山陂。',72,'全唐诗/poet.song.148000.json','["我行欲安適，莽莽窮山陂。", "晨裝遠林表，午憩通川湄。", "曠望想慈親，行役嗟吾兒。", "喟然陟屺歎，歸心浩無涯。", "曉霜徒御寒，暮雨朋儔悲。", "前期諒非遠，無爲苦愁思。"]'),
('f3cb4a89-85de-440c-9e8c-a8b2bef5a282','過潤陂日晴意可喜至暮復雨伯崇有詩因次其韻','朱熹','宋','宋诗','song-poetry','','[]','客裏歲云暮，我心殊未平。',60,'全唐诗/poet.song.148000.json','["客裏歲云暮，我心殊未平。", "悠悠惜往日，鬰鬰懷平生。", "况復久陰雨，喜茲霜曉明。", "那知不終日，又作瀟瀟聲。", "坐厭泥塗辱，空嗟鴻鴈輕。"]'),
('058314a7-9709-4b5b-9a1c-ac07635d7c35','山行兩日至金步復見平川行夷路計程七日可到家矣','朱熹','宋','宋诗','song-poetry','','[]','行穿側徑度荒山，又踏深泥過野田。',64,'全唐诗/poet.song.148000.json','["行穿側徑度荒山，又踏深泥過野田。", "路轉忽然開遠望，眼明復此見平川。", "江烟浦樹悲重疊，楚水閩山喜接連。", "稅駕有期心轉迫，稜稜瘦馬不勝鞭。"]'),
('fd4092d0-d9c2-410f-9cb6-ef3838fa2617','次韻擇之金步喜見大江有作','朱熹','宋','宋诗','song-poetry','','[]','江頭四望遠峰稠，江水中間自在流。',32,'全唐诗/poet.song.148000.json','["江頭四望遠峰稠，江水中間自在流。", "並岸東行三百里，水源窮處即吾州。"]'),
('5cacf6fe-7046-4003-aed7-77940cb0abf9','次韻擇之餘干道中','朱熹','宋','宋诗','song-poetry','','[]','寒盡春生草又青，化工消息幾曾停。',32,'全唐诗/poet.song.148000.json','["寒盡春生草又青，化工消息幾曾停。", "因君一詠陵陂麥，恍憶儂家老圃亭。"]'),
('8458de18-a440-4ad3-b9b1-8fb0ddc5539b','安仁曉行','朱熹','宋','宋诗','song-poetry','','[]','夙駕安仁道，行行得自娛。',48,'全唐诗/poet.song.148000.json','["夙駕安仁道，行行得自娛。", "荒山圍野闊，遠樹出林孤。", "景晦長煙合，天寒碧草枯。", "歸心懷往路，極目向平蕪。"]'),
('08170816-e6b5-4769-a49f-b66849a7a9ce','十七日早霜晴觀日出霧中喜而成詩','朱熹','宋','宋诗','song-poetry','','[]','斜月夜窗白，肅霜朝氣清。',48,'全唐诗/poet.song.148000.json','["斜月夜窗白，肅霜朝氣清。", "長塗披素錦，寒霧湧金鉦。", "已作三冬雨，何妨十日晴。", "天公且相念，莫遣暮雲生。"]'),
('a2680d98-d74a-423e-be48-691ac344d4e1','再用前韻','朱熹','宋','宋诗','song-poetry','','[]','久陰冬竟暖，欲霽氣先清。',48,'全唐诗/poet.song.148000.json','["久陰冬竟暖，欲霽氣先清。", "田舍占煙火，軍家候鼓鉦。", "風霜千里肅，天地一朝晴。", "明日知何日，陽春又發生。"]'),
('303fd9b0-2192-4d34-b34c-479a71aaa188','次韻擇之過丫頭巖','朱熹','宋','宋诗','song-poetry','','[]','四面晴岡紫石崖，如何渾作白皚皚。',32,'全唐诗/poet.song.148000.json','["四面晴岡紫石崖，如何渾作白皚皚。", "須知暖入陰泉溜，不是寒封積雪堆。"]'),
('fcc49371-257c-4688-abff-756c8db398d7','章巖','朱熹','宋','宋诗','song-poetry','','[]','豁爾天開宇，呀然夜不扃。',48,'全唐诗/poet.song.148000.json','["豁爾天開宇，呀然夜不扃。", "閑雲任棲宿，密雨斷飄零。", "破屋僧常住，高軒客屢經。", "古今題寫處，一半蘚文青。"]'),
('2ae1a5d4-0213-4bb6-95ef-8c52d0d85bad','次韻擇之章巖','朱熹','宋','宋诗','song-poetry','','[]','驅馬倦長道，投鞭憩此巖。',48,'全唐诗/poet.song.148000.json','["驅馬倦長道，投鞭憩此巖。", "來應六鼇戴，跡是五丁劖。", "泉脈流青潤，林稍擁碧巉。", "老禪深閉戶，客子且征衫。"]'),
('be493bed-17d6-41fb-a42b-7cc8f389bf50','鉛山立春六言二首  其一','朱熹','宋','宋诗','song-poetry','','[]','雪擁山腰洞口，春迴楚尾吳頭。',28,'全唐诗/poet.song.148000.json','["雪擁山腰洞口，春迴楚尾吳頭。", "欲問閩天何處，明朝嶺水南流。"]'),
('7d3bac97-0cf1-4dcd-b87f-245e72ef2227','鉛山立春六言二首  其二','朱熹','宋','宋诗','song-poetry','','[]','行盡風林雪徑，依然水館山村。',28,'全唐诗/poet.song.148000.json','["行盡風林雪徑，依然水館山村。", "却是春風有脚，今朝先到柴門。"]'),
('a69c6455-5e48-47ac-a809-96a740911a8e','次二友石井之作三首  其一','朱熹','宋','宋诗','song-poetry','','[]','一竇陰風萬斛泉，新秋曾此弄清漣。',32,'全唐诗/poet.song.148000.json','["一竇陰風萬斛泉，新秋曾此弄清漣。", "人言湛碧深無底，只恐潛通小有天。"]'),
('6015959a-8a3e-4b13-ab0b-8f25a07bba82','次二友石井之作三首  其二','朱熹','宋','宋诗','song-poetry','','[]','聯騎君登泉上亭，黄塵雙眼想增明。',32,'全唐诗/poet.song.148000.json','["聯騎君登泉上亭，黄塵雙眼想增明。", "籃輿獨向溪南路，惆悵不成同隊行。"]'),
('c8567bd1-288f-4370-8dbc-2090e9a95e65','次二友石井之作三首  其三','朱熹','宋','宋诗','song-poetry','','[]','泉嵌側畔一川明，水石縈迴更有情。',32,'全唐诗/poet.song.148000.json','["泉嵌側畔一川明，水石縈迴更有情。", "聞說近來疏葺好，想應仍是舊溪聲。"]'),
('e52b248b-6650-4be2-9b5f-b803866f8922','次韻擇之鉛山道中二首  其一','朱熹','宋','宋诗','song-poetry','','[]','幾月高堂闕問安，歸塗不管上天難。',32,'全唐诗/poet.song.148000.json','["幾月高堂闕問安，歸塗不管上天難。", "誦君兩疊思親句，也信從來取友端。"]'),
('c1f8d17b-70cc-44a7-9dab-2055e7b24a22','次韻擇之鉛山道中二首  其二','朱熹','宋','宋诗','song-poetry','','[]','行盡江湘萬疊山，家山猶在有無間。',32,'全唐诗/poet.song.148000.json','["行盡江湘萬疊山，家山猶在有無間。", "明朝漸喜登閩嶺，澗水分流響珮環。"]'),
('c396c7e5-6563-4ef7-80cb-0fa8493f1549','次韻擇之發紫溪有作','朱熹','宋','宋诗','song-poetry','','[]','明日振衣千仞岡，夜分起看月和霜。',32,'全唐诗/poet.song.148000.json','["明日振衣千仞岡，夜分起看月和霜。", "久知行路難如此，不用悲歌淚滿裳。"]'),
('87b63f71-f404-482c-849e-b8993510c518','次韻別林擇之','朱熹','宋','宋诗','song-poetry','','[]','暫時相別不須悲，楚調凄凉政爾爲。',64,'全唐诗/poet.song.148000.json','["暫時相別不須悲，楚調凄凉政爾爲。", "幾曲清溪足相送，一天明月豈曾離。", "上堂嘉慶多爲問，緣道風光少賦詩。", "更謝同袍二三子，夜來幽夢滿春池。"]'),
('ebc105fe-4139-4080-9250-af3ec14cd7b6','次韻別范伯崇二首  其一','朱熹','宋','宋诗','song-poetry','','[]','平生罪我只春秋，更作囂囂萬里遊。',32,'全唐诗/poet.song.148000.json','["平生罪我只春秋，更作囂囂萬里遊。", "頼有吾人肯相伴，群譏衆詆不能憂。"]'),
('8108b906-4b9b-4a93-8c70-2b58afbfeb74','次韻別范伯崇二首  其二','朱熹','宋','宋诗','song-poetry','','[]','累月追隨今別離，人生離合豈無時。',32,'全唐诗/poet.song.148000.json','["累月追隨今別離，人生離合豈無時。", "願言更勵堅高志，力索窮探慰所思。"]'),
('e140e3df-5c1b-4fc2-b963-a240fa3662b8','有懷南軒老兄呈伯崇擇之二友二首  其一','朱熹','宋','宋诗','song-poetry','','[]','憶昔秋風裏，尋盟湘水傍。',48,'全唐诗/poet.song.148000.json','["憶昔秋風裏，尋盟湘水傍。", "勝遊朝挽袂，妙語夜連牀。", "別去多遺恨，歸來識大方。", "惟應微密處，猶欲細商量。"]'),
('dd5a9eb3-2ea1-410d-8358-91f2bb313520','有懷南軒老兄呈伯崇擇之二友二首  其二','朱熹','宋','宋诗','song-poetry','','[]','積雨芳菲暗，新晴始豁然。',48,'全唐诗/poet.song.148000.json','["積雨芳菲暗，新晴始豁然。", "園林媚幽獨，窗戶愜清妍。", "晤語心何遠，書題意未宣。", "懸知今夜月，同夢舞雩邊。"]'),
('b5ccdac0-bd4d-4daa-9721-dc224b8cd86f','九日登天湖以菊花須插滿頭歸分韻賦詩得歸字','朱熹','宋','宋诗','song-poetry','','[]','去歲瀟湘重九時，滿城寒雨客思歸。',64,'全唐诗/poet.song.148000.json','["去歲瀟湘重九時，滿城寒雨客思歸。", "故山此日還佳節，黄菊清罇更晚暉。", "短髮無多休落帽，長風不斷且吹衣。", "相看下視人寰小，祇合從今老翠微。"]'),
('5196bb5d-f63d-4e9b-be3d-24d7b7b7022c','歸報德再用前韻','朱熹','宋','宋诗','song-poetry','','[]','幾枝藤竹醉相携，何處千峰頂上歸。',64,'全唐诗/poet.song.148000.json','["幾枝藤竹醉相携，何處千峰頂上歸。", "正好臨風眺平野，却須入谷避斜暉。", "酒邊泉溜寒侵骨，坐上嵐光翠染衣。", "踏月過橋驚易晚，林坰回首更依微。"]'),
('01e04b50-45d5-4f59-9bce-768c107d3d97','雪中與林擇之祝弟登劉園之宴坐巖有懷南嶽舊遊賦此呈擇之屬和并寄敬夫兄','朱熹','宋','宋诗','song-poetry','','["\u8861\u5c71"]','風雪集歲晏，掩關聊自休。',168,'全唐诗/poet.song.148000.json','["風雪集歲晏，掩關聊自休。", "今辰展遐眺，倚此寒巖幽。", "同雲暗空室，皓彩迷林丘。", "崩奔小澗歇，飛舞增綢繆。", "仰看鸞鶴翔，俯視江漢流。", "乾坤有奇變，澒洞驚兩眸。", "三酌不自溫，倚杖空冥搜。", "悲歌動華薄，璀璨忽滿裘。", "向來一杯酒，浩蕩千里遊。", "亦復有茲賞，微言寄清酬。", "解携今幾許，光景逝不留。", "懷人眇山嶽，省己紛愆尤。", "對此奇絕境，一歡生百憂。", "茫然發孤詠，遠思誰能收。"]'),
('7374ff37-7ebd-41a0-b53f-6ca47f1f28f3','和人游西巖','朱熹','宋','宋诗','song-poetry','','[]','平生壯志浩無窮，老寄寒泉亂石中。',64,'全唐诗/poet.song.148000.json','["平生壯志浩無窮，老寄寒泉亂石中。", "閑去披襟弄清泚，靜來合眼聽玲瓏。", "不知澗寺晴時雨，何似溪亭落處風。", "吟罷君詩自瀟灑，此心端不限西東。"]'),
('03f3a8b7-be9b-42c2-a8b8-2998ef222311','次知郡章丈遊山之韻','朱熹','宋','宋诗','song-poetry','','[]','前峰鸞鶴去無蹤，邂逅荒尋得故宮。',64,'全唐诗/poet.song.148000.json','["前峰鸞鶴去無蹤，邂逅荒尋得故宮。", "但覺風烟隨意好，便驚塵土轉頭空。", "提壺命駕幽期遠，授簡哦詩妙處同。", "安得西山一丸藥，共隨簫鼓向雲中。"]'),
('59d86d24-4599-4a63-a726-4303ecdbc992','題周氏溪園三首  其一','朱熹','宋','宋诗','song-poetry','','[]','循澗闢芳園，結亭對虛壁。',48,'全唐诗/poet.song.148000.json','["循澗闢芳園，結亭對虛壁。", "澄潭俯幽鑒，空翠仰寒滴。", "主人心事遠，妙寄塵壤隔。", "豈爲功名期，而忘此泉石。"]'),
('162e9edd-558f-42d7-a510-e6348b701ace','題周氏溪園三首  其二','朱熹','宋','宋诗','song-poetry','','[]','危亭竹柏間，悄蒨日幽絕。',48,'全唐诗/poet.song.148000.json','["危亭竹柏間，悄蒨日幽絕。", "朔風一以厲，愛此枝上雪。", "仰悲玄景駛，俯歎群芳歇。", "不用此時來，那知歲寒節。"]'),
('9a59fe3b-d2cf-4d97-bc19-66b62330ee32','題周氏溪園三首  其三','朱熹','宋','宋诗','song-poetry','','[]','手種籬間樹，枝繁不忍刪。',48,'全唐诗/poet.song.148000.json','["手種籬間樹，枝繁不忍刪。", "新亭最佳處，勝日共歡顔。", "景晏春紅淺，雨餘寒翠潸。", "光風回巧笑，桃李任漫山。"]'),
('8a53a261-8705-4840-9611-e19e7a5beae2','寄林擇之','朱熹','宋','宋诗','song-poetry','','[]','故人千里寄書來，三復塵襟頓豁開。',64,'全唐诗/poet.song.148000.json','["故人千里寄書來，三復塵襟頓豁開。", "勸我從容深燕養，莫將佔畢苦沉埋。", "杖藜此日應同趣，揮麈何時得共陪。", "珍重相期俱努力，自慙殊未竭淵才。"]'),
('2039e5fb-38e1-4c15-9ea4-bf04b65aa3a8','送林擇之還鄉赴選三首  其一','朱熹','宋','宋诗','song-poetry','','[]','青驪去路欲駸駸，回首猶須話此心。',32,'全唐诗/poet.song.148000.json','["青驪去路欲駸駸，回首猶須話此心。", "一別便成三數月，有疑誰講過誰箴。"]'),
('d498b866-b20b-45e3-8590-7c6c1a540bd4','送林擇之還鄉赴選三首  其二','朱熹','宋','宋诗','song-poetry','','[]','門外槐花似欲黄，高堂應望促歸裝。',32,'全唐诗/poet.song.148000.json','["門外槐花似欲黄，高堂應望促歸裝。", "箇中自有超然處，肯學兒曹一例忙。"]'),
('9a045ab4-79b2-4292-b643-ab0e4ffe96c5','送林擇之還鄉赴選三首  其三','朱熹','宋','宋诗','song-poetry','','[]','今朝握手送君歸，馬上薰風拂面吹。',32,'全唐诗/poet.song.148000.json','["今朝握手送君歸，馬上薰風拂面吹。", "不用丁寧防曲學，寒窗久矣共心期。"]'),
('59234c24-bada-49d9-a2ac-956ab6910f9b','題林擇之欣木亭','朱熹','宋','宋诗','song-poetry','','[]','危亭俯清川，登覽自晨暮。',72,'全唐诗/poet.song.148000.json','["危亭俯清川，登覽自晨暮。", "佳哉陽春節，看此隔溪樹。", "連林爭秀發，生意各呈露。", "大化本無言，此心誰與晤。", "真歡水菽外，一笑和樂孺。", "聊復共徜徉，殊形乃同趣。"]'),
('f9fb12ec-7e4d-43b6-83eb-a46b8c9c1bd0','擇之誦所賦擬呂子進元宵詩因用元韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','何處元宵好，山房入定僧。',48,'全唐诗/poet.song.148000.json','["何處元宵好，山房入定僧。", "往來衣上月，明暗佛前燈。", "實際徒勞說，空華詎可憑。", "還教知此意，妙用一時興。"]'),
('60775070-f9a4-447a-a8e9-537a1c51e5fa','擇之誦所賦擬呂子進元宵詩因用元韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','何處元宵好，寒龕獨寐人。',48,'全唐诗/poet.song.148000.json','["何處元宵好，寒龕獨寐人。", "月窗同皎皎，燈鏡自塵塵。", "靜鑒通天地，潛思妙鬼神。", "却憐迷路子，狂走閙城闉。"]'),
('9f3f2db8-262e-4211-a1cc-8f57c0b1f7ad','次韻擇之梧竹二首并呈季通  其一','朱熹','宋','宋诗','song-poetry','','[]','竹塢深深處，檀欒遶舍青。',48,'全唐诗/poet.song.148000.json','["竹塢深深處，檀欒遶舍青。", "暑風成慘淡，寒月助清泠。", "客去空塵榻，詩來拓采櫺。", "此君同一笑，午夢頓能醒。"]'),
('c1b73f0f-7df2-409c-b267-fd6fdacc411d','次韻擇之梧竹二首并呈季通  其二','朱熹','宋','宋诗','song-poetry','','[]','永日長梧下，清陰小院幽。',48,'全唐诗/poet.song.148000.json','["永日長梧下，清陰小院幽。", "自憐風嫋嫋，客賦雨瀏瀏。", "作別今千里，相思欲九秋。", "更憐同社友，復此誤淹留。"]'),
('c423e8cb-403f-4779-b9cd-2a68daddc634','擇之寄示深卿唱和烏石南湖佳句輒次元韻三首  其一','朱熹','宋','宋诗','song-poetry','','[]','未識南湖景，遥欣二子遊。',48,'全唐诗/poet.song.148000.json','["未識南湖景，遥欣二子遊。", "賞心并勝日，妙語逼清秋。", "賸欲携書卷，相將買釣舟。", "微吟歸去晚，杜若滿汀洲。"]'),
('933b812a-84a8-40cb-b76c-efaa5b86c4a2','擇之寄示深卿唱和烏石南湖佳句輒次元韻三首  其二','朱熹','宋','宋诗','song-poetry','','[]','平湖渺空闊，積水暮生寒。',48,'全唐诗/poet.song.148000.json','["平湖渺空闊，積水暮生寒。", "但見綠千頃，不知深幾竿。", "人間元迫隘，世路足艱難。", "若了滄洲趣，無勞正眼看。"]'),
('5e4e9c92-2a34-4486-85d1-b55773cc1b16','擇之寄示深卿唱和烏石南湖佳句輒次元韻三首  其三','朱熹','宋','宋诗','song-poetry','','[]','年來年去爲誰忙，三伏炎蒸忽變凉。',64,'全唐诗/poet.song.148000.json','["年來年去爲誰忙，三伏炎蒸忽變凉。", "閲世謾勞心悁悁，懷人空得鬢蒼蒼。", "詩篇眼界何終極，道學心期未遽央。", "安得追尋二三子，舞雩風月共徜徉。"]'),
('dadd4f6f-b51b-46ed-b6fa-5a65b20db371','小詩奉送擇之仁友赴漕臺之招後篇喜趙公之得士而不敢致私怨焉然別懷黯然不能成章亦足以見區區也二首  其一','朱熹','宋','宋诗','song-poetry','','[]','之子論交久，深衷兩自知。',48,'全唐诗/poet.song.148000.json','["之子論交久，深衷兩自知。", "提携方有頼，離索遽成悲。", "聖處應無數，書來肯見私。", "臨分莫惆悵，努力共心期。"]'),
('9b362916-d14c-4941-b444-23d2317b5322','小詩奉送擇之仁友赴漕臺之招後篇喜趙公之得士而不敢致私怨焉然別懷黯然不能成章亦足以見區區也二首  其二','朱熹','宋','宋诗','song-poetry','','[]','珍重東臺老，英聲舊所聞。',48,'全唐诗/poet.song.148000.json','["珍重東臺老，英聲舊所聞。", "能懷吐哺意，豈但枉書勤。", "得士看如許，持心定不群。", "願言推此志，清濁見朋分。"]'),
('b9eb781f-a336-4df8-a8a9-a23874ae6333','擇之賢友歸途左顧示以四明酬唱煥爛盈編三復咏嘆想見聚遊之樂輒用黄山即事之韻賦呈擇之兼懷子重老兄順之賢友','朱熹','宋','宋诗','song-poetry','','[]','十年身卧白雲堆，已分黄塵斷往回。',64,'全唐诗/poet.song.148000.json','["十年身卧白雲堆，已分黄塵斷往回。", "不是幽人遺俗去，肯尋流水渡關來。", "三秋風月從頭說，千里湖山覿面開。", "久欲過逢須一快，豈知勞結倍難裁。"]'),
('2021a32c-6936-413c-90a8-2f4dd042c092','夜聞擇之誦師曾題畫絕句遐想高致偶成小詩','朱熹','宋','宋诗','song-poetry','','[]','一幅瀟湘不易求，新詩誰遣送閑愁。',32,'全唐诗/poet.song.148000.json','["一幅瀟湘不易求，新詩誰遣送閑愁。", "遥知水遠天長外，更有離騷極目秋。"]'),
('2d999506-4590-4d70-836f-f8b7b6dc3668','次林擴之開善避暑韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','炎官虐焰遍山村，也到蕭蕭柳下門。',32,'全唐诗/poet.song.148000.json','["炎官虐焰遍山村，也到蕭蕭柳下門。", "水玉秋菰那可得，羨君行處午陰繁。"]'),
('ef2d8974-7981-4aea-9f18-5aaf89b0f7d1','次林擴之開善避暑韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','山齋幾日旱塵昏，欲拂朱絃已憚煩。',32,'全唐诗/poet.song.148000.json','["山齋幾日旱塵昏，欲拂朱絃已憚煩。", "凉意感君持寄我，雨聲花思滿胸存。"]'),
('10d20488-e228-4b93-91c8-ca012c3a4f34','送林熙之詩五首  其一','朱熹','宋','宋诗','song-poetry','','[]','君行往返一千里，過我屏山山下村。',32,'全唐诗/poet.song.148000.json','["君行往返一千里，過我屏山山下村。", "濁酒寒燈靜相對，論心直欲到忘言。"]'),
('fcb0fd9d-0568-49cf-9fb8-381d6b435831','送林熙之詩五首  其二','朱熹','宋','宋诗','song-poetry','','[]','仁體難明君所疑，欲求直截轉支離。',32,'全唐诗/poet.song.148000.json','["仁體難明君所疑，欲求直截轉支離。", "聖言妙縕無窮意，涵泳從容只自知。"]'),
('09309822-e1b7-442f-987e-1a90f14eb07e','送林熙之詩五首  其三','朱熹','宋','宋诗','song-poetry','','[]','天理生生本不窮，要從知覺驗流通。',32,'全唐诗/poet.song.148000.json','["天理生生本不窮，要從知覺驗流通。", "若知體用元無間，始笑前來說異同。"]'),
('9e2acbb2-4873-412d-ad47-3f9f70ddc023','送林熙之詩五首  其四','朱熹','宋','宋诗','song-poetry','','[]','十年燈火與君同，誰道年來西復東。',32,'全唐诗/poet.song.148000.json','["十年燈火與君同，誰道年來西復東。", "不學世情雲雨手，從教人事馬牛風。"]'),
('15ac12b9-566f-41a3-9dce-d348d1819ee0','送林熙之詩五首  其五','朱熹','宋','宋诗','song-poetry','','[]','古鏡重磨要古方，眼明偏與日爭光。',32,'全唐诗/poet.song.148000.json','["古鏡重磨要古方，眼明偏與日爭光。", "明明直照吾家路，莫指并州作故鄉。"]'),
('5e061870-4cba-418f-a0af-a20049a3e11d','春雪用韓昌黎韻同彭應之作','朱熹','宋','宋诗','song-poetry','','[]','既有陽春曲，那無白雪謠。',120,'全唐诗/poet.song.148000.json','["既有陽春曲，那無白雪謠。", "連天飛不斷，著地煖還銷。", "未掩高人戶，難齊衲子腰。", "稍開銀世界，漸長玉枝條。", "興盡愁煙艇，行迷認野橋。", "酒腸渾欲凍，吟筆爲誰摇。", "殘臘成三白，餘寒又一朝。", "香隨梅蘂落，輕伴柳花飄。", "神女羞捐佩，鮫人敢獻綃。", "東皇應好事，避舍亦相饒。"]'),
('fd0427d7-36d9-40b0-a0b3-e51b9cd9e821','次彭應之餐雪韻','朱熹','宋','宋诗','song-poetry','','[]','雪水瀹清茗，自謂絕世清。',72,'全唐诗/poet.song.148000.json','["雪水瀹清茗，自謂絕世清。", "終然犯煙火，况復勞煎烹。", "豈如午霽餘，探此竹外楹。", "柘漿發甘和，寶盌凝寒晶。", "心胸既清凉，齒頰亦鏘鳴。", "吞腥期永謝，飲玉希長生。"]'),
('e01ac41a-88d2-48b4-856c-0fe9b0e49442','次彭應之魚樂亭韻','朱熹','宋','宋诗','song-poetry','','[]','亭前活水破輕冰，漸見遊鯈傍石稜。',32,'全唐诗/poet.song.148000.json','["亭前活水破輕冰，漸見遊鯈傍石稜。", "老子自知魚樂處，不須莊惠與同登。"]'),
('38bd8f19-78fe-4d51-86cf-ac20687f5454','與劉德明祝濟之胡子寬晚步偶成','朱熹','宋','宋诗','song-poetry','','[]','雨罷寒逾勁，霜威正凜然。',48,'全唐诗/poet.song.148000.json','["雨罷寒逾勁，霜威正凜然。", "不知荒逕濕，行到野橋邊。", "曠望情何極，徘徊意莫傳。", "清波涵衆影，日落暗晴川。"]'),
('36f89b33-5b57-48e6-8db4-982d9f58e945','劉德明彥集祝弟以夏雲多奇峰爲韻賦詩戲成五絕  其一','朱熹','宋','宋诗','song-poetry','','[]','出山幾何時，歸來便長夏。',24,'全唐诗/poet.song.148000.json','["出山幾何時，歸來便長夏。", "端居心不怡，散策長林下。"]'),
('ceba5f3f-3edf-42a5-a566-323a3d04fbf4','劉德明彥集祝弟以夏雲多奇峰爲韻賦詩戲成五絕  其二','朱熹','宋','宋诗','song-poetry','','[]','爲客厭城市，還家辭世紛。',24,'全唐诗/poet.song.148000.json','["爲客厭城市，還家辭世紛。", "朝昏何所見，但有四山雲。"]'),
('b40cce75-bd81-4009-8d7f-e2d9dd0f447d','劉德明彥集祝弟以夏雲多奇峰爲韻賦詩戲成五絕  其三','朱熹','宋','宋诗','song-poetry','','[]','閉門事幽討，歲月忽已多。',24,'全唐诗/poet.song.148000.json','["閉門事幽討，歲月忽已多。", "客來無可問，與君共絃歌。"]'),
('8535e174-f0bb-4edd-bd14-3e05ec0efe21','劉德明彥集祝弟以夏雲多奇峰爲韻賦詩戲成五絕  其四','朱熹','宋','宋诗','song-poetry','','[]','干時本已懶，胸次况亡奇。',24,'全唐诗/poet.song.148000.json','["干時本已懶，胸次况亡奇。", "若問中林趣，婆娑祇自知。"]'),
('35cb65b5-78b5-4ced-a480-720cf0950ee0','劉德明彥集祝弟以夏雲多奇峰爲韻賦詩戲成五絕  其五','朱熹','宋','宋诗','song-poetry','','[]','炎蒸不可柰，雲氣滿前峰。',24,'全唐诗/poet.song.148000.json','["炎蒸不可柰，雲氣滿前峰。", "向夕風吹盡，微聞遠寺鍾。"]'),
('116daf94-248a-41eb-8473-8b9d771aa7eb','仙洲新亭熹名以晝寒紫微張公爲書其額判院劉丈乃出新句輒次高韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','聞說藤蘿外，神龍舊所蟠。',48,'全唐诗/poet.song.148000.json','["聞說藤蘿外，神龍舊所蟠。", "擘開千丈峽，寫盡一襟寒。", "賞寄三杯酒，歸投六尺竿。", "若無詩律好，清絕不成歡。"]'),
('9e028eeb-0929-43eb-a2d3-42deb5b9f00e','仙洲新亭熹名以晝寒紫微張公爲書其額判院劉丈乃出新句輒次高韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','悄蒨非人境，寒蟬夏已稠。',48,'全唐诗/poet.song.148000.json','["悄蒨非人境，寒蟬夏已稠。", "陽崖驚素雪，午扇怯清秋。", "共說新亭好，真堪妙墨留。", "賞心元不厭，仙夢肯來遊。"]'),
('f81432e6-0f04-454a-b867-028c4f96071a','次韻晝寒','朱熹','宋','宋诗','song-poetry','','[]','行穿危磴盡，林表見孤亭。',48,'全唐诗/poet.song.148000.json','["行穿危磴盡，林表見孤亭。", "澗瀉千尋白，峰回四面青。", "塵襟元落落，風腋自泠泠。", "一醉今何許，無心賦獨醒。"]'),
('40310af9-ce12-479e-b895-6f9b9865e772','次判院丈晝寒亭韻有懷平父','朱熹','宋','宋诗','song-poetry','','[]','把酒懷人處，幽尋記往時。',48,'全唐诗/poet.song.148000.json','["把酒懷人處，幽尋記往時。", "新亭勞指顧，勝踐闕追隨。", "爲報層簷出，莫憂浮柱欹。", "惟應舊飛雪，想象合心知。"]'),
('310c5968-8c28-4d3a-a0f7-96530506027e','次判院丈清湍之什','朱熹','宋','宋诗','song-poetry','','[]','明滅青羅带，周遭碧玉環。',48,'全唐诗/poet.song.148000.json','["明滅青羅带，周遭碧玉環。", "孤亭感陳迹，茂樹喜重攀。", "爽氣琴尊外，泉聲枕簟間。", "詩成無寫處，絕壁蘚痕斑。"]'),
('bec96e96-cb87-47da-8796-69ab12180867','遊密菴分韻賦詩得還字','朱熹','宋','宋诗','song-poetry','','[]','我行得佳友，勝日尋名山。',120,'全唐诗/poet.song.148000.json','["我行得佳友，勝日尋名山。", "春山既妍秀，清溪亦潺湲。", "行行造禪扉，小憩腰脚頑。", "窮探意未已，理策重躋攀。", "入谷翳蒙密，俯澗隨泓灣。", "誰將百尺綃，掛此長林間。", "雄聲殷地厚，洪源瀉天慳。", "偉哉奇特觀，償此一日閑。", "所恨境過清，悄愴暮當還。", "顧步三嘆息，人生何苦艱。"]'),
('96a0de73-9255-4be8-9c01-d9a5d94eb339','遊密菴分韻賦詩得絕字','朱熹','宋','宋诗','song-poetry','','[]','閩鄉饒奇山，仙洲故稱傑。',72,'全唐诗/poet.song.148000.json','["閩鄉饒奇山，仙洲故稱傑。", "巍然一峰高，復與衆山絕。", "傳聞極目處，天水遠明滅。", "萬里倏往還，三光下羅列。", "我來發孤興，徑欲躋嵽嵲。", "病骨竟支離，何當攀去轍。"]'),
('d688bb69-efce-4449-ad4e-e7e18fd80c2c','次韻宿密菴','朱熹','宋','宋诗','song-poetry','','[]','忽作經宵別，胸奇莫與陳。',48,'全唐诗/poet.song.148000.json','["忽作經宵別，胸奇莫與陳。", "暮歸誇得句，寒苦頓生春。", "道義知無斁，文章自有真。", "它年應共說，此日自由身。"]'),
('253197c4-d81f-4e49-a0f6-1005f0c16fff','遊密菴','朱熹','宋','宋诗','song-poetry','','[]','弱齡慕丘壑，茲山屢遊盤。',144,'全唐诗/poet.song.148000.json','["弱齡慕丘壑，茲山屢遊盤。", "朝隮青冥外，暮陟浮雲端。", "晴嵐染襟裾，水石清肺肝。", "俯仰未云已，歲月如飛翰。", "中年塵霧牽，引脰空長歎。", "曠歲一登歷，心期殊未闌。", "矧此親友集，笑談有餘歡。", "結架迫彎碕，徙倚臨奔湍。", "共惜前古秘，今爲後來觀。", "落景麗雲木，回風馥秋蘭。", "林昏景益佳，悵然撫歸鞍。", "諒哉故山好，莫遣茲盟寒。"]'),
('6e3adeb1-eaff-4d8f-889a-5f7dc051ce6d','游晝寒以茂林脩竹清流激湍分韻賦詩得竹字','朱熹','宋','宋诗','song-poetry','','[]','仙洲幾千仞，下有雲一谷。',288,'全唐诗/poet.song.148000.json','["仙洲幾千仞，下有雲一谷。", "道人何年來，借地結茅屋。", "想應厭塵網，寄此媚幽獨。", "架亭俯清湍，開徑玩飛瀑。", "交游得名勝，還往有篇牘。", "杖屨或鼎來，共此巖下宿。", "夜燈照奇語，曉策散游目。", "茗椀共甘寒，蘭臯薦清馥。", "至今壁間字，來者必三讀。", "再拜仰高山，悚然心神肅。", "我生雖已後，久此寄齋粥。", "孤興屢呻吟，群遊幾追逐。", "十年落塵土，尚幸不遠復。", "新凉有佳期，幾日戒征軸。", "宵興出門去，急雨遍原陸。", "入谷尚輕埃，解裝已銀竹。", "虛空一瞻望，遠思翻蹙恧。", "袒跣亟躋攀，冠巾如膏沐。", "雲泉增舊觀，怒響震寒木。", "深尋得新賞，一簣今再覆。", "同來况才彥，行酒屢更僕。", "從容出妙句，珠貝爛盈匊。", "後生更亹亹，俊語非碌碌。", "吾纓不復洗，已失塵萬斛。"]'),
('d10c3900-f8dd-4ab7-b5ec-b81815cfc5d8','聞季通德明諸友入山以詩迎之仍請先往觀瀑布','朱熹','宋','宋诗','song-poetry','','[]','勝友南窗底，看書老歲華。',48,'全唐诗/poet.song.148000.json','["勝友南窗底，看書老歲華。", "不因寒瀑響，肯到野僧家。", "古徑開能久，新亭去豈賒。", "躋攀那可緩，寂寞有雄夸。"]'),
('0f7654ce-712f-4c70-9a24-178118e14022','次觀瀑布韻','朱熹','宋','宋诗','song-poetry','','[]','快瀉蒼崖一道泉，白龍飛下鬰藍天。',32,'全唐诗/poet.song.148000.json','["快瀉蒼崖一道泉，白龍飛下鬰藍天。", "空山有此真奇觀，倚杖來看思凜然。"]'),
('e5951df4-4a59-4908-b988-ffccf71f8989','和季通晝寒韻','朱熹','宋','宋诗','song-poetry','','[]','萬壑爭流處，千年樹石幽。',48,'全唐诗/poet.song.148000.json','["萬壑爭流處，千年樹石幽。", "危亭因我作，勝日爲君留。", "酒笑紅裙醉，詩慙雜珮酬。", "尚嫌心境窄，更約九垓游。"]'),
('14e7fc31-cc89-4adf-ab94-0a1b95968153','次韻謁忠顯劉公墓下','朱熹','宋','宋诗','song-poetry','','[]','理亂由來今古同，覆車那肯戒前蹤。',32,'全唐诗/poet.song.148000.json','["理亂由來今古同，覆車那肯戒前蹤。", "紛紛誤國人無數，不昧丹心獨此公。"]'),
('b4e4930d-885f-4f7f-b8bb-cfa65e7837d3','次季通晝寒亭韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','不信高懷與世殊，清游試問與誰俱。',32,'全唐诗/poet.song.148000.json','["不信高懷與世殊，清游試問與誰俱。", "相將靜聽潺湲水，洗滌塵襟肯自污。"]'),
('b0657bbc-6434-4e64-a784-bb915f0548a3','次季通晝寒亭韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','山行前後有光輝，撲撲浮嵐翠染衣。',32,'全唐诗/poet.song.148000.json','["山行前後有光輝，撲撲浮嵐翠染衣。", "直到仙洲奇絕處，晝寒亭下玉龍飛。"]'),
('cdc13cb9-67c4-4e3d-b870-ce224dce6ffb','飲清湍亭石上小醉再登晝寒','朱熹','宋','宋诗','song-poetry','','[]','水邊今日共傳杯，多謝殷勤數子來。',64,'全唐诗/poet.song.148000.json','["水邊今日共傳杯，多謝殷勤數子來。", "三伏炎蒸那有此，百年懷抱頓能開。", "雲山合匝還生霧，雪澗崩騰怒吼雷。", "却恨蒼屏遮遠日，凌風直欲跨蓬萊。"]'),
('cf4ae332-4f7e-43c5-bd0f-e7e291c8c8e0','次清湍亭韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','上下青山今白頭，穿雲入塢未能休。',32,'全唐诗/poet.song.148000.json','["上下青山今白頭，穿雲入塢未能休。", "因君去覓仙洲路，却嘆周南獨滯留。"]'),
('1cf212cf-187e-496b-9f78-d880103ed4e4','次清湍亭韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','仄徑穿林欲造天，未妨停策聽涓涓。',32,'全唐诗/poet.song.148000.json','["仄徑穿林欲造天，未妨停策聽涓涓。", "知君便有刀頭意，莫忘仙洲澗底泉。"]'),
('63f81191-c4f6-417a-9d78-2f25f366c526','立春大雪邀劉圭甫諸兄遊天湖','朱熹','宋','宋诗','song-poetry','','[]','同雲被四野，寒氣慘悲凉。',144,'全唐诗/poet.song.148000.json','["同雲被四野，寒氣慘悲凉。", "回風一以定，密雪來飄揚。", "時當冬候窮，開歲五日彊。", "蓬巷無與適，陟此瓊臺岡。", "賓友既追隨，兒童亦携將。", "攀躋得冢頂，徙倚聊彷徨。", "俯視千里空，仰看萬鶴翔。", "遠迷亂峰翠，近失平林蒼。", "偃薄瑩神骨，咀嚥清肝腸。", "朗詠招隠作，悲吟黄竹章。", "古人不可見，來者誰能量。", "且復記茲日，他年亦難忘。"]'),
('f249cc52-7df0-4563-9cb5-91da3a0df7a6','次圭父游將軍巖韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','極目危岑杳靄間，誰將層棟壓巑岏。',64,'全唐诗/poet.song.148000.json','["極目危岑杳靄間，誰將層棟壓巑岏。", "瘦筇上上莫辭遠，絕境行行得細觀。", "眢井尚餘茅絰處，考槃無復碩人寬。", "倦來拂石支拳睡，萬壑吟風午夢闌。"]'),
('65cf6bcd-9e29-4255-a396-8c8390233fda','次圭父游將軍巖韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','陳迹真成俯仰間，回頭猶認碧巑岏。',64,'全唐诗/poet.song.148000.json','["陳迹真成俯仰間，回頭猶認碧巑岏。", "更煩地主殷勤意，得盡雲山表裏觀。", "景晏共愁歸路遠，年侵獨負酒盃寬。", "明朝覓句酬珠玉，剩喜詩情却未闌。"]'),
('5c3bf2c0-4e3d-4ded-b53f-71f4f4260928','圭父約爲金斗之遊次韻獻疑聊發一笑','朱熹','宋','宋诗','song-poetry','','[]','幾日春風未破寒，遠峰晴露玉巑岏。',64,'全唐诗/poet.song.148000.json','["幾日春風未破寒，遠峰晴露玉巑岏。", "不成蠟屐携筇去，且復鈎窗拄頰觀。", "聞道追遊當作意，故應期日尚能寬。", "陰崖凍合無垂練，却恐詩翁興易闌。"]'),
('ea3430df-4f8b-41d5-b185-883025bb42c9','次彥集經營別墅之作','朱熹','宋','宋诗','song-poetry','','[]','回北成南指顧間，要令華敞對巑岏。',64,'全唐诗/poet.song.148000.json','["回北成南指顧間，要令華敞對巑岏。", "家山信有千巖擁，雲月何妨兩處觀。", "傑閣已資隣築勝，新基還見繚牆寬。", "老仙鶴骨殊蕭爽，歸興從今豈易闌。"]'),
('5250769c-3cde-4a08-876c-c4219ad58f5a','彥集圭父擇之同飲白雲精舍以醉酒飽德爲韻熹分得飽字醉中走筆奉呈','朱熹','宋','宋诗','song-poetry','','[]','奔趨名利場，禍福急相絞。',72,'全唐诗/poet.song.148000.json','["奔趨名利場，禍福急相絞。", "夜窗一反側，膚垢紛兩爪。", "豈知親朋集，晚食聊一飽。", "心期共悠悠，文字各稍稍。", "華燭既屢更，詩腸亦頻攪。", "寒更儘渠深，孤諷寧至卯。"]'),
('53789aea-a767-47b5-86e9-a47d2f41c532','次劉圭甫和人梅花韻','朱熹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','意行欲遍江村路，恰到詩人斷魂處。',128,'全唐诗/poet.song.148000.json','["意行欲遍江村路，恰到詩人斷魂處。", "梅花未肯笑春風，蔓草何須怨零露。", "歸來四壁無餘聲，俯檻祇有寒塘青。", "美人邂逅一笑粲，倒影的皪踈枝橫。", "寸心久矣遺紛雜，不但老禪齋夏臘。", "此時悢悢欲何言，本根落落幾難合。", "走遍諸君詩卷中，西湖東閣病還同。", "劃然長笑驚夢破，碧雲散盡山叢叢。"]'),
('4608aee6-a00f-4f24-bab5-175c2cf4f6dd','奉酬圭父末利之作','朱熹','宋','宋诗','song-poetry','','[]','玉蘂琅玕樹，天香知見薰。',48,'全唐诗/poet.song.148000.json','["玉蘂琅玕樹，天香知見薰。", "露寒清透骨，風定遠含芬。", "爽致銷繁暑，高情謝曉雲。", "遥憐河朔飲，那得醉時聞。"]'),
('4765be3c-a13e-4c27-9b8e-888c039eae76','奉酬圭父白蓮之作','朱熹','宋','宋诗','song-poetry','','[]','忽傳夔府句，并送遠公蓮。',48,'全唐诗/poet.song.148000.json','["忽傳夔府句，并送遠公蓮。", "翠蓋臨風迥，冰華浥露鮮。", "舞衣清縞袂，倒景爛珠躔。", "想象芙蓉闕，冥冥絕世緣。"]'),
('a6da9518-f184-42c5-9f10-f5e4a9fff33f','次圭父觀魚韻','朱熹','宋','宋诗','song-poetry','','[]','平生三伏斷追遊，誰喚來穿澗樹幽。',64,'全唐诗/poet.song.148000.json','["平生三伏斷追遊，誰喚來穿澗樹幽。", "初訝網橫天影破，忽驚人蹴浪花浮。", "鳴榔不用齊吳榜，鼓枻何須學楚謳。", "便有金盤堆白雪，却憐清泚向東流。"]'),
('abfe6859-8725-4ab6-a2c2-90297710cab2','奉同黄子厚賦白芙蓉呈劉彥集平父','朱熹','宋','宋诗','song-poetry','','[]','湛湛曲池水，曉含風露清。',72,'全唐诗/poet.song.148000.json','["湛湛曲池水，曉含風露清。", "田田綠羅蓋，粲粲白玉英。", "澹然絕世姿，不與穠艷并。", "俯鑒冰雪影，詎懷兒女情。", "山中徒淹留，堂下空目成。", "獨有忘機客，相看兩無營。"]'),
('9cd005e8-0881-47c4-b9b9-97e9e482ee4d','觀洪遵雙陸譜有感呈劉平甫范仲宣二兄','朱熹','宋','宋诗','song-poetry','','[]','近從新譜識梟盧，擬喚安陽舊博徒。',32,'全唐诗/poet.song.148000.json','["近從新譜識梟盧，擬喚安陽舊博徒。", "只恐分陰閑過了，更教人誚牧豬奴。"]'),
('c3d97448-99f5-44e3-9475-21e3c42bd0d6','次劉彥集木犀韻三首  其一','朱熹','宋','宋诗','song-poetry','','[]','衆芳摇落九秋期，橫出天香第一枝。',32,'全唐诗/poet.song.148000.json','["衆芳摇落九秋期，橫出天香第一枝。", "莫似寒梅太孤絕，更交遥夜笛中吹。"]'),
('f202d9bb-9c29-4dee-8b10-b780e702612e','次劉彥集木犀韻三首  其二','朱熹','宋','宋诗','song-poetry','','[]','仙衣纔試鬰金黄，便覺秋風滿院芳。',32,'全唐诗/poet.song.148000.json','["仙衣纔試鬰金黄，便覺秋風滿院芳。", "定觀極知先透徹，通心豈是故迎將。"]'),
('3fa73f6a-c6fe-45c0-8f72-b56f4d1c05c8','次劉彥集木犀韻三首  其三','朱熹','宋','宋诗','song-poetry','','[]','秋到寒巖桂樹叢，小山吟罷思悲翁。',32,'全唐诗/poet.song.148000.json','["秋到寒巖桂樹叢，小山吟罷思悲翁。", "不妨更作淹留計，占取人間十里風。"]'),
('4a197cee-c0ff-4061-a66b-30ff49260381','寄謝劉彥集菖蒲之貺二首  其一','朱熹','宋','宋诗','song-poetry','','[]','君家蘭杜久萋萋，近養菖蒲綠未齊。',32,'全唐诗/poet.song.148000.json','["君家蘭杜久萋萋，近養菖蒲綠未齊。", "乞與幽人伴岑寂，小窗風露日低迷。"]'),
('325aa6dd-5c23-41cd-8c1d-423c60a316d5','寄謝劉彥集菖蒲之貺二首  其二','朱熹','宋','宋诗','song-poetry','','[]','泉清石瘦碧纖長，秋露懸珠炯夜光。',32,'全唐诗/poet.song.148000.json','["泉清石瘦碧纖長，秋露懸珠炯夜光。", "箇裏無窮閑造化，別來誰與共平章。"]'),
('17bf24ae-2fdb-4fce-877c-b6e906b882e8','公濟惠山蔬四種并以佳篇來貺因次其韻 𬊳','朱熹','宋','宋诗','song-poetry','','[]','靈草生何許，風泉古澗傍。',48,'全唐诗/poet.song.148000.json','["靈草生何許，風泉古澗傍。", "褰裳勤采擷，枝筯嚏芳香。", "冷入玄根閟，春歸翠穎長。", "遥知拈起處，全體露其常。"]'),
('f52c6c44-8a52-417e-95e6-2a3c01c5d39b','公濟惠山蔬四種并以佳篇來貺因次其韻 芹','朱熹','宋','宋诗','song-poetry','','[]','晚食寧論肉，知君薄世榮。',48,'全唐诗/poet.song.148000.json','["晚食寧論肉，知君薄世榮。", "瓊田何日種，玉本一時生。", "白鶴今休誤，青泥舊得名。", "收單還炙背，北闕儻關情。"]'),
('bc72787f-f71a-413d-a856-378bb0eec281','公濟惠山蔬四種并以佳篇來貺因次其韻 筍','朱熹','宋','宋诗','song-poetry','','[]','新笋因君寄，康廬入夢中。',48,'全唐诗/poet.song.148000.json','["新笋因君寄，康廬入夢中。", "丹元餘故宅，翠竹尚餘風。", "日日來威鳳，年年饌籜龍。", "猶嫌有兼味，不似一源功。"]'),
('c42cae39-4059-4d3e-a568-0d665bd1db1d','公濟惠山蔬四種并以佳篇來貺因次其韻 蕨','朱熹','宋','宋诗','song-poetry','','[]','西山採蕨人，蓬首尚傾國。',48,'全唐诗/poet.song.148000.json','["西山採蕨人，蓬首尚傾國。", "懷哉遠莫致，引脰氣已塞。", "傾筐忽墮前，此意豈易得。", "良遇不可遲，枯筇有餘力。"]'),
('ffe0d0c4-7ea3-40d2-a628-727b0172dd13','題吳公濟風泉亭','朱熹','宋','宋诗','song-poetry','','[]','澗谷居永久，高情未云酬。',120,'全唐诗/poet.song.148000.json','["澗谷居永久，高情未云酬。", "茲焉發天祕，始造寒巖幽。", "上有茂樹陰，下有清泉流。", "結亭倚蒼峭，鑿磴窮嵌丘。", "翠壁自屏立，青蘚亦環周。", "朅來憩永夏，凜若臨清秋。", "仰空韻笙竽，俯檻鏘琳璆。", "幽聽一以會，悠然與神謀。", "遐哉超世心，暇日聊娛憂。", "笑問車馬客，誰能淹此留。"]'),
('6693131a-7fef-4ad6-a446-427aca1d45c2','再題吳公濟風泉亭','朱熹','宋','宋诗','song-poetry','','[]','華林翠磵響風泉，竟日閑來石上眠。',32,'全唐诗/poet.song.148000.json','["華林翠磵響風泉，竟日閑來石上眠。", "更結危亭俯幽聽，未妨長作地行仙。"]'),
('f1ffd6b3-1fc1-40c1-ba94-8ea7c2af3dba','奉和公濟兄留周賓之句','朱熹','宋','宋诗','song-poetry','','[]','端居感時序，駕言誰適從。',156,'全唐诗/poet.song.148000.json','["端居感時序，駕言誰適從。", "聊携二三子，杖屨此日同。", "悠哉素心人，宴坐空巖中。", "真成三秋別，夢想情何窮。", "行行陟崇岡，引脰希高風。", "忽然兩相值，俯仰迷西東。", "鱣堂偶休閒，雞黍聊從容。", "不辭腰脚勞，共上西南峰。", "佩萸笑長房，把菊追陶公。", "遐觀衆山迥，一酌千慮融。", "興罷復來歸，杳靄秋堂空。", "窺樽訖餘瀝，倚閣聞踈鍾。", "主人意未闌，驪駒勿怱怱。"]'),
('d9d91ee2-1cde-4364-a4ab-f0b2cf0b9038','寄吳公濟兼簡李伯諫五首  其一','朱熹','宋','宋诗','song-poetry','','[]','客子歸來春未深，祇應寒雨罷登臨。',64,'全唐诗/poet.song.148000.json','["客子歸來春未深，祇應寒雨罷登臨。", "閑窗竟日焚香坐，一段孤明見此心。", "三徑莓苔晝掩關，君來問道却空還。", "從今蠟屐應無恙，有興何妨再入山。"]'),
('c5d6f0d5-2c0e-4d9f-9a47-535f41f4bd3d','寄吳公濟兼簡李伯諫五首  其二','朱熹','宋','宋诗','song-poetry','','[]','盤翁別去久無書，可復因循自作踈。',32,'全唐诗/poet.song.148000.json','["盤翁別去久無書，可復因循自作踈。", "珍重寄聲煩問訊，箇中消息定何如。"]'),
('ad0f8911-6ddc-4d8f-917a-0f1abfca0d7c','寄吳公濟兼簡李伯諫五首  其三','朱熹','宋','宋诗','song-poetry','','[]','繁絃急管盛流傳，清廟遺音久絕絃。',32,'全唐诗/poet.song.148000.json','["繁絃急管盛流傳，清廟遺音久絕絃。", "欲識寥寥千古意，莫將新語勘塵編。"]'),
('6142ad91-da93-461a-bb61-b439ea9142d6','寄吳公濟兼簡李伯諫五首  其四','朱熹','宋','宋诗','song-poetry','','[]','憶昔殊方久滯淫，年深歸路始駸駸。',32,'全唐诗/poet.song.148000.json','["憶昔殊方久滯淫，年深歸路始駸駸。", "傍人欲問簞瓢樂，理義誰知悅我心。"]'),
('ec9d69bd-d373-45a4-8590-bb38836c0228','公濟和詩見閔耽書勉以教外之樂以詩請問二首  其一','朱熹','宋','宋诗','song-poetry','','[]','至理無言絕淺深，塵塵剎剎不相侵。',32,'全唐诗/poet.song.148000.json','["至理無言絕淺深，塵塵剎剎不相侵。", "如云教外傳真的，却是瞿曇有兩心。"]'),
('aac9e891-c047-456b-b09b-ffe5484a5adf','公濟和詩見閔耽書勉以教外之樂以詩請問二首  其二','朱熹','宋','宋诗','song-poetry','','[]','未必瞿曇有兩心，莫將此意攪儒林。',32,'全唐诗/poet.song.148000.json','["未必瞿曇有兩心，莫將此意攪儒林。", "欲知陋巷憂時樂，只向韋編絕處尋。"]'),
('fee34b4a-247d-47a1-8cb0-3f50072dccd7','伯諫和詩云邪色哇聲方漫漫是中正氣愈駸駸予謂此乃聖人從心之妙三歎成詩重以問彼二首  其一','朱熹','宋','宋诗','song-poetry','','[]','任從耳畔妍聲過，特地胸中順氣萌。',32,'全唐诗/poet.song.148000.json','["任從耳畔妍聲過，特地胸中順氣萌。", "箇裏詎容思勉得，羨君一躍了平生。"]'),
('ece90fcf-6d05-493e-80e6-67ec25f29842','伯諫和詩云邪色哇聲方漫漫是中正氣愈駸駸予謂此乃聖人從心之妙三歎成詩重以問彼二首  其二','朱熹','宋','宋诗','song-poetry','','[]','闕里當年語從心，至今蹤跡尚難尋。',32,'全唐诗/poet.song.148000.json','["闕里當年語從心，至今蹤跡尚難尋。", "况君直至無心處，肯向人前話淺深。"]'),
('a5206992-08a7-494e-a7c2-647e33147107','游百丈山以徙倚弄雲泉分韻賦詩得雲字','朱熹','宋','宋诗','song-poetry','','[]','執熱倦煩跼，駕言起宵分。',144,'全唐诗/poet.song.148000.json','["執熱倦煩跼，駕言起宵分。", "隨川踏曉月，度嶺披朝雲。", "攀緣白石梯，拂拭蒼蘚紋。", "噴薄驚快覿，琮琤喜先聞。", "奇哉此精廬，眇然隔塵氛。", "諸公肯同來，定非俗子羣。", "永日坐清樾，短章策奇勳。", "慨然念疇昔，聯裾已荒墳。", "中路忘磬折，寸心謾絲棼。", "惟應泉石願，三生有餘薰。", "茲游獲重尋，十載心氤氳。", "他年訪舊躅，山靈莫移文。"]'),
('49fd8eb0-0cd2-4882-8552-d778c1d76375','百丈山六詠 石磴','朱熹','宋','宋诗','song-poetry','','[]','層崖俯深幽，微逕忽中斷。',24,'全唐诗/poet.song.148000.json','["層崖俯深幽，微逕忽中斷。", "努力一躋攀，前行有奇觀。"]'),
('bfb45067-27e8-44f0-b155-69311229ade8','百丈山六詠 小澗','朱熹','宋','宋诗','song-poetry','','[]','兩崖交翠陰，一水自清瀉。',24,'全唐诗/poet.song.148000.json','["兩崖交翠陰，一水自清瀉。", "俯仰契幽情，神襟頓飄洒。"]'),
('ce1cbbe0-9218-4fc0-8c6c-bd3670489199','百丈山六詠 山門','朱熹','宋','宋诗','song-poetry','','[]','置屋兩山間，巧當奇絕處。',24,'全唐诗/poet.song.148000.json','["置屋兩山間，巧當奇絕處。", "峽束百泉傾，澗激回風度。"]'),
('17f3324e-f473-4976-8b9b-b2bacbe35c13','百丈山六詠 石臺','朱熹','宋','宋诗','song-poetry','','[]','出谷轉石稜，俯身窺木末。',24,'全唐诗/poet.song.148000.json','["出谷轉石稜，俯身窺木末。", "夕眺嵐翠分，朝隮雲海闊。"]'),
('b65f7256-52a7-486a-9ae3-4d79417471e6','百丈山六詠 西閣','朱熹','宋','宋诗','song-poetry','','[]','借此雲窗眠，靜夜心獨苦。',24,'全唐诗/poet.song.148000.json','["借此雲窗眠，靜夜心獨苦。", "安得枕下泉，去作人間雨。"]'),
('456b2e6f-6b0f-4fb0-b1c8-9b81d026954a','百丈山六詠 瀑布','朱熹','宋','宋诗','song-poetry','','[]','巔崖出飛泉，百尺散風雨。',24,'全唐诗/poet.song.148000.json','["巔崖出飛泉，百尺散風雨。", "空質麗晴暉，龍鸞共掀舞。"]'),
('a53be97d-504e-4168-bfd8-8934cdd91fb6','游蘆峰分韻得盡字','朱熹','宋','宋诗','song-poetry','','[]','蘆山一何高，上上不可盡。',156,'全唐诗/poet.song.148000.json','["蘆山一何高，上上不可盡。", "我行獨忘疲，泉石有招引。", "須臾出蒙密，矯首眺無畛。", "已謂極崢嶸，仰視猶隠嶙。", "新齋小休憩，餘力更勉黽。", "東峰切霄漢，首夏正凄緊。", "杖策同攀躋，極目散幽窘。", "萬里俯連環，千里瞰孤隼。", "因知平生懷，未與塵慮泯。", "歸塗采薇蕨，晚餉雜蔬筍。", "笑謂同來人，此願天所允。", "獨往會淹留，寒棲甘菌蠢。", "山阿子慕予，無憂勒回軫。"]'),
('195cea6e-9545-4bf4-bff7-fbec902965c1','同丘子服游蘆峰以嶺上多白雲分韻賦詩得白字','朱熹','宋','宋诗','song-poetry','','[]','登巖出囂塵，入谷媚泉石。',144,'全唐诗/poet.song.148000.json','["登巖出囂塵，入谷媚泉石。", "悠然愜幽趣，不覺幾朝夕。", "高尋倦冢頂，舊賞歎陳迹。", "仰慙仙人杖，俯愧謝公屐。", "昨日吾弟來，勇往意無歝。", "今晨蓐食罷，千仞一咫尺。", "心期未究竟，眼界已開闢。", "浮野衆麓青，縈雲兩川白。", "須臾互吞吐，變化已今昔。", "曠若塵慮空，悲哉人境窄。", "平生有孤念，萬里思矯翮。", "感此復沖然，胡爲尚形役。"]'),
('dc8748c3-827c-44f0-ad6e-11750984f56b','登蘆峰','朱熹','宋','宋诗','song-poetry','','[]','行到蘆峰最上頭，幾回振策又還休。',32,'全唐诗/poet.song.148000.json','["行到蘆峰最上頭，幾回振策又還休。", "因君好句撩孤興，却恨雲烟未肯收。"]'),
('9cace5bb-4a69-4f58-b5a2-df1aaefe90a4','將游雲谷約同行者','朱熹','宋','宋诗','song-poetry','','[]','躋險擇幽棲，搴蘿結茅屋。',96,'全唐诗/poet.song.148000.json','["躋險擇幽棲，搴蘿結茅屋。", "疏泉下石濞，種樹滿煙谷。", "時登北原上，一騁千里目。", "雲物下逶迤，岡巒遠重複。", "暫辭忽曠歲，再往恨牽俗。", "因悲昨游侶，或已在鬼錄。", "暄風悟新陽，一雨欣衆綠。", "明發君莫遲，幽期我當卜。"]'),
('ffa0538b-d54f-4c93-ab22-398c06d77eec','九月六日早發潭溪夜登雲谷翌旦賦此','朱熹','宋','宋诗','song-poetry','','[]','懷山不能寐，中宵命行軒。',156,'全唐诗/poet.song.148000.json','["懷山不能寐，中宵命行軒。", "亭午息畏景，薄暮登危巒。", "峻極踰百磴，縈紆欲千盤。", "行行遂曛黑，月落天風寒。", "羽人候中塗，良朋集林端。", "問我何所迫，而嘗茲險艱。", "疲勞既云極，饑渴不能言。", "投裝卧中丘，幸此一室寬。", "怒號竟永夕，客枕無時安。", "旦起闢幽戶，竹樹青檀欒。", "驚喜非昔覩，披尋得新觀。", "淹留十日期，俯仰有餘歡。", "寄語後來子，勿辭行路難。"]'),
('fe2a15bb-0c76-44a4-a44b-8cfe00aad2ca','雲谷二十六詠 雲谷','朱熹','宋','宋诗','song-poetry','','[]','寒雲無四時，散漫此山谷。',24,'全唐诗/poet.song.148000.json','["寒雲無四時，散漫此山谷。", "幸乏霖雨姿，何妨媚幽獨。"]'),
('3e1d6f12-bc55-4d87-9c01-3f7e6131c6e9','雲谷二十六詠 南澗','朱熹','宋','宋诗','song-poetry','','[]','危石下崢嶸，高林上蒼翠。',24,'全唐诗/poet.song.148000.json','["危石下崢嶸，高林上蒼翠。", "中有橫飛泉，崩奔雜奇麗。"]'),
('9a3a1302-4472-48d1-be44-2748a2fca5fc','雲谷二十六詠 瀑布','朱熹','宋','宋诗','song-poetry','','[]','峰回危逕轉，垂練忽千尋。',24,'全唐诗/poet.song.148000.json','["峰回危逕轉，垂練忽千尋。", "不爲登山倦，躊躇秋澗陰。"]'),
('354b4e0c-6455-4ba7-8ba6-0a45de28e513','雲谷二十六詠 雲關','朱熹','宋','宋诗','song-poetry','','[]','白雲去復還，黄塵到難入。',24,'全唐诗/poet.song.148000.json','["白雲去復還，黄塵到難入。", "只有澗水聲，出關流更急。"]'),
('51ef6a4e-c1ca-40cb-8669-27a891fbd417','雲谷二十六詠 蓮沼','朱熹','宋','宋诗','song-poetry','','[]','亭亭玉芙蓉，迥立映澄碧。',24,'全唐诗/poet.song.148000.json','["亭亭玉芙蓉，迥立映澄碧。", "只愁山月明，照作寒露滴。"]'),
('a056adcc-fa1b-43dd-bbcc-bdc4418b837e','雲谷二十六詠 杉逕','朱熹','宋','宋诗','song-poetry','','[]','南起雲關口，縈紆上草堂。',24,'全唐诗/poet.song.148000.json','["南起雲關口，縈紆上草堂。", "天風發清籟，山月度寒光。"]'),
('e2e7fb4d-e16d-4b76-9391-cfc42bde2d21','雲谷二十六詠 雲莊','朱熹','宋','宋诗','song-poetry','','[]','小丘橫翠几，層嶂復嵯峨。',24,'全唐诗/poet.song.148000.json','["小丘橫翠几，層嶂復嵯峨。", "釋耒閑來看，巖姿此處多。"]'),
('5bff31c6-0ccf-4656-9ebc-2ce2bbf9af32','雲谷二十六詠 泉硤','朱熹','宋','宋诗','song-poetry','','[]','入關但平田，復此得清響。',24,'全唐诗/poet.song.148000.json','["入關但平田，復此得清響。", "何必問真源，神襟一蕭爽。"]'),
('7106255e-4c8f-4fb3-b354-3540a219f9da','雲谷二十六詠 石池','朱熹','宋','宋诗','song-poetry','','[]','兩岸蒼峭石，護此碧泓寒。',24,'全唐诗/poet.song.148000.json','["兩岸蒼峭石，護此碧泓寒。", "秋月來窺影，驪珠吐玉盤。"]'),
('6c78cbf6-168f-4df9-858c-9d0f456bc2aa','雲谷二十六詠 山楹','朱熹','宋','宋诗','song-poetry','','[]','山楹一悵望，恨此雲迷谷。',24,'全唐诗/poet.song.148000.json','["山楹一悵望，恨此雲迷谷。", "仙人不可期，縹緲雙髻綠。"]'),
('996706a9-0d82-4fb2-8f4c-c931d86d5291','雲谷二十六詠 藥圃','朱熹','宋','宋诗','song-poetry','','[]','長鑱斸靈根，蒔此泉下圃。',24,'全唐诗/poet.song.148000.json','["長鑱斸靈根，蒔此泉下圃。", "珍劑未須論，丹荑已堪煮。"]'),
('37640f23-e4d6-498d-a1e4-a1199b719919','雲谷二十六詠 井泉','朱熹','宋','宋诗','song-poetry','','[]','山高澤氣通，石竇飛靈液。',24,'全唐诗/poet.song.148000.json','["山高澤氣通，石竇飛靈液。", "默料谷中雲，多應從此出。"]'),
('81d43d54-cfde-45dc-88f2-ebff09043ffc','雲谷二十六詠 西寮','朱熹','宋','宋诗','song-poetry','','[]','畬田種胡麻，結草寄林樾。',24,'全唐诗/poet.song.148000.json','["畬田種胡麻，結草寄林樾。", "珍重無心人，寒棲弄明月。"]'),
('5c96ceff-f130-4c94-995e-27b79479995a','雲谷二十六詠 晦菴','朱熹','宋','宋诗','song-poetry','','[]','憶昔屏山翁，示我一言教。',24,'全唐诗/poet.song.148000.json','["憶昔屏山翁，示我一言教。", "自信久未能，巖棲冀微效。"]'),
('19a601a0-f0c7-47d9-a4fb-a502b9b094ae','雲谷二十六詠 草廬','朱熹','宋','宋诗','song-poetry','','[]','青山繞蓬廬，白雲障幽戶。',24,'全唐诗/poet.song.148000.json','["青山繞蓬廬，白雲障幽戶。", "卒歲聊自娛，時人莫留顧。"]'),
('8bdefbde-5fbd-40ce-8a5e-2adb638a097b','雲谷二十六詠 懷仙','朱熹','宋','宋诗','song-poetry','','[]','西望多奇峰，北瞰獨仙府。',24,'全唐诗/poet.song.148000.json','["西望多奇峰，北瞰獨仙府。", "欲致武夷君，石壇羅桂醑。"]'),
('55685541-4ae1-403f-bf95-7cdc1ac836f4','雲谷二十六詠 揮手','朱熹','宋','宋诗','song-poetry','','[]','山臺一揮手，從此斷將迎。',24,'全唐诗/poet.song.148000.json','["山臺一揮手，從此斷將迎。", "不見塵中事，惟聞打麥聲。"]'),
('982cf4d0-24e5-4d43-a66f-bbc3444753fe','雲谷二十六詠 雲社','朱熹','宋','宋诗','song-poetry','','[]','自作山中人，即與雲爲友。',24,'全唐诗/poet.song.148000.json','["自作山中人，即與雲爲友。", "一嘯雨紛紛，無勞三奠酒。"]'),
('85d3a823-87b2-404b-8aec-f7c637889bfc','雲谷二十六詠 桃蹊','朱熹','宋','宋诗','song-poetry','','[]','澗裏春泉響，種桃泉上頭。',24,'全唐诗/poet.song.148000.json','["澗裏春泉響，種桃泉上頭。", "爛紅紛委地，未肯出山流。"]'),
('db748d50-2435-4d44-baa5-a012ce6c59cc','雲谷二十六詠 竹塢','朱熹','宋','宋诗','song-poetry','','[]','悄蒨桃蹊北，蕭椮竹塢深。',24,'全唐诗/poet.song.148000.json','["悄蒨桃蹊北，蕭椮竹塢深。", "不堪秋夜永，風雨助悲吟。"]'),
('d9c6c29f-4098-4b3d-9867-8d1a8e3cd070','雲谷二十六詠 漆園','朱熹','宋','宋诗','song-poetry','','[]','舊聞南華仙，作吏漆園裏。',24,'全唐诗/poet.song.148000.json','["舊聞南華仙，作吏漆園裏。", "應悟見割憂，嗒然空隠几。"]'),
('eb6e4c8a-b0a8-451d-9583-2fe126bfd22c','雲谷二十六詠 茶坂','朱熹','宋','宋诗','song-poetry','','[]','携籝北嶺西，采擷供茗飲。',24,'全唐诗/poet.song.148000.json','["携籝北嶺西，采擷供茗飲。", "一啜夜窗寒，跏趺謝衾枕。"]'),
('02dd4373-1336-45c4-a87a-f6854ddc2e98','雲谷二十六詠 絕頂','朱熹','宋','宋诗','song-poetry','','[]','當年赫曦臺，移治在茲嶺。',24,'全唐诗/poet.song.148000.json','["當年赫曦臺，移治在茲嶺。", "寥廓無四隣，三光疑倒影。"]'),
('33de0d52-2e60-4fa1-b466-da487868e747','雲谷二十六詠 北澗','朱熹','宋','宋诗','song-poetry','','[]','土斷川亦分，北下成陰澗。',24,'全唐诗/poet.song.148000.json','["土斷川亦分，北下成陰澗。", "秀石得佳名，服膺吾敢慢。"]'),
('5433a601-e81f-443b-8479-fa8508ed8736','雲谷二十六詠 中溪','朱熹','宋','宋诗','song-poetry','','[]','南下東嶺阿，云是中溪道。',24,'全唐诗/poet.song.148000.json','["南下東嶺阿，云是中溪道。", "巖樹愛樛枝，石田悲蔓草。"]'),
('834bb9f2-b849-4fcd-9c6d-67bf4875e8fa','雲谷二十六詠 休菴','朱熹','宋','宋诗','song-poetry','','[]','別嶺有精廬，林巒亦幽絕。',24,'全唐诗/poet.song.148000.json','["別嶺有精廬，林巒亦幽絕。", "無事一往來，茶瓜不須設。"]'),
('949021f9-f176-4b9f-9321-2335c7b3fb11','雲谷雜詩十二首 登山','朱熹','宋','宋诗','song-poetry','','[]','夕陽翳東峰，微月下西嶺。',36,'全唐诗/poet.song.148000.json','["夕陽翳東峰，微月下西嶺。", "不辭青鞋穿，陟此巖路永。", "巖路永且躋，中情何耿耿。"]'),
('cb369a3e-b747-4298-8408-567cdf574cc4','雲谷雜詩十二首 值風','朱熹','宋','宋诗','song-poetry','','[]','山下風吹衣，山上風拔木。',36,'全唐诗/poet.song.148000.json','["山下風吹衣，山上風拔木。", "茅茨何足保，瀛海慮翻覆。", "永念執鬯人，無心還自恧。"]'),
('4ccf1f2a-9922-4423-a716-2ef3b70797b2','雲谷雜詩十二首 翫月','朱熹','宋','宋诗','song-poetry','','[]','風起雲氣昏，風定天宇肅。',36,'全唐诗/poet.song.148000.json','["風起雲氣昏，風定天宇肅。", "遥遥萬里暉，炯炯穿我屋。", "良友共徘徊，山中詎幽獨。"]'),
('ad3e2a7d-99e6-4736-8fe4-57c1fd7340f6','雲谷雜詩十二首 謝客','朱熹','宋','宋诗','song-poetry','','[]','野人載酒來，農談日西夕。',36,'全唐诗/poet.song.148000.json','["野人載酒來，農談日西夕。", "此意良已勤，感歎情何極。", "歸去莫頻來，林深山路黑。"]'),
('564c172f-0c9e-48d8-be39-7c16059dda8d','雲谷雜詩十二首 勞農','朱熹','宋','宋诗','song-poetry','','[]','四體久不勤，筋力坐駑緩。',36,'全唐诗/poet.song.148000.json','["四體久不勤，筋力坐駑緩。", "何事兩山阿，離離豆苗滿。", "多謝植杖翁，居然見長短。"]'),
('9c59804d-57d8-46f2-98e8-4038af261a61','雲谷雜詩十二首 講道','朱熹','宋','宋诗','song-poetry','','[]','高居遠塵雜，崇論探杳冥。',36,'全唐诗/poet.song.148000.json','["高居遠塵雜，崇論探杳冥。", "亹亹玄運駛，林林群動爭。", "天道固如此，吾生安得寧。"]'),
('a8b1a0c2-def2-4c8e-8189-842009848700','雲谷雜詩十二首 懷人','朱熹','宋','宋诗','song-poetry','','[]','吾黨二三子，欲來從我遊。',36,'全唐诗/poet.song.148000.json','["吾黨二三子，欲來從我遊。", "塵機諒擾擾，遐諾終悠悠。", "空山日復晚，佇立悵夷猶。"]'),
('0137064d-6e5b-46fe-a829-5ef8f65ea22b','雲谷雜詩十二首 倦遊','朱熹','宋','宋诗','song-poetry','','[]','故人千里別，約我仍丹丘。',36,'全唐诗/poet.song.148000.json','["故人千里別，約我仍丹丘。", "云何一解散，書到令人愁。", "此山豈不幽，何必賦遠遊。"]'),
('4fc46d51-a6b3-416b-929b-e9b4f2a3a8f0','雲谷雜詩十二首 修書','朱熹','宋','宋诗','song-poetry','','[]','紬書厭塵累，執簡投雲關。',36,'全唐诗/poet.song.148000.json','["紬書厭塵累，執簡投雲關。", "靈鑰啟玄秘，蕭斧鋤幽姦。", "書成莫示人，留置此山間。"]'),
('65d1ad44-3276-4dab-b59a-a37f2a18d0cb','雲谷雜詩十二首 宴坐','朱熹','宋','宋诗','song-poetry','','[]','登山思無窮，臨水心未厭。',36,'全唐诗/poet.song.148000.json','["登山思無窮，臨水心未厭。", "沉痾何當平，膏肓今自砭。", "默坐秋堂空，遐觀靡餘念。"]'),
('3ebc47f9-0439-4395-aa7c-62967a3e46de','雲谷雜詩十二首 下山','朱熹','宋','宋诗','song-poetry','','[]','行隨流水聲，步出哀壑底。',36,'全唐诗/poet.song.148000.json','["行隨流水聲，步出哀壑底。", "綠樹枝相樛，白澗石齒齒。", "樹石無窮年，流水日千里。"]'),
('df95668f-b1ab-40a2-8d8f-67176b61b509','雲谷雜詩十二首 還家','朱熹','宋','宋诗','song-poetry','','[]','出去柴門掩，歸來蕙草秋。',36,'全唐诗/poet.song.148000.json','["出去柴門掩，歸來蕙草秋。", "素荂林下吐，清芬衣上浮。", "欲寄山中友，日暮悵離憂。"]'),
('8477a02b-1a52-404a-b755-deabc13ac06f','雲谷合記事目效俳體戲作三詩寄季通  其一','朱熹','宋','宋诗','song-poetry','','[]','雲關須早築，基趾要堅牢。',48,'全唐诗/poet.song.148000.json','["雲關須早築，基趾要堅牢。", "栽竹行教密，穿池岸欲高。", "乘春移菡萏，带雪覓蕭椮。", "更向關門外，疏泉斬亂蒿。"]'),
('3d119d6a-bb0f-483b-8ca1-87950934bd67','雲谷合記事目效俳體戲作三詩寄季通  其二','朱熹','宋','宋诗','song-poetry','','[]','堂成今六載，上雨復旁風。',48,'全唐诗/poet.song.148000.json','["堂成今六載，上雨復旁風。", "逐急添茅蓋，連忙畢土功。", "桂林何日秀，蘭逕幾時通。", "并築雙臺子，東山接水筒。"]'),
('5c95a26d-6bed-44ae-80ee-5c16ffca43a0','雲谷合記事目效俳體戲作三詩寄季通  其三','朱熹','宋','宋诗','song-poetry','','[]','莊舍宜先立，山楹却漸營。',48,'全唐诗/poet.song.148000.json','["莊舍宜先立，山楹却漸營。", "泉疏藥圃潤，堰起石池清。", "早印荒田契，仍標別戶名。", "想應頻檢校，祇恐欠方兄。"]'),
('9a283d8a-6bac-449e-80ff-02db7ff785f1','雲谷懷魏元履','朱熹','宋','宋诗','song-poetry','','[]','歎息艮齋老，當年共此來。',48,'全唐诗/poet.song.148000.json','["歎息艮齋老，當年共此來。", "千峰奇絕處，一望興悠哉。", "病怯披雲卧，詩勞擁鼻裁。", "祇今何處所，宿草閟餘哀。"]'),
('15d8e138-18a3-4e0a-b8a2-73e1381b315f','送許順之南歸二首  其一','朱熹','宋','宋诗','song-poetry','','[]','門前三逕長蒿萊，愧子殷勤千里來。',32,'全唐诗/poet.song.148000.json','["門前三逕長蒿萊，愧子殷勤千里來。", "校罷遺書却歸去，此心元自不曾灰。"]'),
('f02b06f6-c2fb-401a-a8ca-8bcbba3d49a5','送許順之南歸二首  其二','朱熹','宋','宋诗','song-poetry','','[]','幾年江海事幽尋，偏與雲僧話此心。',32,'全唐诗/poet.song.148000.json','["幾年江海事幽尋，偏與雲僧話此心。", "今日肯來論舊學，歲寒猶恐雪霜侵。"]'),
('70a9b7cf-9920-431b-aa76-81aa5a79c5ea','宿雲際寺許順之將別以詩求教次韻','朱熹','宋','宋诗','song-poetry','','[]','薄暮投花縣，聯車入翠微。',48,'全唐诗/poet.song.148000.json','["薄暮投花縣，聯車入翠微。", "長林生缺月，永夜照寒扉。", "情話欣無歝，離懷悵有違。", "勉哉彊毅力，千里要同歸。"]'),
('373bec5c-b4c1-405e-8598-db0a5b1010d4','挽汪端明三首  其一','朱熹','宋','宋诗','song-poetry','','[]','聖王興炎運，明公起妙年。',48,'全唐诗/poet.song.148000.json','["聖王興炎運，明公起妙年。", "材推漢庭右，學自北方傳。", "出入丹心壯，安危素髮鮮。", "空餘題劍在，光燭舊林泉。"]'),
('34d4439e-cf42-44ee-a702-0afc4fc2664a','挽汪端明三首  其二','朱熹','宋','宋诗','song-poetry','','[]','曠宇元無際，孤標自不羣。',48,'全唐诗/poet.song.148000.json','["曠宇元無際，孤標自不羣。", "物情良有寄，讒口詎堪聞。", "未許時明政，猶堪史闕文。", "衣冠忽長夜，餘子謾紛紛。"]'),
('77321ac1-df8a-45a5-8a8c-1fa6770c68b2','挽汪端明三首  其三','朱熹','宋','宋诗','song-poetry','','[]','先友當年盛，斯文元祐徒。',48,'全唐诗/poet.song.148000.json','["先友當年盛，斯文元祐徒。", "艱虞共流落，存沒半嗚呼。", "顧我真無頼，逢公幸不孤。", "祇今還一慟，即此是窮塗。"]'),
('b1545d0a-bc1b-4563-9e89-45d0a90e0a0f','彥集奉檄歸省示及佳篇次韻奉酬呈諸兄友','朱熹','宋','宋诗','song-poetry','','[]','游子思親久聚糧，不堪官裏簿書忙。',64,'全唐诗/poet.song.148000.json','["游子思親久聚糧，不堪官裏簿書忙。", "平生况少鷹鸇意，此日尤慙時世粧。", "臘雪未消歡奉檄，春風初轉喜還鄉。", "上堂佳慶從容問，一釂何妨累十觴。"]'),
('59a74a71-b9d6-4f20-8e2c-e6cf9877af3a','彥集兄再適臨汀惠顧蓬蓽賦詩留別眷予良勤次韻祖行言不盡意','朱熹','宋','宋诗','song-poetry','','[]','賸喜君才老更成，伊優叢裏見孤撐。',64,'全唐诗/poet.song.148000.json','["賸喜君才老更成，伊優叢裏見孤撐。", "官身未免心徒壯，親膝頻違淚欲橫。", "簿領不嫌春筍束，廉聲要比玉壺清。", "枉車投翰殷勤甚，安得仁言與贈行。"]'),
('e3523c22-6d86-4103-9425-547027af0a19','圭父爲彥集置酒白蓮沼上彥集有詩因次其韻呈坐上諸友','朱熹','宋','宋诗','song-poetry','','[]','大阮歸來客滿堂，更移芳席近回塘。',64,'全唐诗/poet.song.148000.json','["大阮歸來客滿堂，更移芳席近回塘。", "共憐的皪水花凈，并倚離披風蓋凉。", "銀筆看題青玉案，佳人悵望碧雲鄉。", "此時此景真愁絕，病著無因爲舉觴。"]'),
('508f82e8-f208-4e3e-a7e4-48adba4a5024','寄題宜春使君定叟張兄隠齋','朱熹','宋','宋诗','song-poetry','','[]','大專槃萬生，異體實同氣。',168,'全唐诗/poet.song.148000.json','["大專槃萬生，異體實同氣。", "云胡分彼己，直以私自蔽。", "君家桂林伯，德學妙一世。", "閉戶不忘憂，纓冠矧行義。", "眷言介弟賢，四益謹先畀。", "千里各分符，一心同盡瘁。", "遠題齋戶冊，來表棲息地。", "系述寫心胸，俯仰資惕厲。", "陽嘉既滌蕩，陰慝失封閉。", "介然彼苛癢，嚇若我黥劓。", "拊摩極哀恫，征取敢常藝。", "戰兢一日力，洋溢四封被。", "君看物我間，隠顯豈殊致。", "願反振民功，更懋根本計。"]'),
('993b0b72-2722-4dc7-9776-86631a7b31bb','次韻題平父兄重建一枝堂','朱熹','宋','宋诗','song-poetry','','[]','畫㦸朱門枕碧山，貂蟬元自出儒冠。',64,'全唐诗/poet.song.148000.json','["畫㦸朱門枕碧山，貂蟬元自出儒冠。", "更餘此日林間樂，遠繼當年膝下歡。", "命駕賓朋千里近，放懷琴酒百憂寬。", "遺編却好傳孫子，莫遣因循學宴安。"]'),
('1638cc83-553b-45bf-b544-5c685c604a73','日用自警示平父','朱熹','宋','宋诗','song-poetry','','[]','圓融無際大無餘，即此身心是太虛。',64,'全唐诗/poet.song.148000.json','["圓融無際大無餘，即此身心是太虛。", "不向用時勤猛省，却於何處味真腴。", "尋常應對尤須謹，造次施爲更莫踈。", "一日洞然無別體，方知不枉費功夫。"]'),
('67153bca-f304-4815-aed1-e222827b3b93','抄二南寄平父因題此詩','朱熹','宋','宋诗','song-poetry','','[]','闕里言詩得賜商，千秋誰復與相望。',64,'全唐诗/poet.song.148000.json','["闕里言詩得賜商，千秋誰復與相望。", "鄒汾斷簡光前載，關洛新書襲舊芳。", "析句分章功自少，吟風弄月興何長。", "從容咏嘆無今古，此樂從茲樂未央。"]'),
('8f42ed07-c2ca-4653-b9b0-b68f8df4972c','題劉平甫定菴五詠 定菴','朱熹','宋','宋诗','song-poetry','','[]','風生長林悲，雲起空谷暝。',24,'全唐诗/poet.song.148000.json','["風生長林悲，雲起空谷暝。", "下有不死人，一室常在定。"]'),
('de9a8a55-9613-4124-9750-5c0cc2dea4d3','題劉平甫定菴五詠 巢雲','朱熹','宋','宋诗','song-poetry','','[]','入山何所見，雲樹春濛濛。',24,'全唐诗/poet.song.148000.json','["入山何所見，雲樹春濛濛。", "安知巢居子，避世於其中。"]'),
('f0d5e12b-6d3a-4e6b-88a3-0dae4432dfa0','題劉平甫定菴五詠 山臺','朱熹','宋','宋诗','song-poetry','','[]','林居厭棲迷，山頂幸清曠。',24,'全唐诗/poet.song.148000.json','["林居厭棲迷，山頂幸清曠。", "無事一登臨，却愁心浩蕩。"]'),
('9267e7d5-9fa6-4e44-bde2-cd89adac64c9','題劉平甫定菴五詠 井泉','朱熹','宋','宋诗','song-poetry','','[]','開山昔何人，鑿此寒泉井。',24,'全唐诗/poet.song.148000.json','["開山昔何人，鑿此寒泉井。", "獨夜潄瓊瑶，泠然發深省。"]'),
('db01fff1-88ba-41a6-8a85-99827867a129','題劉平甫定菴五詠 壽穴','朱熹','宋','宋诗','song-poetry','','[]','百年不可期，一壑當預卜。',24,'全唐诗/poet.song.148000.json','["百年不可期，一壑當預卜。", "自憐木偶人，空羨王官谷。"]'),
('009f2ea8-226b-4c38-991a-6f013ea304e9','劉平甫席上分韻得寫字','朱熹','宋','宋诗','song-poetry','','[]','歲暮風雨交，流雲暗平野。',48,'全唐诗/poet.song.148000.json','["歲暮風雨交，流雲暗平野。", "公子燕華姻，招呼及同社。", "高情寄壺觴，晤語到風雅。", "剪燭夜堂深，幽懷共輸寫。"]'),
('1be85892-4fdb-46a7-88e1-d849f0eb8e4c','劉平甫分惠水梔小詩爲謝二首  其一','朱熹','宋','宋诗','song-poetry','','[]','年來衰懶罷書淫，偶向盆山寄此心。',32,'全唐诗/poet.song.148000.json','["年來衰懶罷書淫，偶向盆山寄此心。", "何事凉陰老居士，便分幽賞助清吟。"]'),
('15f36130-816d-4d17-a067-4aa9bbf93977','劉平甫分惠水梔小詩爲謝二首  其二','朱熹','宋','宋诗','song-poetry','','[]','何處飛來薝蔔林，老枝樛屈更蕭椮。',32,'全唐诗/poet.song.148000.json','["何處飛來薝蔔林，老枝樛屈更蕭椮。", "凄凉杜老江頭句，坐對行吟得自箴。"]'),
('9cec9ea6-f291-43d2-8c4c-d18e9a402df9','和喜雨二絕  其一','朱熹','宋','宋诗','song-poetry','','[]','雨師誰遣送餘春，珍重天公惠我民。',32,'全唐诗/poet.song.148000.json','["雨師誰遣送餘春，珍重天公惠我民。", "且看歡顔垂白叟，莫愁頩頰踏青人。"]'),
('f25575f2-98ee-42de-8b08-91ee996a6f15','和喜雨二絕  其二','朱熹','宋','宋诗','song-poetry','','[]','黄昏一雨到天明，夢裏豐年有頌聲。',32,'全唐诗/poet.song.148000.json','["黄昏一雨到天明，夢裏豐年有頌聲。", "起望平疇烟草綠，只今投筆事農耕。"]'),
('f133252d-7c1e-40b4-8a67-d8d42b8e24e3','和章國華祈雨呈平父諸兄三首  其一','朱熹','宋','宋诗','song-poetry','','[]','極目平疇半欲枯，遥知精禱意無餘。',32,'全唐诗/poet.song.148000.json','["極目平疇半欲枯，遥知精禱意無餘。", "更憐不待豚蹄祝，便得汙邪暗滿車。"]'),
('e611b7ef-dfea-4c36-a0fc-d166fdef412c','和章國華祈雨呈平父諸兄三首  其二','朱熹','宋','宋诗','song-poetry','','[]','九重清夜仰昭回，旱魃知從何處來。',32,'全唐诗/poet.song.148000.json','["九重清夜仰昭回，旱魃知從何處來。", "不是幽人祈得雨，又煩丹詔走風雷。"]'),
('dc07f1a9-08ee-47cd-9b9b-91ece2eda6df','和章國華祈雨呈平父諸兄三首  其三','朱熹','宋','宋诗','song-poetry','','[]','晴窗揮汗苦驕陽，雨檻披衣快晚凉。',32,'全唐诗/poet.song.148000.json','["晴窗揮汗苦驕陽，雨檻披衣快晚凉。", "多謝龍公餘事業，爲驅寒谷變炎方。"]'),
('1add18fd-bd96-45a4-a267-d5b82f543708','山館諸兄共賦驟雨鷺鷥二絕  其一','朱熹','宋','宋诗','song-poetry','','[]','平疇焦渴不堪論，簫鼓悲秋徹帝閽。',32,'全唐诗/poet.song.148000.json','["平疇焦渴不堪論，簫鼓悲秋徹帝閽。", "霹靂一聲雲自墨，山前山後雨翻盆。"]'),
('15e6bd22-abd4-46be-b4f8-816427e0a97f','山館諸兄共賦驟雨鷺鷥二絕  其二','朱熹','宋','宋诗','song-poetry','','[]','雨罷微塘凜欲秋，飛來白鳥便夷猶。',32,'全唐诗/poet.song.148000.json','["雨罷微塘凜欲秋，飛來白鳥便夷猶。", "從今認得橫塘路，水遠天長百不憂。"]'),
('61ef4976-4707-4398-bdfc-a4fbfd9d09db','唐石雪中','朱熹','宋','宋诗','song-poetry','','[]','春風欲動客辭家，霖潦縱橫路轉賒。',32,'全唐诗/poet.song.148000.json','["春風欲動客辭家，霖潦縱橫路轉賒。", "行到溪山愁絕處，千林一夜玉成花。"]'),
('ea89aede-c618-479a-8cdd-f40c2111f7ef','秋日同廖子晦劉淳叟方伯休劉彥集登天湖下飲泉石軒以山水含清暉分韻賦詩得清字','朱熹','宋','宋诗','song-poetry','','[]','閒居寡儔侶，掩關抱孤清。',96,'全唐诗/poet.song.148000.json','["閒居寡儔侶，掩關抱孤清。", "良友倏來止，曠然舒我情。", "矧此凉秋初，暑退裳衣輕。", "相與一携手，東山眇遐征。", "前穿林嶺幽，俯瞰川原平。", "降集崖寺古，徘徊濁醪傾。", "長吟伐木篇，潛鱗亦相驚。", "願結沮溺耦，窮年此巖耕。"]'),
('8ad68d51-ba5e-475e-a20d-0ba63d305492','淳熙戊戌七月二十九日與子晦純叟伯休同發屏山西登雲谷越夕乃至而季通德功亦自山北來會賦詩記事以雲卧衣裳冷分韻賦詩得冷字','朱熹','宋','宋诗','song-poetry','','[]','端筴得幽貞，考槃寄茲嶺。',132,'全唐诗/poet.song.148000.json','["端筴得幽貞，考槃寄茲嶺。", "未成長往計，抱恨中耿耿。", "秋風吹庭樹，遥夜枕席冷。", "感彼歲序移，慨此心事永。", "明晨發孤興，趣駕向絕境。", "躋攀力雖倦，想象意逾騁。", "雲山一以眺，俯仰疑倒景。", "檢校石田收，眷戀茅屋靜。", "淹留復未遂，外物愧張邴。", "珍重同來人，妙語各清整。", "擊節三嘆餘，超然得深省。"]'),
('06ae5364-9416-4a80-97b7-76e5b1a7e556','宿黄沙以山如翠浪湧分韻賦詩得如字','朱熹','宋','宋诗','song-poetry','','[]','日中秣吾馬，日暮膏吾車。',72,'全唐诗/poet.song.148000.json','["日中秣吾馬，日暮膏吾車。", "崎嶇涉南嶺，浩蕩凌八嶇。", "夜雨薦峰前，朝登碧琳瓀。", "蒼茫永嘯罷，翕忽清景徂。", "去此二三子，我行將焉如。", "崔嵬正丘垤，萬里思南圖。"]'),
('e7d04b51-2376-49db-902a-5e13adafabcc','雲谷次吳公濟韻','朱熹','宋','宋诗','song-poetry','','[]','昔營此幽棲，邈與世相絕。',144,'全唐诗/poet.song.148000.json','["昔營此幽棲，邈與世相絕。", "誓將百年身，來守固窮節。", "心期苦未遂，歲月一何闊。", "終然匹夫志，肯遽甘沒沒。", "茲晨復登瞰，目盡雲一抹。", "激烈永嘯餘，朗寥高韻發。", "夫君內德備，不學王駘兀。", "觀心見參倚，出世自英傑。", "朅來肯顧我，同去弄雲月。", "微言得深扣，大句亦孤拔。", "多謝警踈慵，未敢嘆瞻忽。", "更問毫釐間，是同端是別。"]'),
('cf9e140f-ce64-4c3c-a355-a4c1c86d37f3','宿休菴用德功壁間韻贈陳道人','朱熹','宋','宋诗','song-poetry','','[]','暮入千峰裏，寒棲一草菴。',48,'全唐诗/poet.song.148000.json','["暮入千峰裏，寒棲一草菴。", "室連丹竈煖，厨引石泉甘。", "塵慮紛難到，神光暖內含。", "非君有道氣，孤絕詎能堪。"]'),
('eab52501-a435-474c-bd7d-913624e723c3','挽劉樞密三首  其一','朱熹','宋','宋诗','song-poetry','','[]','天畀經綸業，家傳忠義心。',48,'全唐诗/poet.song.148000.json','["天畀經綸業，家傳忠義心。", "謀謨經國遠，勳烈到人深。", "廊廟風雲斷，江湖歲月侵。", "一朝成殄瘁，九牧共沾襟。"]'),
('51cfda26-81cc-4335-bbde-39945b78f8d8','挽劉樞密三首  其二','朱熹','宋','宋诗','song-poetry','','[]','談笑平蠻策，焦勞振廩功。',48,'全唐诗/poet.song.148000.json','["談笑平蠻策，焦勞振廩功。", "復讐乖宿志，忍死罄餘忠。", "人嘆百身贖，天悲一鑑空。", "九原終莫起，千載自英風。"]'),
('c6616cb1-5678-4900-84e1-b8055a582228','挽劉樞密三首  其三','朱熹','宋','宋诗','song-poetry','','[]','久矣身無用，前恩嘆莫償。',48,'全唐诗/poet.song.148000.json','["久矣身無用，前恩嘆莫償。", "豈期今老大，復此重悲傷。", "淚向遺書盡，心隨宿草荒。", "諸君那不死，慟絕鬢成霜。"]'),
('a06392e4-d3b8-4ab8-a1bb-c5bb8a6617d9','武夷七詠 天柱峰','朱熹','宋','宋诗','song-poetry','','[]','屹然天一柱，雄鎮斡維東。',24,'全唐诗/poet.song.148000.json','["屹然天一柱，雄鎮斡維東。", "祇說乾坤大，誰知立極功。"]'),
('9e3f56b3-1b04-406a-bc63-f43cd264b6c5','武夷七詠 洞天','朱熹','宋','宋诗','song-poetry','','[]','絕壁上千尋，隠約巖栖處。',24,'全唐诗/poet.song.148000.json','["絕壁上千尋，隠約巖栖處。", "笙鶴去不還，人間自今古。"]'),
('6c420e0a-50bc-4bcf-ab26-4aa378947209','武夷七詠 畫鶴','朱熹','宋','宋诗','song-poetry','','[]','誰寫青田質，高超鴈鶩群。',24,'全唐诗/poet.song.148000.json','["誰寫青田質，高超鴈鶩群。", "長疑風月夜，清唳九霄聞。"]'),
('523747b2-952a-4d83-b2d6-85efa040fb70','武夷七詠 仰高堂','朱熹','宋','宋诗','song-poetry','','[]','面勢來空翠，哦詩獨好仁。',24,'全唐诗/poet.song.148000.json','["面勢來空翠，哦詩獨好仁。", "懷人今已矣，誰遣棟梁新。"]'),
('c4550fad-6cbc-49ef-88ca-8678b3526e5b','武夷七詠 趨真亭','朱熹','宋','宋诗','song-poetry','','[]','危亭久已傾，祇有頹基在。',24,'全唐诗/poet.song.148000.json','["危亭久已傾，祇有頹基在。", "何事往來人，不知容鬢改。"]'),
('00ce1938-95c2-425e-a524-434153e40973','武夷七詠 大小藏巖','朱熹','宋','宋诗','song-poetry','','[]','藏室岌相望，塵編何莽鹵。',24,'全唐诗/poet.song.148000.json','["藏室岌相望，塵編何莽鹵。", "欲問伯陽翁，風煙迷處所。"]'),
('8b28d514-cbf4-4eb1-9db3-93c26a8331aa','武夷七詠 丹竈','朱熹','宋','宋诗','song-poetry','','[]','仙人推卦節，煉火守金舟。',24,'全唐诗/poet.song.148000.json','["仙人推卦節，煉火守金舟。", "一上煙霄路，千年亦不還。"]'),
('55dfae20-b983-4d6a-8583-28767bbc4716','壬子三月二十七日聞迅雷有感','朱熹','宋','宋诗','song-poetry','','[]','誰將神斧破頑陰，地裂山開鬼失林。',32,'全唐诗/poet.song.148000.json','["誰將神斧破頑陰，地裂山開鬼失林。", "我願君王法天造，早施雄斷答羣心。"]'),
('c3013556-d89f-4ca7-96d7-0984a424e2e5','崇壽客舍夜聞子規得三絕句寫呈平父兄煩爲轉寄彥集兄及兩縣間諸親友  其一','朱熹','宋','宋诗','song-poetry','','[]','空山初夜子規鳴，靜對琴書百慮清。',32,'全唐诗/poet.song.148000.json','["空山初夜子規鳴，靜對琴書百慮清。", "喚得形神兩超越，不知底是斷腸聲。"]'),
('b012a93f-970d-4df0-8c2c-bb47aa4a879e','崇壽客舍夜聞子規得三絕句寫呈平父兄煩爲轉寄彥集兄及兩縣間諸親友  其二','朱熹','宋','宋诗','song-poetry','','[]','空山中夜子規啼，病怯餘寒覓故衣。',32,'全唐诗/poet.song.148000.json','["空山中夜子規啼，病怯餘寒覓故衣。", "不爲明時堪眷戀，久知岐路不如歸。"]'),
('358afb3c-eef4-4c06-8e70-1ca0d1eddee3','崇壽客舍夜聞子規得三絕句寫呈平父兄煩爲轉寄彥集兄及兩縣間諸親友  其三','朱熹','宋','宋诗','song-poetry','','[]','空山後夜子規號，斗轉星移月尚高。',32,'全唐诗/poet.song.148000.json','["空山後夜子規號，斗轉星移月尚高。", "夢裏不知歸未得，已驅黄犢度寒臯。"]'),
('48d0f951-4c5c-468a-9263-5dead947e186','寄雲谷瑞泉菴主','朱熹','宋','宋诗','song-poetry','','[]','憶昔誅茅日，山房我自名。',72,'全唐诗/poet.song.148000.json','["憶昔誅茅日，山房我自名。", "風埃猶俗累，煙雨負巖耕。", "多謝空門侶，能同物外情。", "肯來分半壑，聊爾度平生。", "少待清秋日，閑尋遠嶽盟。", "不知誰是客，一笑絕塵纓。"]'),
('21f1b5b6-0a83-47e1-84a4-eedcb9a3e6cb','入南康界閲圖經感陶公李渤劉凝之事戲作','朱熹','宋','宋诗','song-poetry','','[]','長官定笑歸來晚，中允應嫌去却回。',32,'全唐诗/poet.song.148000.json','["長官定笑歸來晚，中允應嫌去却回。", "惟有山人莫相笑，也曾還俗做官來。"]'),
('25b0219d-2043-4538-a7fe-a19fc52de0d5','屢游廬阜欲賦一篇而不能就六月中休董役卧龍偶成此詩','朱熹','宋','宋诗','song-poetry','','[]','登車閩嶺徼，息駕康山陽。',192,'全唐诗/poet.song.148000.json','["登車閩嶺徼，息駕康山陽。", "康山高不極，連峰鬰蒼蒼。", "金輪西嵯峨，五老東昂藏。", "想象仙聖集，似聞笙鶴翔。", "林谷下凄迷，雲關杳相望。", "千巖雖競秀，二勝終莫量。", "仰瞻銀河翻，俯看交龍驤。", "長吟謫仙句，和以玉局章。", "疇昔勞夢思，茲今幸徜徉。", "尚恨忝符竹，未愜棲雲房。", "已尋兩峰間，結屋依陽岡。", "上有飛瀑駛，下有清流長。", "循名協心期，弔古增悲凉。", "壯齒乏奇節，頹年矧昏荒。", "誓將塵土蹤，暫寄雲水鄉。", "封章儻從欲，歸哉澡滄浪。"]'),
('23122664-2ef2-4ad7-8706-0f1da088d4cc','讀李賓老玉澗詩偶成','朱熹','宋','宋诗','song-poetry','','[]','獨抱瑶琴過玉溪，琅然清夜月明時。',32,'全唐诗/poet.song.148000.json','["獨抱瑶琴過玉溪，琅然清夜月明時。", "祇今已是無心久，却怕山前荷簣知。"]'),
('7cd6b3ac-2784-4c82-b845-6a6594aeaaad','立秋日同子澄寺簿及僉判教授二同寮星子令尹約周君段君同遊三峽過山房登折桂分韻賦詩得萬字輒成十韻呈諸同遊','朱熹','宋','宋诗','song-poetry','','[]','抗塵幾何時，猿鶴共悲怨。',120,'全唐诗/poet.song.148000.json','["抗塵幾何時，猿鶴共悲怨。", "豈知朱墨暇，乃適山水願。", "茲晨秋令初，休沐謹邦憲。", "佳賓忽四來，英僚亦三勸。", "駕言北郭門，謝此旟隼建。", "散目山崔嵬，縱轡路脩蔓。", "凭欄快倒峽，躋壑困脫輓。", "追攀林樾深，歡喜脚力健。", "登高眺遠浦，衆景爭自獻。", "何必仍丹丘，徑欲凌九萬。"]'),
('a8fee36e-2ab6-432f-a388-68383c8b8f02','和子澄白鹿之句','朱熹','宋','宋诗','song-poetry','','[]','經旬不到鹿場陰，夢想飛馳不自禁。',64,'全唐诗/poet.song.148000.json','["經旬不到鹿場陰，夢想飛馳不自禁。", "幸有高軒同勝賞，何妨折屐共幽尋。", "徘徊未厭詩書樂，感慨難忘忠孝心。", "更對豐鎸哦伐木，風泉雲壑助清吟。"]'),
('0fdb15b1-6f7f-4d29-8815-7f1003ee397f','暇日侍法曹叔父陪諸名勝爲落星之遊分韻得往字率爾賦呈聊發一笑','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江西委輸，匯澤東滉瀁。',72,'全唐诗/poet.song.148000.json','["長江西委輸，匯澤東滉瀁。", "中川屹孤嶼，佛屋寄幽賞。", "我來此何日，秋氣欲蕭爽。", "共載得高儔，良晨豈孤往。", "酒酣清嘯發，浪湧初月上。", "疊鼓喚歸艎，陳迹真俯仰。"]'),
('80787d42-5264-405e-b0dc-54bf606d5eff','九日奉陪高州史君莆陽別駕會稽丞公善化明府仲衡詩伯并屈子美元範二兄及郡中諸文武同登紫霄絕頂南望江湖北眺淮甸少快心目既歸又得仲衡佳篇句法清麗情致悽惋三復不勝起予之歎謹次韻呈請皆賦之以紀一時之盛甚惠甚望','朱熹','宋','宋诗','song-poetry','','[]','此日登高處，千巖錦樹稠。',48,'全唐诗/poet.song.148000.json','["此日登高處，千巖錦樹稠。", "無人嘲落帽，有客賦悲秋。", "忽忽塵中老，怱怱物外遊。", "江湖空極目，不盡古今愁。"]'),
('69999c59-76c5-4d61-8d59-c7118a71266a','下元節假行視陂塘因與賓友挈兒甥出郭登山歸賦二詩示子直春卿及折桂雲谷并寫呈郡中諸寮友','朱熹','宋','宋诗','song-poetry','','[]','廬阜東北際，岧嶢五峰尊。',168,'全唐诗/poet.song.148000.json','["廬阜東北際，岧嶢五峰尊。", "中巖穹林繞，青天白雲屯。", "郡閣有佳眺，徙倚空朝昏。", "今晨幸休暇，發軔北郭門。", "牽蘿出林端，躡屐躋雲根。", "高尋却深宦，小憩欣潺湲。", "古殿宿寒靄，新甍麗朝暾。", "扶藜陟東岡，夙昔規曾軒。", "却倚千尋峭，前窺百泉奔。", "長風卷浮埃，江湖渺相吞。", "結架雖未諧，雄瓌已難論。", "同來俱勝流，晤語仍王孫。", "已踐支許諾，不慙夙尚魂。", "賦詩紀茲日，歲晚期相敦。"]'),
('6459297d-6825-4d5a-8490-5e945a9fc67f','卧龍之遊得秋字賦詩紀事呈同遊諸名勝聊發一笑','朱熹','宋','宋诗','song-poetry','','[]','躡石度急澗，窮源得靈湫。',192,'全唐诗/poet.song.148000.json','["躡石度急澗，窮源得靈湫。", "谽谺兩對立，噴薄中怒投。", "何年避人世，結屋棲巖陬。", "嘉名信有託，故迹誰能求。", "我來一經行，凄其仰前脩。", "鄰翁識此意，伐木南山幽。", "爲我立精舍，開軒俯清流。", "多岐諒匪安，一壑真良謀。", "解組云未遂，驅車且來遊。", "嘉賓頗蟬聯，野䔩更獻酬。", "飲罷不知晚，欲去還淹留。", "躋攀已別峰，窺臨忽滄洲。", "下集西澗底，沉吟樹相樛。", "玉淵茗飲餘，三峽空尊愁。", "懷賢既伊鬰，感事增綢繆。", "前旌向城郭，回首千峰秋。"]'),
('b863b846-d88c-4313-81a0-143fb3011feb','卧龍之遊錢通守得江字不及賦詩已解維矣熹用其韻紀事以贈并附卷末','朱熹','宋','宋诗','song-poetry','','[]','君行安所適，衝風泝濤江。',96,'全唐诗/poet.song.148000.json','["君行安所適，衝風泝濤江。", "傳聞閬州好，未見心已降。", "邀君康山遊，聽此巨壑淙。", "班坐酌溪石，幽尋憩雲窗。", "勸君盡此杯，錦帆已稠杠。", "明年儻來東，鳴鐃建高幢。", "訪我深澗底，晤言絕紛嚨。", "城南且細說，慰我心悾悾。"]'),
('10b4b74f-90b1-4e63-ae06-c20b38ea8ca7','分韻得眠意二字賦醉石簡寂各一篇呈同遊諸兄  其一','朱熹','宋','宋诗','song-poetry','','[]','驅車何所適，往至秋雲邊。',120,'全唐诗/poet.song.148000.json','["驅車何所適，往至秋雲邊。", "企彼澗中石，舉觴酹飛泉。", "懷哉千載人，矯首辭世喧。", "凄凉義熙後，日醉向此眠。", "仰視但青冥，俯聽驚潺湲。", "起坐三太息，涕泗如奔川。", "神馳北闕陰，思屬東海壖。", "丹衷竟莫展，素節空復全。", "低徊萬古情，惻愴顔公篇。", "爲君結茅屋，歲暮當來還。"]'),
('e145a211-7cb1-4949-9d2f-799a58e9b5d7','分韻得眠意二字賦醉石簡寂各一篇呈同遊諸兄  其二','朱熹','宋','宋诗','song-poetry','','[]','天秋山氣深，日落林景翠。',120,'全唐诗/poet.song.148000.json','["天秋山氣深，日落林景翠。", "亦知後騎迫，且復一流憩。", "環瞻峰列屏，迥矚泉下濞。", "永懷仙陸子，久挹浮丘袂。", "于今知幾載，故宇日荒廢。", "空餘醮壇石，香火誰復繼。", "更憐韋刺史，五字有真意。", "虎竹付歸人，悲風起橫吹。", "沉吟向絕迹，浩蕩發幽寄。", "來者知爲誰，念我儻三喟。"]'),
('fe1a9444-8985-4765-9911-77b4c9bc31c7','尋白鹿洞故址愛其幽邃議復興建感歎有作','朱熹','宋','宋诗','song-poetry','','[]','清泠寒澗水，窈窕青山阿。',144,'全唐诗/poet.song.148000.json','["清泠寒澗水，窈窕青山阿。", "昔賢有幽尚，眷言此婆娑。", "事往今幾時，高軒絕來過。", "學館空廢址，鳴絃息遺歌。", "我來勸相餘，杖策搴綠蘿。", "謀野欣有獲，披圖知匪訛。", "永懷當年盛，莘莘衿佩多。", "博約感明恩，涵濡熙泰和。", "凄凉忽荒榛，俯仰驚頹波。", "發教逮綱紀，喟然心靡它。", "伐木循陰岡，結屋依陽坡。", "一朝謝塵濁，歸哉碩人薖。"]'),
('1818cce8-2214-4bfc-99a5-51841f080c96','遊白鹿洞熹得謝字賦呈元範伯起之才三兄并示諸同遊者','朱熹','宋','宋诗','song-poetry','','[]','歲月有環周，窮臘忽受謝。',144,'全唐诗/poet.song.148000.json','["歲月有環周，窮臘忽受謝。", "眷眷山水心，幸此朱墨暇。", "招呼得良友，邂逅成夙駕。", "深尋故轍迹，喜見新結架。", "永懷拾遺公，藏器此待價。", "橫流詩書澤，下及楊李霸。", "炎神撫興運，制作流大化。", "石室萬卷藏，綸言九天下。", "規模未云遠，荒茀良可詫。", "自非賢邑宰，誰復此精舍。", "會當求敕賜，畢願老耕稼。", "更與盡心期，臨流抗風榭。"]'),
('2efa2891-e226-4bf2-963b-13994bb65769','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 江梅','朱熹','宋','宋诗','song-poetry','','[]','大雪天地閉，窮陰渺寒濱。',24,'全唐诗/poet.song.148000.json','["大雪天地閉，窮陰渺寒濱。", "誰知江南信，已作明年春。"]'),
('53d40ee3-523b-4304-8067-8b8050d97c10','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 嶺梅','朱熹','宋','宋诗','song-poetry','','[]','梅花破萼時，瘴雨吹成雪。',24,'全唐诗/poet.song.148000.json','["梅花破萼時，瘴雨吹成雪。", "驛使忽相逢，無言似愁絕。"]'),
('51ef9dd0-563f-4699-8803-99f6313c1f23','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 野梅','朱熹','宋','宋诗','song-poetry','','[]','野風吹孤芳，迥立正愁絕。',24,'全唐诗/poet.song.148000.json','["野風吹孤芳，迥立正愁絕。", "皂蓋莫徘徊，堪看不堪折。"]'),
('b981b257-8b44-446f-824c-61d36a7e6be6','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 早梅','朱熹','宋','宋诗','song-poetry','','[]','霜風殊未高，杖策荒園裏。',24,'全唐诗/poet.song.148000.json','["霜風殊未高，杖策荒園裏。", "仙子別經年，相看共驚喜。"]'),
('66627706-b8cc-4dbe-8ce6-88e21b7dd133','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 寒梅','朱熹','宋','宋诗','song-poetry','','[]','白玉堂前樹，風清月影殘。',24,'全唐诗/poet.song.148000.json','["白玉堂前樹，風清月影殘。", "無情三弄笛，遥夜不勝寒。"]'),
('abef7778-af8e-4f46-ac57-9d7f3485db89','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 小梅','朱熹','宋','宋诗','song-poetry','','[]','且喜梅花開，莫嗟梅花小。',24,'全唐诗/poet.song.148000.json','["且喜梅花開，莫嗟梅花小。", "花小風味深，此意君已了。"]'),
('849a79d6-d9d5-4207-bdad-91f6e85c7e3f','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 踺梅','朱熹','宋','宋诗','song-poetry','','[]','玉笛未黄昏，冰灘已清淺。',24,'全唐诗/poet.song.148000.json','["玉笛未黄昏，冰灘已清淺。", "踈影不勝妍，愁心爲誰遠。"]'),
('ad4cf6ef-8a43-4053-9f27-5215245c443f','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 枯梅','朱熹','宋','宋诗','song-poetry','','[]','樛枝卧龍蛇，冷蘂綴冰雪。',24,'全唐诗/poet.song.148000.json','["樛枝卧龍蛇，冷蘂綴冰雪。", "千里故人心，今年爲誰折。"]'),
('1cf81d6b-7825-46c1-8f0f-83761e2a2d7a','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 落梅','朱熹','宋','宋诗','song-poetry','','[]','花開已凄凉，花落更愁寂。',24,'全唐诗/poet.song.148000.json','["花開已凄凉，花落更愁寂。", "來歲煙雨時，爲君和鼎實。"]'),
('9abe1c86-82ec-4b99-a6c0-685864c4d890','元範尊兄示及十梅詩風格清新意寄深遠吟玩累日欲和不能昨夕自白鹿玉澗歸偶得數語 賦梅','朱熹','宋','宋诗','song-poetry','','[]','君欲賦梅花，梅花若爲賦。',24,'全唐诗/poet.song.148000.json','["君欲賦梅花，梅花若爲賦。", "繞樹百千回，句在無言處。"]'),
('bd0a281e-bc44-452c-af3f-e84e82497980','觀梅小集以齋禁不得奉陪因寄小詩','朱熹','宋','宋诗','song-poetry','','[]','梅花年後欲離披，恰是先生變食時。',32,'全唐诗/poet.song.148000.json','["梅花年後欲離披，恰是先生變食時。", "送與西樓一尊酒，諸君莫負可憐枝。"]'),
('6e325647-c8ef-4c47-ae01-12c8f2b60837','元範別後寄惠佳篇清叟次韻見示格律俱高詠歎不置因亦用韻寫呈二兄聊發一笑  其一','朱熹','宋','宋诗','song-poetry','','[]','故人別我去，一月曠音驛。',96,'全唐诗/poet.song.148000.json','["故人別我去，一月曠音驛。", "今朝得新詩，開卷意已適。", "知君到里門，征騎聊一息。", "行復敞天閽，從容正朝幘。", "自今九霄路，不復兩塵隔。", "容與日華東，翱翔禁扉北。", "回頭五峰下，寂漠笑孤客。", "不賦歸去來，心形謾相役。"]'),
('1a32b4c3-1fa6-44f8-80e6-00bfc56c3f06','元範別後寄惠佳篇清叟次韻見示格律俱高詠歎不置因亦用韻寫呈二兄聊發一笑  其二','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五十行過二，雙鬢颯秋草。',96,'全唐诗/poet.song.148000.json','["五十行過二，雙鬢颯秋草。", "平生素心人，誰與共茲抱。", "今年廬山下，得子恨不早。", "歲月幸同庚，詩書復同道。", "惟應山南北，雲母夜堪擣。", "獨生有先期，迴崖詎難到。", "丹經不我誑，白髮須一掃。", "看公鬚眉蒼，杖鉞督征討。"]'),
('4fd6a229-94ea-426d-ba07-dfd7d6d25327','次卜掌書落成白鹿佳句','朱熹','宋','宋诗','song-poetry','','[]','重營舊館喜初成，要共群賢聽鹿鳴。',64,'全唐诗/poet.song.148000.json','["重營舊館喜初成，要共群賢聽鹿鳴。", "三爵何妨奠蘋藻，一編詎敢議明誠。", "深源定自閑中得，妙用元從樂處生。", "莫問無窮菴外事，此心聊與此山盟。"]'),
('96b2e9e4-268d-4b89-9b4b-3b041c3416bc','白鹿講會次卜丈韻','朱熹','宋','宋诗','song-poetry','','[]','宮牆蕪沒幾經年，祇有寒煙鎖澗泉。',64,'全唐诗/poet.song.148000.json','["宮牆蕪沒幾經年，祇有寒煙鎖澗泉。", "結屋幸容追舊觀，題名未許續遺編。", "青雲白石聊同趣，霽月光風更別傳。", "珍重箇中無限樂，諸郎莫苦羨騰騫。"]'),
('5f030ca4-dcc8-4f8c-ac42-4ccac5e781da','再用前韻示諸同遊','朱熹','宋','宋诗','song-poetry','','[]','幽卧寒巖不記年，飽看山月聽風泉。',64,'全唐诗/poet.song.148000.json','["幽卧寒巖不記年，飽看山月聽風泉。", "舒憂正得琴三疊，玩意惟憑易一編。", "誤落塵中乖夙尚，却思洞裏付真傳。", "封章倘幸天從欲，便解銅符謝縶騫。"]'),
('65786b95-3704-4b9b-ac8b-56953a7c2886','次韻四十叔父白鹿之作','朱熹','宋','宋诗','song-poetry','','[]','誅茅結屋想前賢，千載遺蹤尚宛然。',64,'全唐诗/poet.song.148000.json','["誅茅結屋想前賢，千載遺蹤尚宛然。", "故作軒窗挹蒼翠，要將絃誦答潺湲。", "諸郎有志須精學，老子無能但欲眠。", "多少箇中名教樂，莫談空諦莫求仙。"]'),
('17c12fe8-1926-4d25-a4a5-77f4be34d85b','送四十叔父','朱熹','宋','宋诗','song-poetry','','[]','吾家從昔號清門，叔父于今道更尊。',64,'全唐诗/poet.song.148000.json','["吾家從昔號清門，叔父于今道更尊。", "客路艱難空自惜，遺經終始向誰論。", "獨尋雲嶠逢孤姪，共愛春江接故園。", "細說刈葵休放手，此來真不爲盤餐。"]'),
('0da01f3b-7ac7-4d8f-b9a3-04eb1bd34273','伏蒙秘閣張丈寵顧下邑并以長篇爲貺降歎之餘牽勉繼韻仰求斤削僭率皇恐','朱熹','宋','宋诗','song-poetry','','[]','向來滅迹東山東，閉門不問烏雌雄。',320,'全唐诗/poet.song.148000.json','["向來滅迹東山東，閉門不問烏雌雄。", "門前有路向塵土，兩足未舉心先慵。", "當時亦有車馬客，此意欲說嗟誰同。", "窮居聊復追仲蔚，篤論何必須劉龔。", "平生故人子張子，相思安得長相從。", "每勞書疏問生死，坐想星宿羅心胸。", "幾年持節漢水上，木牛流馬旌旗紅。", "君王輟饋思頗牧，外庸且訖來朝宗。", "因能過我紫霄下，後乘載得珠簾櫳。", "蒼顔白髮應笑我，曷不飽卧陶窗風。", "開樽鵝池水清激，下馬醮石烟空濛。", "須臾路轉山更好，摩天巨刃排雙峰。", "少看銀河忽倒掛，直欲跳下清泠中。", "南臨匯澤共指點，縹緲貝闕浮珠宮。", "公言平日愛登覽，到此一洗羣山空。", "坐間爲我出奇句，不用遠寄南飛鴻。", "上言雲泉足奇賞，下歎契闊歡相逢。", "紛吾失脚墮世網，乃有此會寧天窮。", "流光過眼驚昨夢，舊約回首羞塵容。", "明朝却上煙艇去，滅沒萬頃追鳬翁。"]'),
('9e29adfc-bb39-4eb1-9fce-7cb43ae85a3e','和張彥輔初到南康之句','朱熹','宋','宋诗','song-poetry','','[]','十年不共賦陽春，正有胸中萬斛塵。',64,'全唐诗/poet.song.148000.json','["十年不共賦陽春，正有胸中萬斛塵。", "失喜清詩還入手，細看佳句轉驚人。", "知公近覺青山好，顧我頻嗟白髮新。", "肯過寒齋共尊酒，向來心事請深陳。"]'),
('34c24f09-b6da-4617-b75b-3dd1f73d52f4','奉同都運直閣張丈哭敬夫張兄張丈有詩敢次元韻悲悼之極情見乎詞伏幸采覽二首  其一','朱熹','宋','宋诗','song-poetry','','[]','秀翁威略憺華戎，遺恨車書久未同。',64,'全唐诗/poet.song.148000.json','["秀翁威略憺華戎，遺恨車書久未同。", "喜有象賢堪嗣事，故知鴻業自無窮。", "蕃宣合奏三年最，風采俄驚一旦空。", "根本平生有深計，遺書不但子囊忠。"]'),
('1b3fa161-7bdc-4abe-9631-9ed980f922a8','奉同都運直閣張丈哭敬夫張兄張丈有詩敢次元韻悲悼之極情見乎詞伏幸采覽二首  其二','朱熹','宋','宋诗','song-poetry','','[]','不應世道即漂淪，何事今年失此人。',64,'全唐诗/poet.song.148000.json','["不應世道即漂淪，何事今年失此人。", "禮樂端能懷益友，琴笙忍遽樂嘉賓。", "亦知遊好曾通譜，却記登臨喚卜隣。", "兩首悲詩數行淚，感傷那復鬭清新。"]'),
('ca5c8322-f5c7-4175-ac1e-16bfa773d8ba','秘閣張丈簡寂之篇韻高難繼別賦五字以謝來貺','朱熹','宋','宋诗','song-poetry','','[]','勞農會稽宅，息駕丹元鄉。',144,'全唐诗/poet.song.148000.json','["勞農會稽宅，息駕丹元鄉。", "丹元不可見，翠壁空雲房。", "是時中春月，暄風發新陽。", "白水注幽壑，綠樹敷崇岡。", "俯聽足怡悅，仰觀共徜徉。", "班坐得瑶草，傾壺出瓊漿。", "長吟遊仙詩，亂以招隠章。", "忽忽林景西，躊躇申慨慷。", "坐上江海客，兀傲鬚眉蒼。", "逸氣邁霄漢，英詞吐琳琅。", "思與泉石勝，韻隨笙鶴翔。", "追遊不敢及，咏歎可能忘。"]'),
('4a14e256-7974-4667-b9e5-c534223ace78','和張彥輔落星寺之作','朱熹','宋','宋诗','song-poetry','','[]','嵌空奇石戰驚濤，樓殿崢嶸勢自高。',64,'全唐诗/poet.song.148000.json','["嵌空奇石戰驚濤，樓殿崢嶸勢自高。", "四面真成開玉鑑，三山應是失金鰲。", "題詩正爾難搜句，舉酒何妨共作豪。", "倚遍欄干更愁絕，歸來白盡鬢邊毛。"]'),
('cc60e62d-2ea0-4b93-8525-f2bc1fafc8f9','和張彥輔白鹿洞之作','朱熹','宋','宋诗','song-poetry','','[]','邃谷新華館，風煙再吐吞。',48,'全唐诗/poet.song.148000.json','["邃谷新華館，風煙再吐吞。", "舊眠聞野鹿，遺恨響驚猿。", "共賞忻同趣，分携愴別魂。", "徘徊空日夕，無策駐行軒。"]'),
('3e847482-c4c6-4d1c-bd50-e7089fdcad8c','次張彥輔西原之作','朱熹','宋','宋诗','song-poetry','','[]','無處堪投跡，空山寄一椽。',48,'全唐诗/poet.song.148000.json','["無處堪投跡，空山寄一椽。", "懸門窺絕壁，繚徑上層巔。", "檻闊吞江浪，窗虛響谷泉。", "丹經閑自讀，不爲學神仙。"]'),
('e03f65e8-4dc6-4f63-a3ec-2b0844e93751','次張彥輔卧龍之作','朱熹','宋','宋诗','song-poetry','','[]','瀑水源何處，高疑雲漢通。',48,'全唐诗/poet.song.148000.json','["瀑水源何處，高疑雲漢通。", "瀉時垂練直，落處古潭空。", "客寄詩能好，龍蟠意自雄。", "知君來峴首，爲我說隆中。"]'),
('3bf374fb-6de3-4069-aa20-5854256532a8','次張彥輔棲賢之作','朱熹','宋','宋诗','song-poetry','','[]','融冶何年事，停杯莫問天。',48,'全唐诗/poet.song.148000.json','["融冶何年事，停杯莫問天。", "祇今從痼疾，疇昔似因緣。", "傾耳真三峽，投文沕九淵。", "蘭亭那得此，猶足致群賢。"]'),
('8a1cfa68-a080-438c-9e5a-e6658ad75e49','和張彥輔雪後棲賢之作','朱熹','宋','宋诗','song-poetry','','[]','夜來春雪遍林丘，却喜風威曉便收。',64,'全唐诗/poet.song.148000.json','["夜來春雪遍林丘，却喜風威曉便收。", "好上籃輿閑縱目，莫將衲被苦蒙頭。", "微官正愧逍遥社，勝日猶堪汗漫遊。", "欲出林關戀瑶草，不妨尊酒更淹留。"]'),
('3b1c26c3-5c01-456e-a7a4-d5458c1a3bca','謝張彥輔留別之作','朱熹','宋','宋诗','song-poetry','','[]','一別屢更歲，思君無已時。',228,'全唐诗/poet.song.148000.json','["一別屢更歲，思君無已時。", "知君亦念我，相望兩嗟咨。", "我病卧田間，君行護疆陲。", "隠顯既殊跡，會合安可期。", "今年定何年，有此一段奇。", "我來五峰陽，君歸九江湄。", "聞君肯來辱，歡喜不自持。", "迎君紫霄峰，舉觴白鵝池。", "强健初共欣，艱棘旋相悲。", "相顧出危涕，薄言首東岐。", "留連十日飲，愴恨八哀詩。", "散懷水石幽，遂忘筋力疲。", "雄篇既鼎來，逸韻方窮追。", "云胡遽告別，牙纛風披披。", "攬祛不得留，酌酒前致辭。", "願君醻此觴，去上白玉墀。", "國論罄忠益，廟謨參設施。", "一請正紀綱，再請誅羌夷。", "及時樹勳業，慰我空山饑。"]'),
('d755650c-5c10-4af6-b26a-70dead30d650','奉答張彥輔戲贈之句','朱熹','宋','宋诗','song-poetry','','[]','已驅送客車，復著登山屐。',48,'全唐诗/poet.song.148000.json','["已驅送客車，復著登山屐。", "未論窺臨快，且脫詩酒厄。", "從今謹出入，保此頤正吉。", "不柰歲寒心，於公有深憶。"]'),
('d0a27d44-268a-4fe6-885c-50e4a407c7eb','奉答張彥輔解嘲','朱熹','宋','宋诗','song-poetry','','[]','康俗遺居萬疊山，高垂鐵鎖詎容攀。',32,'全唐诗/poet.song.148000.json','["康俗遺居萬疊山，高垂鐵鎖詎容攀。", "青鞋布襪非公事，古木寒泉要我閑。"]'),
('58e3d4ab-6831-4a84-a06a-15991eace500','伏蒙某官寵示和陶見寄舊作伏讀歎仰又感知待期許之意蓋非一日率易次韻少見謝臆伏惟矜憐有以教之','朱熹','宋','宋诗','song-poetry','','[]','吾公抱經濟，軒冕非所欣。',96,'全唐诗/poet.song.148000.json','["吾公抱經濟，軒冕非所欣。", "向來清禁闥，本自山林人。", "浩歌歸去來，神交邈何因。", "一朝脫冠去，妙境聊同臻。", "謂予雖後來，臭味亦有聞。", "賡詞久見屬，重以告語勤。", "荒寒想高風，令人思無鄰。", "甘棠矧在此，躑躅晴湖濱。"]'),
('3dd115ad-68c4-4ec4-a706-0fab052e2e12','贈于盛二生','朱熹','宋','宋诗','song-poetry','','[]','昔日豐城劍，寒光射斗牛。',48,'全唐诗/poet.song.148000.json','["昔日豐城劍，寒光射斗牛。", "江山餘秀傑，人物尚風流。", "二妙今安匹，孤帆各倦游。", "還家問師友，折節慕前修。"]'),
('4b0a0712-e0e4-4506-964d-34ca85988b11','秋日告病齋居奉懷黄子厚劉平父及山間諸兄友','朱熹','宋','宋诗','song-poetry','','[]','出山今幾時，忽忽歲再秋。',180,'全唐诗/poet.song.148000.json','["出山今幾時，忽忽歲再秋。", "江湖豈不永，我興終悠悠。", "况復逢旱魃，農畝無餘收。", "赤子亦何辜，黄屋勞深憂。", "而我忝朝寄，政荒積𠎝尤。", "懷痾卧空閣，惻愴增綢繆。", "東南望故山，上有玄煙浮。", "平生采芝侶，寂寞今焉儔。", "朝游雲峰巔，夕宿寒巖幽。", "爲我泛瑶瑟，泠然發清謳。", "裂牋寄晨風，問我君何求。", "洪濤捩君柁，狹硤摧君輈。", "君還苦不早，無乃非良謀。", "再拜謝故人，低徊更包羞。", "桂華幸未歇，去矣從君游。"]'),
('f8c8b1aa-06de-4aa3-8b48-bbe0de2e6265','夜坐有感','朱熹','宋','宋诗','song-poetry','','[]','秋堂天氣清，坐久寒露滴。',48,'全唐诗/poet.song.148000.json','["秋堂天氣清，坐久寒露滴。", "幽獨不自憐，茲心竟誰識。", "讀書久已懶，理郡更無術。", "獨有憂世心，寒燈共蕭瑟。"]'),
('f6f9ec2c-5243-4b37-91f2-d01b78a5defc','讀諸友遊山詩卷不容盡和和首尾兩篇  其一','朱熹','宋','宋诗','song-poetry','','[]','去年尋得李家山，考卜真成屋數間。',64,'全唐诗/poet.song.148000.json','["去年尋得李家山，考卜真成屋數間。", "要與青衿時散帙，閑臨碧澗共觀瀾。", "詩書本說人間事，勳業休看鏡裏顔。", "誰識寥寥千古意，新詩題罷蘚痕斑。"]'),
('15bcb3fe-ff02-4b15-8a1b-ba19a8a8c136','讀諸友遊山詩卷不容盡和和首尾兩篇  其二','朱熹','宋','宋诗','song-poetry','','[]','向來結友尋名山，下窮絕壑高危顛。',64,'全唐诗/poet.song.148000.json','["向來結友尋名山，下窮絕壑高危顛。", "胡爲一旦墮塵網，五老在望心茫然。", "青牛底處有行迹，白鹿幾時同正員。", "清遊带雨想幽絕，妙處只恐詩中傳。"]'),
('9ce4e638-36ee-49c2-b65c-0bb0523fd24b','戲贈勝私老友','朱熹','宋','宋诗','song-poetry','','[]','槐花黄盡不關渠，老向功名意自踈。',32,'全唐诗/poet.song.148000.json','["槐花黄盡不關渠，老向功名意自踈。", "乞得山田三百畝，青燈徹夜課農書。"]'),
('b83442ab-c665-4b3f-b527-95cea98fb129','代勝私下一轉語','朱熹','宋','宋诗','song-poetry','','[]','碓下泉鳴溜决渠，屋頭桑樹綠扶踈。',32,'全唐诗/poet.song.148000.json','["碓下泉鳴溜决渠，屋頭桑樹綠扶踈。", "朱虛正自知田事，馬服何妨讀父書。"]'),
('cfc35bc6-9b60-4aab-b94b-a21e48854223','和戴主簿韻','朱熹','宋','宋诗','song-poetry','','[]','平生本自好樓居，况接高人永晝餘。',64,'全唐诗/poet.song.148000.json','["平生本自好樓居，况接高人永晝餘。", "共喜江山入尊俎，從教幕府省文書。", "感君肯出新詩句，恨我終思舊草廬。", "擬借韋編訂龍馬，免推納甲話蟾蜍。"]'),
('2bd0d6f8-e642-4540-b1ed-f40da3ae1d00','次沈侍郎游楞伽李氏山房韻  其一','朱熹','宋','宋诗','song-poetry','','[]','喜陪後騎陟崔嵬，竹裏泉鳴古寺開。',32,'全唐诗/poet.song.148000.json','["喜陪後騎陟崔嵬，竹裏泉鳴古寺開。", "吟罷蘇仙頭白句，天風更送好詩來。"]'),
('e722505f-0364-436a-925d-c59ab4dd49cd','次沈侍郎游楞伽李氏山房韻  其二','朱熹','宋','宋诗','song-poetry','','[]','天聰已許一言悟，年少懸知萬卷開。',32,'全唐诗/poet.song.148000.json','["天聰已許一言悟，年少懸知萬卷開。", "珍重當時讀書處，低回空有後人來。"]'),
('ccb6ed9a-f486-4176-999c-fb30622cc9e1','奉同尤延之提舉廬山雜詠十四篇 白鹿洞書院','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔人讀書地，町疃白鹿場。',96,'全唐诗/poet.song.148000.json','["昔人讀書地，町疃白鹿場。", "世道有升降，茲焉更表章。", "矧今中興年，治具一以張。", "絃歌獨不嗣，山水無輝光。", "荒榛適剪除，聖謨已汪洋。", "亦有皇華使，肯來登此堂。", "問俗良懇惻，懷賢增慨慷。", "雅歌有餘韻，絕學何能忘。"]'),
('0a3c5a8d-e137-49ef-a73d-e6dec5062b88','奉同尤延之提舉廬山雜詠十四篇 折桂院黄雲觀','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','城中東北望，五老何蒼蒼。',96,'全唐诗/poet.song.148000.json','["城中東北望，五老何蒼蒼。", "下有前朝寺，一原頗深藏。", "門前林澗幽，屋後雲木荒。", "閑窗亦明潔，著此瑞錦張。", "更能理枯筇，步上林北岡。", "仰視天宇闊，俯瞰江流長。", "受書彼何人，姓字不足詳。", "竹帛有遺臭，桂樹徒芬芳。"]'),
('a5a62689-7a5a-4045-ae00-398d6f011739','奉同尤延之提舉廬山雜詠十四篇 楞伽院李氏山房','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','躡石循急磵，穿林度重岡。',96,'全唐诗/poet.song.148000.json','["躡石循急磵，穿林度重岡。", "俛入幽谷邃，仰見奇峰蒼。", "李公英妙年，讀書此雲房。", "一去上臺閣，致身何慨慷。", "蘇公記藏書，文字有耿光。", "餘事亦騷雅，戲墨仍風霜。", "兩公不歸來，歲月忽已荒。", "何用建遺烈，寒泉薦孤芳。"]'),
('62b7e1d2-0ebc-48dc-86c8-f5d703a7f5b7','奉同尤延之提舉廬山雜詠十四篇 棲賢院三峽橋','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','兩岸蒼壁對，直下成斗絕。',96,'全唐诗/poet.song.148000.json','["兩岸蒼壁對，直下成斗絕。", "一水從中來，湧潏知幾折。", "石梁據其會，迎望遠明滅。", "倏至走長蛟，捷來翻素雪。", "聲雄萬霹靂，勢倒千嵽嵲。", "足掉不自持，魂驚詎堪說。", "老仙有妙句，千古擅奇崛。", "尚想化鶴來，乘流弄明月。"]'),
('abce5ba8-114e-4b7d-9996-e8f93aa7d0d9','奉同尤延之提舉廬山雜詠十四篇 西澗清凈退菴','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','凌兢度三峽，窈窕復一原。',96,'全唐诗/poet.song.148000.json','["凌兢度三峽，窈窕復一原。", "絕壁擁蒼翠，奔流逝潺湲。", "聞昔避世人，寄此茅三間。", "壯節未云遠，高風杳難攀。", "深尋得遺墟，縛屋臨清灣。", "坐睨寒木杪，飛泉閟雲關。", "茲游非昔游，累解身復閑。", "保此清凈退，當歌不能諼。"]'),
('de210067-6473-4cb6-97f4-ee775badb875','奉同尤延之提舉廬山雜詠十四篇 卧龍菴武侯祠','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','空山龍卧處，蒼峭神所鑿。',96,'全唐诗/poet.song.148000.json','["空山龍卧處，蒼峭神所鑿。", "下有寒潭幽，上有明河落。", "我來愛佳名，小築寄幽壑。", "永念千載人，丹心豈今昨。", "英姿儼繪事，凜若九原作。", "寒藻薦芳馨，飛泉奉明酌。", "公來識此意，顧步慘不樂。", "抱膝一長吟，神交付冥漠。"]'),
('522a427a-770f-4a51-b038-c57fc467e661','奉同尤延之提舉廬山雜詠十四篇 萬杉寺','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','休沐聊命駕，駕言何所之。',96,'全唐诗/poet.song.148000.json','["休沐聊命駕，駕言何所之。", "行尋慶雲寺，想像昭陵時。", "門前杉徑深，屋後杉色奇。", "空山歲年晚，鬰鬰凌寒姿。", "當年雨露恩，千載有餘滋。", "匠石不敢睨，孤標儼相持。", "更啟石室藏，仰瞻天像垂。", "願以清凈化，永爲太平基。"]'),
('dfe58459-b5dc-41cb-8969-3d0b26e013ca','奉同尤延之提舉廬山雜詠十四篇 開先潄玉亭','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','奇哉康山陽，雙劍屹對起。',96,'全唐诗/poet.song.148000.json','["奇哉康山陽，雙劍屹對起。", "上有橫飛雲，下有瀑布水。", "崩騰復璀璨，佳麗更雄偉。", "勢從三梁外，影落明湖裏。", "平生兩仙句，詠嘆深仰止。", "三年落星灣，悵望眼空瞇。", "今朝隨杖屨，得此弄清泚。", "更誦玉虹篇，塵襟諒昭洗。"]'),
('1721fbde-4994-4e32-8d3a-4e6e169b4a5d','奉同尤延之提舉廬山雜詠十四篇 簡寂觀','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高士昔遺世，築室蒼崖陰。',96,'全唐诗/poet.song.148000.json','["高士昔遺世，築室蒼崖陰。", "朝真石壇峻，煉藥古井深。", "結交五柳翁，屢賞無絃琴。", "相携白蓮渚，一笑傾夙心。", "晚歲更市朝，故山鎖雲岑。", "柴車竟不返，鸞鶴空遺音。", "我來千載餘，舊事不可尋。", "四顧但絕壁，苦竹寒蕭椮。"]'),
('b1a38423-17eb-4c73-9edf-8539872c5ae3','奉同尤延之提舉廬山雜詠十四篇 歸宗寺','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','金輪紫霄上，寶界鸞溪邊。',96,'全唐诗/poet.song.148000.json','["金輪紫霄上，寶界鸞溪邊。", "往昔王內史，願香有餘煙。", "千年今一歸，景物還依然。", "澗水既蕩潏，山花亦清妍。", "不辭原隰勞，樂此賓從賢。", "訪古共紆鬰，勞農獨勤拳。", "憐我乖勝踐，裂牋寄真詮。", "逃禪公勿遽，且畢區中緣。"]'),
('30f4499b-b223-4075-9eb4-e2cd0c8e6c34','奉同尤延之提舉廬山雜詠十四篇 陶公醉石歸去來館','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','予生千載後，尚友千載前。',96,'全唐诗/poet.song.148000.json','["予生千載後，尚友千載前。", "每尋高士傳，獨嘆淵明賢。", "及此逢醉石，謂言公所眠。", "况復巖壑古，縹緲藏風煙。", "仰看喬木陰，俯聽橫飛泉。", "景物自清絕，優游可忘年。", "結廬倚蒼峭，舉觴酹潺湲。", "臨風一長嘯，亂以歸來篇。"]'),
('97b2f50d-d784-46f1-896e-37c4ce3b0a57','奉同尤延之提舉廬山雜詠十四篇 溫湯','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','連山西南來，中斷還崛起。',96,'全唐诗/poet.song.148000.json','["連山西南來，中斷還崛起。", "干霄幾千仞，據地三百里。", "飛峰上靈秀，衆壑下清美。", "逮茲勢力窮，猶能出奇偉。", "誰燃丹黄燄，爨此玉池水。", "客來爭解带，萬劫付一洗。", "當年謝康樂，絃絕今已矣。", "水碧復流溫，相思五湖裏。"]'),
('62845d19-c6a1-4ce3-8a61-17b8b92cff67','奉同尤延之提舉廬山雜詠十四篇 康王谷水簾','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','循山西北騖，崎嶇幾經丘。',96,'全唐诗/poet.song.148000.json','["循山西北騖，崎嶇幾經丘。", "前行荒蹊斷，豁見清溪流。", "一涉臺殿古，再涉川原幽。", "縈紆復屢渡，乃得寒巖陬。", "飛泉天上來，一落散不收。", "披崖日璀璨，噴壑風颼飀。", "追薪爨絕品，瀹茗澆窮愁。", "敬酹古陸子，何年復來游。"]'),
('04c336f3-405b-4840-99a4-4100de13c9d8','奉同尤延之提舉廬山雜詠十四篇 落星寺','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','浩浩長江水，東逝無停波。',96,'全唐诗/poet.song.148000.json','["浩浩長江水，東逝無停波。", "及此一回薄，湖平烟浪多。", "孤嶼屹中川，層臺起周阿。", "晨望愛明滅，夕遊驚蕩磨。", "極目青冥茫，回瞻碧嵯峨。", "不復車馬迹，唯聞榜人歌。", "我願辭世紛，茲焉老漁簑。", "會有滄浪子，鳴舷夜相過。"]'),
('612a5110-8bbc-4ed3-8a5c-94a8711cccf3','閏月十一日月中坐彭蠡門喚船與諸人共載汎湖至隄首回棹入西灣還分韻賦詩約來晚復集詩不至者浮以大白','朱熹','宋','宋诗','song-poetry','','[]','解組無多日，歸哉喜欲狂。',48,'全唐诗/poet.song.148000.json','["解組無多日，歸哉喜欲狂。", "臨風成邂逅，載月下滄浪。", "酌酒傳清影，鳴橈擊素光。", "它年隔千里，此夜莫相忘。"]'),
('8e410526-d2bc-49f9-9ea4-0db3da2fb22d','和林擇之黄雲之句兼簡同遊諸兄','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','登覽日云晏，歸車眇重岡。',72,'全唐诗/poet.song.148000.json','["登覽日云晏，歸車眇重岡。", "天風振余旟，夕露沾我裳。", "數子情未厭，春山杳茫茫。", "還瞻長江白，迥眺飛雲黄。", "當念塵中友，心期邈相望。", "無爲跨鴻鵠，决起凌青蒼。"]'),
('f850c251-72a4-45f4-b055-693e366b3387','和彭蠡月夜汎舟落星湖','朱熹','宋','宋诗','song-poetry','','[]','長占烟波弄明月，此心久矣從誰說。',64,'全唐诗/poet.song.148000.json','["長占烟波弄明月，此心久矣從誰說。", "只今一舸漾中流，上下天光兩奇絕。", "回頭忽見西郭門，尚喜蘇仙有遺烈。", "問予何事却回船，塵土涴君頭上雪。"]'),
('9409ffe6-16d7-4a01-9e95-4db37c92b5d5','熹罷官觀康王谷水簾夜飲山月軒分韻得主字奉別送行諸君','朱熹','宋','宋诗','song-poetry','','[]','嗟余老不才，記憶謝明主。',72,'全唐诗/poet.song.148000.json','["嗟余老不才，記憶謝明主。", "畀茲山水郡，北邇通玄府。", "一官再溫凉，十日九塵土。", "迨茲解章紱，絕境方快覩。", "殷勤故人厚，追送崖寺古。", "把酒聽鳴泉，相看淚如雨。"]'),
('c5e7dd05-5928-4631-81ef-1217a3929355','游天池','朱熹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三年落星渚，北望天池山。',108,'全唐诗/poet.song.148000.json','["三年落星渚，北望天池山。", "臨風幾浩嘆，欲往無飛翰。", "今朝復何朝，陟此青雲端。", "高尋已奇絕，俯瞰何其寬。", "西窮濂溪原，東盡湓城關。", "渺然滄波外，淮山碧連環。", "我意殊未極，更思出塵寰。", "何當駕輕鴻，八表須臾間。", "視此長江水，滔滔儻西還。"]'),
('f74c065d-cf75-472e-80a9-7c227fd379a6','觀野燈','朱熹','宋','宋诗','song-poetry','','[]','飛螢腐草尋常事，作底茲山獨耀芒。',32,'全唐诗/poet.song.148000.json','["飛螢腐草尋常事，作底茲山獨耀芒。", "須信地靈資物化，金膏隨處發明光。"]'),
('75a43349-0b6d-45ae-a76f-7be98a358a07','山北紀行十二章章八句  其一','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','祗役廬山陽，矯首廬山陰。',48,'全唐诗/poet.song.148000.json','["祗役廬山陽，矯首廬山陰。", "雲峰不可覿，碧澗何由尋。", "昨朝解印章，結友同窺臨。", "盡彼巖壑勝，滿茲仁知心。"]'),
('71d7f08c-b2e5-480b-b6f2-242b6c2f26e7','山北紀行十二章章八句  其二','朱熹','宋','宋诗','song-poetry','','[]','窺臨事若何，請從圓通說。',48,'全唐诗/poet.song.148000.json','["窺臨事若何，請從圓通說。", "逶迤山門路，悄蒨蹤篁列。", "溪仍侯家名，屋是孱王設。", "何救黍離歌，喟焉傷覆轍。"]'),
('fc654df5-a357-4af3-bab6-444e72bd3059','山北紀行十二章章八句  其三','朱熹','宋','宋诗','song-poetry','','[]','行逢石門雨，解驂寒澗東。',48,'全唐诗/poet.song.148000.json','["行逢石門雨，解驂寒澗東。", "朝隮錦繡谷，俯仰春冥濛。", "懸泉忽淙琤，雜樹紛青紅。", "屢憩小亭古，幽探思無窮。"]'),
('039e90a2-eb8d-4a7c-9212-3ab09ae9ba64','山北紀行十二章章八句  其四','朱熹','宋','宋诗','song-poetry','','[]','竦身長林端，策足層崖表。',48,'全唐诗/poet.song.148000.json','["竦身長林端，策足層崖表。", "仰瞻空界闊，俯歎塵寰小。", "天池西嵌崟，佛手東窈窕。", "杖屨往復來，憑軒瞰歸鳥。"]'),
('ff6727cd-f84e-4cd5-a60d-b9acd58e8da8','山北紀行十二章章八句  其五','朱熹','宋','宋诗','song-poetry','','[]','斯須暮雲合，白日無餘暉。',48,'全唐诗/poet.song.148000.json','["斯須暮雲合，白日無餘暉。", "金波從地湧，寶燄穿林飛。", "僧言自雄誇，俗駭無因依。", "安知本地靈，發見隨天機。"]'),
('06679759-8e41-4dc2-9d23-4f9f532a314b','山北紀行十二章章八句  其六','朱熹','宋','宋诗','song-poetry','','[]','深尋兩林間，清波貫華屋。',48,'全唐诗/poet.song.148000.json','["深尋兩林間，清波貫華屋。", "蓮社有遺蹤，草堂非舊築。", "脩廊餘故刻，好醜雜珉玉。", "亦復記經行，深慙後人讀。"]'),
('4adc169d-ce12-4496-b5b4-809f3eda1848','山北紀行十二章章八句  其七','朱熹','宋','宋诗','song-poetry','','[]','行軒復東騖，祠城當晚遊。',48,'全唐诗/poet.song.148000.json','["行軒復東騖，祠城當晚遊。", "胡然冠蓋集，不盡心期幽。", "夜厭百谷喧，旦失千峰稠。", "出門有遺恨，回首空綢繆。"]'),
('0eb2f560-abf8-49f0-bd85-9766d5942626','山北紀行十二章章八句  其八','朱熹','宋','宋诗','song-poetry','','[]','山水誠乃奇，云誰究終始。',48,'全唐诗/poet.song.148000.json','["山水誠乃奇，云誰究終始。", "曇遠亦何人，神君豈其鬼。", "東西妄采獲，誣諂共恢詭。", "百世踵謬訛，彝倫日頹圯。"]'),
('c17c32db-1713-4598-b2ba-88073f75ec69','山北紀行十二章章八句  其九','朱熹','宋','宋诗','song-poetry','','[]','以茲遊覽富，翻令懷抱傷。',48,'全唐诗/poet.song.148000.json','["以茲遊覽富，翻令懷抱傷。", "誰哉可告語，舉俗昏且狂。", "乾坤有真心，日月垂休光。", "茫茫宇宙內，此柄孰主張。"]'),
('40ea9f28-0a1e-4d87-bf03-e85ac27c2fb0','山北紀行十二章章八句  其一○','朱熹','宋','宋诗','song-poetry','','[]','北度石塘橋，西訪濂溪宅。',48,'全唐诗/poet.song.148000.json','["北度石塘橋，西訪濂溪宅。", "喬木無遺株，虛堂唯四壁。", "竦瞻德容睟，跪薦寒流碧。", "幸矣有斯人，渾淪再開闢。"]'),
('2c044efc-10c9-4c42-ad2b-8ec40af4811f','山北紀行十二章章八句  其一一','朱熹','宋','宋诗','song-poetry','','[]','平生勞仰止，今日登此堂。',48,'全唐诗/poet.song.148000.json','["平生勞仰止，今日登此堂。", "願以圖象意，質之巾几傍。", "先生寂無言，賤子涕泗滂。", "神聽儻不遺，惠我思無疆。"]'),
('a79fa67c-be6f-4c19-9065-a06d5e2c475e','山北紀行十二章章八句  其一二','朱熹','宋','宋诗','song-poetry','','[]','明晨江磯寺，尊酒聊對設。',48,'全唐诗/poet.song.148000.json','["明晨江磯寺，尊酒聊對設。", "孰是十日遊，遽成千里別。", "英僚樹嘉政，素友厲孤節。", "努力莫相忘，清宵共明月。"]'),
('3581d0a1-3ea3-402b-8bd7-5add2906bec5','買船至演平拜建康劉公墓下遂入城假館梅山堂感涕有作','朱熹','宋','宋诗','song-poetry','','[]','維舟新曆口，步上秣陵阡。',144,'全唐诗/poet.song.148000.json','["維舟新曆口，步上秣陵阡。", "高丘忽嵯峨，宿草迷荒烟。", "拜起淚再滴，哀哉不能言。", "驅車且復東，借此虛堂眠。", "念昔堂中人，經營幾何年。", "一旦舍之去，千秋不言還。", "露井益清渫，風林更修鮮。", "思公獨不見，涕下如奔川。", "感慨西州門，愴悢山陽篇。", "晤嘆日隠樹，悲歌月當軒。", "堂堂忠孝心，終古諒弗諼。", "尚與吳門子，歸來故山巔。"]'),
('f211f365-f099-4f94-b089-6123525a22b0','晚雨凉甚偶得小詩請問遊山之日并請劉平父作主人二首  其一','朱熹','宋','宋诗','song-poetry','','[]','幾年不踏仙洲路，夢入青藤古木間。',32,'全唐诗/poet.song.148000.json','["幾年不踏仙洲路，夢入青藤古木間。", "好趁新秋一番雨，晝寒亭下弄潺湲。"]'),
('d32336fc-2bce-41b2-a426-bef1e5819f9d','晚雨凉甚偶得小詩請問遊山之日并請劉平父作主人二首  其二','朱熹','宋','宋诗','song-poetry','','[]','廬阜歸來祇短筇，解包茶茗粗能供。',32,'全唐诗/poet.song.148000.json','["廬阜歸來祇短筇，解包茶茗粗能供。", "若須載酒邀賓客，付與屏山七老翁。"]'),
('18e424b6-374f-47e7-8e3c-bb8f74d5bb10','宿密菴分韻賦詩得衣字','朱熹','宋','宋诗','song-poetry','','[]','不到仙洲歲月移，携壺特地款巖扉。',64,'全唐诗/poet.song.148000.json','["不到仙洲歲月移，携壺特地款巖扉。", "已驚素雪清人骨，更喜蒼烟染客衣。", "新賞不妨頻徙倚，舊題何事獨噓嚱。", "明朝驛騎黄塵裏，莫待迷塗始賦歸。"]'),
('677003f6-3514-4ce2-979f-435ff419ade7','讀子厚步月詩時方聞呂伯恭訃後數日賦此','朱熹','宋','宋诗','song-poetry','','[]','晚步曲池上，西風吹我裳。',72,'全唐诗/poet.song.148000.json','["晚步曲池上，西風吹我裳。", "仰觀天宇闊，愛此明月光。", "念我素心人，眇焉天一方。", "沒者永乖隔，存者爲參商。", "飄零百歲期，寂寞幽鬢霜。", "還坐三太息，高林鬰蒼蒼。"]'),
('c0797a39-9c4f-44bc-8224-07bbcbf8d41e','次子厚秋懷韻','朱熹','宋','宋诗','song-poetry','','[]','秋風何方來，爲我滌殘暑。',108,'全唐诗/poet.song.148000.json','["秋風何方來，爲我滌殘暑。", "庭梧亦何與，索索終夜雨。", "冥思感物變，念此離索苦。", "浩蕩信莫量，幽紛那得睹。", "丁年舍我去，憔悴故其所。", "廓落濟時心，頹然復安取。", "永懷平生友，夢想見眉宇。", "今晨枉秀句，爛若朝霞舉。", "去去同采芝，高軒坐凝佇。"]'),
('fe7d4858-1781-40a0-be65-e0900f4528f8','黎嶺西南水石佳處不減廬阜戲呈子厚','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','谷深石瘦水潺潺，便是楞伽折桂間。',32,'全唐诗/poet.song.148000.json','["谷深石瘦水潺潺，便是楞伽折桂間。", "珍重下邳圯上客，一年幾度到廬山。"]'),
('11fd8f14-7f9a-43a8-b6b9-4ef187f6b7b5','讀子厚詩卷用其卒章晨起之韻作詩寄之','朱熹','宋','宋诗','song-poetry','','[]','晝永倦殘暑，宵分喜新凉。',84,'全唐诗/poet.song.148000.json','["晝永倦殘暑，宵分喜新凉。", "天雞一振翼，爛爛曉月光。", "病榻感虛徐，中庭起翱翔。", "懷哉穀城子，物外久不忙。", "掩抑琴調希，激烈歌聲長。", "契闊恨清賞，佳期未渠央。", "緘詞託歸鳥，側佇何能忘。"]'),
('7d786348-d525-4675-8380-bedfba23592e','登廬峰二首  其一','朱熹','宋','宋诗','song-poetry','','[]','循磵躋危磴，披雲得勝遊。',48,'全唐诗/poet.song.148000.json','["循磵躋危磴，披雲得勝遊。", "蓬茅增舊葺，竹樹喜新稠。", "夢想三秋別，徘徊十日留。", "餘年端可料，此地欲長休。"]'),
('12521a2b-5d68-4384-842d-8d4133e58557','登廬峰二首  其二','朱熹','宋','宋诗','song-poetry','','[]','佳友紛來集，欣然會宿心。',48,'全唐诗/poet.song.148000.json','["佳友紛來集，欣然會宿心。", "風泉陪徙倚，雲月共窺臨。", "雅唱情俱勝，微言思獨深。", "茲遊非逸豫，邂逅得良箴。"]'),
('d9c84219-10a4-44d3-b7c3-04b82e8a77a9','蘆峰次韻','朱熹','宋','宋诗','song-poetry','','[]','澗水流千仞，巖姿起萬般。',48,'全唐诗/poet.song.148000.json','["澗水流千仞，巖姿起萬般。", "扶藜雖有興，駐屐諒難安。", "好客能同趣，羣峰肯縱觀。", "蒼茫却無際，誰與話愁端。"]'),
('bf9c72b9-5ceb-4b5c-bde6-7ebce3f7653c','次瑞泉詩韻','朱熹','宋','宋诗','song-poetry','','[]','興懷來賞趣，對景却忘言。',48,'全唐诗/poet.song.148000.json','["興懷來賞趣，對景却忘言。", "偶與同遊客，行逢幽澗原。", "淺泓排積腐，暗竇溢流渾。", "終待寒泉食，無憂水鏡昏。"]'),
('825f5730-7adc-4b34-8f72-ecf3aa29dd61','五禽言和王仲衡尚書  其一','朱熹','宋','宋诗','song-poetry','','[]','提胡蘆，沽美酒，春風浩蕩吹花柳。',48,'全唐诗/poet.song.148000.json','["提胡蘆，沽美酒，春風浩蕩吹花柳。", "不用沙頭雙玉瓶，鳥歌蝶舞爲君壽。", "只今□醉是君恩，昨日之愁愁殺人。"]'),
('f2391634-ae6f-461f-a4bf-8c68627586bf','五禽言和王仲衡尚書  其二','朱熹','宋','宋诗','song-poetry','','[]','不如歸去，孤城越絕三春暮。',45,'全唐诗/poet.song.148000.json','["不如歸去，孤城越絕三春暮。", "故山只在白雲間，望極雲深不知處。", "不如歸去不如歸，千仞岡頭一振衣。"]'),
('96862e32-5b3e-43dc-842b-cd0b91b3921f','五禽言和王仲衡尚書  其三','朱熹','宋','宋诗','song-poetry','','[]','泥滑滑，泥滑滑，秦望雲荒鏡湖闊。',48,'全唐诗/poet.song.148000.json','["泥滑滑，泥滑滑，秦望雲荒鏡湖闊。", "綠秧刺水水拍堤，牙旗畫舸凌風發。", "使君行樂三江頭，泥滑水深君莫憂。"]'),
('2b665541-a281-41bc-981d-d380235856f3','五禽言和王仲衡尚書  其四','朱熹','宋','宋诗','song-poetry','','[]','脫袴，脫袴，桑葉陰陰牆下路。',46,'全唐诗/poet.song.148000.json','["脫袴，脫袴，桑葉陰陰牆下路。", "回頭忽憶舍中妻，去年已逐它人去。", "舊袴脫了却不辭，新袴知教阿誰做。"]'),
('b1e4dd8d-98ab-4bdb-82de-f26e55041d1a','五禽言和王仲衡尚書  其五','朱熹','宋','宋诗','song-poetry','','[]','麥熟吟，去年種麥有德音。',44,'全唐诗/poet.song.148000.json','["麥熟吟，去年種麥有德音。", "祇今種熟誰快活，種者已卧官牆陰。", "仁公有政惠存歿，肯使催租更隳突。"]'),
('187a535d-1060-4918-b020-9b70169b30cb','酬黄子厚見訪歸途惠詩韻','朱熹','宋','宋诗','song-poetry','','[]','櫪驥倦千里，籠鶴思九臯。',84,'全唐诗/poet.song.148000.json','["櫪驥倦千里，籠鶴思九臯。", "念昔田舍日，不知山林高。", "一朝逢世紛，故丘得潜逃。", "平生棲遁志，茲焉始堅牢。", "故人穀城翁，高情北窗陶。", "亦復喜我歸，巾車款林巢。", "申旦更離闊，中情重忉忉。"]'),
('ac0e61ee-4d70-4c8e-acd2-ed3743bd595a','游密菴分韻賦詩得清字','朱熹','宋','宋诗','song-poetry','','[]','誤落塵中歲序驚，歸來猶幸此身輕。',64,'全唐诗/poet.song.148000.json','["誤落塵中歲序驚，歸來猶幸此身輕。", "便將舊友尋山去，更喜新詩取意成。", "暖翠乍看渾欲滴，寒流重聽不勝清。", "箇中有趣無人會，琴罷尊空月四更。"]'),
('17f5c4ee-85f6-4abc-b15b-c58e0aa8f836','游密菴得空字','朱熹','宋','宋诗','song-poetry','','[]','欲覓仙洲路，須乘萬里風。',48,'全唐诗/poet.song.148000.json','["欲覓仙洲路，須乘萬里風。", "飲泉雲出岫，卧嶺月流空。", "永夜渾無寐，悲歌莫與同。", "起來殘樹影，清絕小樓東。"]'),
('5583c99e-1662-491c-a801-4b5c52ce4c12','昨爲許進之書胎仙字因以名其室或疑欠舞字者故作此以解之','朱熹','宋','宋诗','song-poetry','','[]','寒山寒月冷颼颼，隻影孤桐萬里遊。',64,'全唐诗/poet.song.148000.json','["寒山寒月冷颼颼，隻影孤桐萬里遊。", "帝樂夢回三疊遠，胎仙舞罷一簾秋。", "未愁悄寂無人會，只恐蹁躚不自休。", "却笑蕊珠何處所，兩忘蝴蝶與莊周。"]'),
('f9f9fd10-6fcf-4fb1-b502-7e91a67bd95a','正月五日欲用斜川故事結客載酒過伯休新居風雨不果二月五日始克踐約坐間以陶公卒章二十字分韻熹得中字賦呈諸同遊者','朱熹','宋','宋诗','song-poetry','','[]','玄景彫暮節，青陽變暄風。',192,'全唐诗/poet.song.148000.json','["玄景彫暮節，青陽變暄風。", "忽尋斜川句，感此勝日逢。", "駕言當出遊，一寫浩蕩胸。", "雲物疑異候，凄迷久連空。", "今朝復何朝，頓覺芳景融。", "疇曩庶復踐，隣曲歡來同。", "伊雅一籃輿，連翩數枝筇。", "綠野生遠思，清川照衰容。", "遥瞻西山足，突兀彌畝宮。", "庭宇豁清曠，林園鬰青葱。", "於焉一逍遥，芳樽間鳴桐。", "既爵日樹隠，班荆汀草豐。", "纖鱗動微波，新荑冠幽叢。", "惆悵景易晏，徘徊思無窮。", "願書今日懷，遠寄柴桑翁。", "仰止固窮節，愧茲百年中。"]'),
('7efa5081-feb5-42c5-bf43-09fbc4c5556b','次呂季克東堂九詠 野塘小隠','朱熹','宋','宋诗','song-poetry','','[]','傳得希夷九卦圖，歸來不復夢榮途。',32,'全唐诗/poet.song.148000.json','["傳得希夷九卦圖，歸來不復夢榮途。", "野塘竟日無人到，讀盡床頭種樹書。"]'),
('266f330b-7cf3-43d2-9181-3bb47ce4ef9f','次呂季克東堂九詠 敬義堂','朱熹','宋','宋诗','song-poetry','','[]','高臺巨榜意何如，住此知非小丈夫。',32,'全唐诗/poet.song.148000.json','["高臺巨榜意何如，住此知非小丈夫。", "浩氣擴充無內外，肯誇心月夜同孤。"]'),
('a400ba88-a224-4c24-9f19-00164c74d0ef','次呂季克東堂九詠 方拙寮','朱熹','宋','宋诗','song-poetry','','[]','一室歸來萬事新，窗間橫竹掛朝紳。',32,'全唐诗/poet.song.148000.json','["一室歸來萬事新，窗間橫竹掛朝紳。", "九流未讓圜機士，四海寧慙巧宦人。"]'),
('0877b241-f11a-4a7c-8559-9242f498f0c1','次呂季克東堂九詠 吟哦室','朱熹','宋','宋诗','song-poetry','','[]','蒲團竹几睡瞢騰，客問君今幾折肱。',32,'全唐诗/poet.song.148000.json','["蒲團竹几睡瞢騰，客問君今幾折肱。", "身世兩忘無可答，起尋詩句遶階行。"]'),
('fbc2cf43-167f-4490-96c4-1b20eb82408d','次呂季克東堂九詠 愛蓮','朱熹','宋','宋诗','song-poetry','','[]','聞道移根玉井旁，開花十丈是尋常。',32,'全唐诗/poet.song.148000.json','["聞道移根玉井旁，開花十丈是尋常。", "月明露冷無人見，獨爲先生引興長。"]'),
('f6672ee4-b0d5-49e1-a6cc-83ad757464b6','次呂季克東堂九詠 月臺','朱熹','宋','宋诗','song-poetry','','[]','臺上無人伴苦吟，歸鴉過盡日西沉。',32,'全唐诗/poet.song.148000.json','["臺上無人伴苦吟，歸鴉過盡日西沉。", "須臾玉匣開塵鏡，却有孤光共此心。"]'),
('e7d594c5-f249-4926-a35a-e6a13f918d53','次呂季克東堂九詠 菜畦','朱熹','宋','宋诗','song-poetry','','[]','雨餘菜甲翠光勻，杞菊成畦亦自春。',32,'全唐诗/poet.song.148000.json','["雨餘菜甲翠光勻，杞菊成畦亦自春。", "骨相定知非食肉，可能長伴箇中人。"]'),
('e5cf513d-7e50-4be2-8b9f-ed0210078a4e','次呂季克東堂九詠 海棠屏','朱熹','宋','宋诗','song-poetry','','[]','蜀樹成行翠作圍，花開時節更芳菲。',32,'全唐诗/poet.song.148000.json','["蜀樹成行翠作圍，花開時節更芳菲。", "主人夢亦尋春去，栩栩深穿錦障飛。"]'),
('f4ac9f8d-9668-4f21-8e1c-b865e623fbcd','次呂季克東堂九詠 橘堤','朱熹','宋','宋诗','song-poetry','','[]','君家池上幾時栽，千樹玲瓏亦富哉。',32,'全唐诗/poet.song.148000.json','["君家池上幾時栽，千樹玲瓏亦富哉。", "荷盡菊殘秋欲老，一年佳處眼中來。"]'),
('7d9c6c9d-45bb-4a44-94bc-caf4a85fd7d6','挽吳給事三首  其一','朱熹','宋','宋诗','song-poetry','','[]','臺省傾群望，江湖去一麾。',48,'全唐诗/poet.song.148000.json','["臺省傾群望，江湖去一麾。", "語聞三諫切，政有百年思。", "不盡雲龍會，還尋霧豹期。", "誰知七休詠，翻入八哀詩。"]'),
('66946806-dca4-4a42-b15e-67de22f10d9b','挽吳給事三首  其二','朱熹','宋','宋诗','song-poetry','','[]','粵自辭神武，超然絕世紛。',48,'全唐诗/poet.song.148000.json','["粵自辭神武，超然絕世紛。", "前身疏太傅，今日范忠文。", "圃樹寒留月，湖波冷浸雲。", "懸知千載下，此地想遺芬。"]'),
('cb921c0a-e8bb-49fc-a40f-c6fe1aa757ec','挽吳給事三首  其三','朱熹','宋','宋诗','song-poetry','','[]','憶昔觀風寄，登堂識老成。',48,'全唐诗/poet.song.148000.json','["憶昔觀風寄，登堂識老成。", "忘年見交態，把酒話詩情。", "別去如三歲，書來忽九京。", "却思憑檻語，忍遽勒公銘。"]'),
('92a9ff1d-f85a-443b-82a0-cb478a471a6a','伏讀雲臺壁間秘閣郎中盤谷傳丈題詩齒及賤名追懷曩昔不勝感涕輒次元韻呈諸同遊計亦同此歎也','朱熹','宋','宋诗','song-poetry','','[]','提携當日忝忘年，曾向瑕丘獨請前。',64,'全唐诗/poet.song.148000.json','["提携當日忝忘年，曾向瑕丘獨請前。", "喜看玄雲生素壁，恍疑後學厠先賢。", "公遊汗漫今何許，我病摧頹久自憐。", "只有空山無歲月，倚天寒木但蒼然。"]'),
('e06fefe9-46ef-4a9d-8939-738b50fbb6ad','次韻寄題萬頃寒光奉呈休齋先生','朱熹','宋','宋诗','song-poetry','','[]','閑將歲月老煙汀，更遣詩情到杳冥。',64,'全唐诗/poet.song.148000.json','["閑將歲月老煙汀，更遣詩情到杳冥。", "遊子故應悲舊國，壯懷那肯泣新亭。", "一官避世今頭白，萬卷收功久汗青。", "但見潮生與潮落，不知沉醉又還醒。"]'),
('77511240-d380-4fc1-9002-0289a14b7967','熹伏蒙休齋先生惠詩見留謹次高韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','忽驚蕭颯鬢毛秋，起向泉山覓舊遊。',64,'全唐诗/poet.song.148000.json','["忽驚蕭颯鬢毛秋，起向泉山覓舊遊。", "盤谷門前淚沾臆，雲臺溪上雪蒙頭。", "歸歟吾黨又千里，老矣心期但一丘。", "珍重休齋書滿屋，可無三宿爲君留。"]'),
('0345d76c-2db8-4978-bc3a-081c54267f8c','熹伏蒙休齋先生惠詩見留謹次高韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','望望西山日幾回，更憐一雨洗浮埃。',64,'全唐诗/poet.song.148000.json','["望望西山日幾回，更憐一雨洗浮埃。", "遠遊莫說雲門寺，往事聊尋單父臺。", "雞犬蕭踈迷洞口，交親零落半巖隈。", "尊前見在君須鬭，速上籃輿相逐來。"]'),
('74f92120-c3e2-4040-9aee-87291510aff6','用林擇之韻別陳休齋','朱熹','宋','宋诗','song-poetry','','[]','別離不覺歲時侵，兩地相望共此心。',64,'全唐诗/poet.song.148000.json','["別離不覺歲時侵，兩地相望共此心。", "今日還成一尊酒，它年應記百篇吟。", "傷情後會無期定，握手交情有舊深。", "多謝晚風知此意，不催寒日下踈林。"]'),
('68ed1af7-0a90-46c5-988f-912c642cce53','奉酬九日東峰道人溥公見贈之作','朱熹','宋','宋诗','song-poetry','','[]','幾年回首夢雲關，此日重來兩鬢斑。',64,'全唐诗/poet.song.148000.json','["幾年回首夢雲關，此日重來兩鬢斑。", "點檢梁間新歲月，招呼臺上舊溪山。", "三生漫說終無據，萬法由來本自閑。", "一笑支郎又相惱，新詩不落語言間。"]'),
('b12820ef-d22c-49b2-9105-335977f941b8','和林擇之鳳凰山韻','朱熹','宋','宋诗','song-poetry','','[]','木落髻鬟擁，湖平粧鏡空。',48,'全唐诗/poet.song.148000.json','["木落髻鬟擁，湖平粧鏡空。", "荒亡餘舊事，慘澹只悲風。", "興發千山裏，詩成一笑中。", "諸君莫惆悵，吾道固當窮。"]'),
('d2c0e182-5911-4d2a-b1a8-15356d2c5c93','次林擇之凉峰韻','朱熹','宋','宋诗','song-poetry','','[]','解轡林間寺，歸鴉晚欲盤。',48,'全唐诗/poet.song.148000.json','["解轡林間寺，歸鴉晚欲盤。", "望中嵐翠合，愁外夕陽殘。", "尊酒何妨盡，羈心且自寬。", "無端滿窗月，遥夜不勝寒。"]'),
('dc5ea484-50a7-4126-9552-230b732aabb3','熹去溫陵二十七年而復來顯菴益老見候七里亭又以佳句見招而休齋陳丈寺丞黄丈皆屬和焉因次韻奉酬併呈二丈','朱熹','宋','宋诗','song-poetry','','[]','不因辭吏役，那得解天刑。',48,'全唐诗/poet.song.148000.json','["不因辭吏役，那得解天刑。", "故國重來遠，寒山依舊青。", "興懷感陳迹，舉目愴新亭。", "尚喜灣頭老，禪房許扣扃。"]'),
('9c320a88-e0ce-47f5-8266-25626006a465','答黄叔張','朱熹','宋','宋诗','song-poetry','','[]','日君趨玉陛，抗疏肅邦刑。',48,'全唐诗/poet.song.148000.json','["日君趨玉陛，抗疏肅邦刑。", "便有榮褒衮，無勞涕伏青。", "衆流爭靡靡，一柱獨亭亭。", "只恐追鋒急，那容晝掩扃。"]'),
('3806f026-2774-46c5-bad9-573bf2211b04','次韻陳休齋蓮華峰之作','朱熹','宋','宋诗','song-poetry','','[]','八石天開勢絕攀，算來未似此心頑。',32,'全唐诗/poet.song.148000.json','["八石天開勢絕攀，算來未似此心頑。", "已吞繚白縈青外，依舊箇中雲夢寬。"]'),
('145c63af-994e-4e78-afb5-5575db7852be','次黄叔張宿凉峰韻','朱熹','宋','宋诗','song-poetry','','[]','菡萏含跗天外秀，婆娑散影月中孤。',32,'全唐诗/poet.song.148000.json','["菡萏含跗天外秀，婆娑散影月中孤。", "惜無畫手追前輩，寫就凉峰憩寂圖。"]'),
('323c17dc-f6f8-4ef2-80f5-b4d6c4eb0f1d','至鳳凰山再作','朱熹','宋','宋诗','song-poetry','','[]','門前寒水青銅闕，林外晴峰紫帽孤。',32,'全唐诗/poet.song.148000.json','["門前寒水青銅闕，林外晴峰紫帽孤。", "記得南垞通柳浪，依稀全是輞川圖。"]'),
('3da52edc-3bf1-4018-b209-bf2d7202dc2a','見梅用攀字韻','朱熹','宋','宋诗','song-poetry','','[]','年來羞把玉梅攀，萬樹爭春我獨頑。',32,'全唐诗/poet.song.148000.json','["年來羞把玉梅攀，萬樹爭春我獨頑。", "只有顛狂無告訴，詩腸欲斷酒腸寬。"]'),
('98b07474-5557-441e-9dea-8c21150c5393','次韻陳休齋懷古堂','朱熹','宋','宋诗','song-poetry','','[]','平昔塵編裏，心期本自幽。',48,'全唐诗/poet.song.148000.json','["平昔塵編裏，心期本自幽。", "那堪舊泉石，更作此追遊。", "好句看猶在，遺忠愴已休。", "亦知今日意，不逐大江流。"]'),
('9e996b91-0adb-4b29-be8d-f8fb313ee655','寄題九日山廓然亭','朱熹','宋','宋诗','song-poetry','','[]','昨遊九日山，散髮巖上石。',96,'全唐诗/poet.song.148000.json','["昨遊九日山，散髮巖上石。", "仰看天宇近，俯歎塵境窄。", "歸來今幾時，夢想掛蒼壁。", "聞公結茅地，恍復記疇昔。", "年隨流水逝，事與浮雲失。", "了知廓然處，初不從外得。", "遥憐植杖翁，鶴骨雙眼碧。", "永嘯月明中，秋風桂花白。"]'),
('56f6c693-442a-43b0-b7f6-cecc55a64dc4','用林擇之韻呈陳福公','朱熹','宋','宋诗','song-poetry','','[]','昔公秉鈞衡，金玉我王度。',48,'全唐诗/poet.song.148000.json','["昔公秉鈞衡，金玉我王度。", "中年幾湖海，偃息安國步。", "巋然九鼎重，翩若孤雲去。", "俯仰天地間，誰哉此同趣。"]'),
('dbd4d0f6-72e7-4ec9-8ecd-5d578204ddda','用前韻答方直甫','朱熹','宋','宋诗','song-poetry','','[]','小儒談大方，任意略權度。',48,'全唐诗/poet.song.148000.json','["小儒談大方，任意略權度。", "未行要疾走，踉蹡不成步。", "唯應過量人，不作與麽去。", "請君敞書帷，爲我說歸趣。"]'),
('25dabe21-f88f-404e-8463-f3f07ffaa3ee','用前韻答林史君','朱熹','宋','宋诗','song-poetry','','[]','十年劇傾馳，此日際風度。',48,'全唐诗/poet.song.148000.json','["十年劇傾馳，此日際風度。", "胡然龔黄最，未接夔龍步。", "詩成肯遽休，客醉那得去。", "却恐驛書來，湖山適成趣。"]'),
('4ed72015-6a0d-4bca-87b8-3d276951b791','題君子亭','朱熹','宋','宋诗','song-poetry','','[]','清晨坐武觀，凉風動高旌。',96,'全唐诗/poet.song.148000.json','["清晨坐武觀，凉風動高旌。", "挾弓一笑起，屈此四座英。", "破的亦已屢，穿楊詎云精。", "軍吏不敢賀，高鳥時相驚。", "解韝脫决遂，緩带飄華纓。", "俯仰新亭幽，曠然塵慮清。", "內正外自直，三揖奚所爭。", "端居得深玩，君子非虛名。"]'),
('753c5e43-405b-45a4-a73b-e6ed6d0c13fe','伏承侍郎使君垂示所與少傅國公唱酬西湖佳句謹次高韻聊發一笑  其一','朱熹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百年地闢有奇功，創見猶驚鶴髮翁。',64,'全唐诗/poet.song.148000.json','["百年地闢有奇功，創見猶驚鶴髮翁。", "共喜安車迎國老，更傳佳句走郵童。", "閑來且看潮頭入，樂事寧憂酒盞空。", "會見台星與卿月，交光齊照廣寒宮。"]'),
('313411ce-05bd-40c1-b581-a8daa5dfd89e','伏承侍郎使君垂示所與少傅國公唱酬西湖佳句謹次高韻聊發一笑  其二','朱熹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','越王城下水融融，此樂從今與衆同。',64,'全唐诗/poet.song.148000.json','["越王城下水融融，此樂從今與衆同。", "滿眼芰荷方永日，轉頭禾黍便西風。", "湖光盡處天容闊，潮信來時海氣通。", "酬唱不誇風物好，一心憂國願年豐。"]'),
('b7d7255e-254e-438b-a181-93f7aff95e12','伏承子直都督侍郎臨餞遠郊仍邀嚴州郎中及諸名勝相與燕集分韻賦詩熹得時字輒成鄙句','朱熹','宋','宋诗','song-poetry','','[]','芳歲倏云晏，故山風雪時。',180,'全唐诗/poet.song.148000.json','["芳歲倏云晏，故山風雪時。", "胡爲在中路，復此行遲遲。", "爲有賢主人，愛客情依依。", "昨夕西門道，終宴不能辭。", "今朝復何朝，祖帳遥相追。", "賓從俱俊賢，車馬有光輝。", "敞扉得華觀，俯檻臨清池。", "南州淑氣多，蕩節佳景隨。", "雪樹雖改色，青山正含姿。", "開樽酌春醪，授簡哦新詩。", "但覺四坐歡，不知寸晷移。", "流雲暗寒空，蒼煙染人衣。", "相看暮色至，我去公當歸。", "別袖不忍分，扣扣陳苦詞。", "願公崇令德，慰我渴與饑。"]'),
('0247661c-91a2-40e6-a597-331bb92780e8','臘月九日晚發懷安公父教授壽翁知丞載酒爲別而元禮景嵩子木擇之廷老考叔舜民諸賢相與同舟乘便風頃刻數十里江空月明飲酒樂甚因以星垂平野闊月湧大江流分韻熹得星字醉中別去乃得數語略紀一時之勝云','朱熹','宋','宋诗','song-poetry','','[]','掛帆望煙渚，整棹別津亭。',144,'全唐诗/poet.song.148000.json','["掛帆望煙渚，整棹別津亭。", "風水已云便，我行安得停。", "離樽枉羣賢，濁醪愧先傾。", "談笑不知遠，但覺江流清。", "獵獵甘蔗洲，茫茫白沙汀。", "斯須復回首，祇有遥山青。", "野色一以暝，川光皛孤明。", "中流漾華月，極浦涵踈星。", "酒酣客散歸，茫然獨宵征。", "起視天宇闊，此身一浮萍。", "難追五湖遊，未願三閭醒。", "且詠招隠作，孤舟轉竛竮。"]'),
('c612153b-5e38-4023-a583-457e0796b17d','伏蒙制置閣學侍郎示及致政少傅相公送行長句并得竊窺酬和佳篇伏讀之餘不勝慰幸謹次高韻少見愚悃以餞車塵伏惟采矚  其一','朱熹','宋','宋诗','song-poetry','','[]','公子威名動海濱，四年相與愧情親。',64,'全唐诗/poet.song.148000.json','["公子威名動海濱，四年相與愧情親。", "忽聞黄鉞分全蜀，更祝彤庭列九賓。", "執手便驚成契闊，贈言還喜和陽春。", "政成但祝歸來早，別恨無端莫重陳。"]'),
('25b78cb4-2056-4518-9d43-fe84fc619814','伏蒙制置閣學侍郎示及致政少傅相公送行長句并得竊窺酬和佳篇伏讀之餘不勝慰幸謹次高韻少見愚悃以餞車塵伏惟采矚  其二','朱熹','宋','宋诗','song-poetry','','[]','地兼梁益盛中權，自昔疇咨出萬全。',64,'全唐诗/poet.song.148000.json','["地兼梁益盛中權，自昔疇咨出萬全。", "定喜封章來活國，故煩伏軾去籌邊。", "軍民傳詔歡聲溢，婦女迎門巧笑妍。", "要答君恩與人望，可無清教逮初筵。"]'),
('32378561-9c30-4afc-b930-76221de2cea3','伏讀致政少傅相公送趙成都佳句兩篇不勝慰幸已次高韻并餞其行而再賦此章以見區區瞻仰之意繕錄拜呈伏乞采覽  其一','朱熹','宋','宋诗','song-poetry','','[]','歸來寂莫卧漳濱，夢想威容阻再親。',64,'全唐诗/poet.song.148000.json','["歸來寂莫卧漳濱，夢想威容阻再親。", "綠野遥聞花欲語，赤書還喜鴈來賓。", "閑中有句人爭誦，妙處無心物自春。", "行馬不因吾輩設，胸奇猶得話陳陳。"]'),
('bb40a7af-b1c7-4fcc-9afe-bee1841bf18e','伏讀致政少傅相公送趙成都佳句兩篇不勝慰幸已次高韻并餞其行而再賦此章以見區區瞻仰之意繕錄拜呈伏乞采覽  其二','朱熹','宋','宋诗','song-poetry','','[]','一旦高辭將相權，身名從此慶雙全。',64,'全唐诗/poet.song.148000.json','["一旦高辭將相權，身名從此慶雙全。", "人誇迹已風塵外，誰道心遊日月邊。", "未許前賢專晚節，更將餘事發春妍。", "君王若要詢黄髮，便好臨雍促肆筵。"]'),
('18589f58-9725-4fbd-a1b8-f5579ec693f3','送彥集之官瀏陽','朱熹','宋','宋诗','song-poetry','','[]','急景彫暮節，高風振空林。',144,'全唐诗/poet.song.148000.json','["急景彫暮節，高風振空林。", "病夫掩關卧，長謠擁孤衾。", "聞君千里行，四牡方駸駸。", "重此別離感，青天欲愁陰。", "君行豈不勞，民瘼亦已深。", "催科處處急，椎鑿年年侵。", "君行寬彼甿，足以慰我心。", "薦書會滿篋，社酒還同斟。", "所念家同産，與君如瑟琴。", "茲焉不並駕，宰木寒蕭椮。", "尚喜吾諸甥，男恭女知欽。", "明朝復相憶，悵望楚山岑。"]'),
('16942562-2461-4e2e-952f-becedaf561d3','次劉正之芙蓉韻三首  其一','朱熹','宋','宋诗','song-poetry','','[]','淺綠深紅出短籬，望中都是可憐枝。',32,'全唐诗/poet.song.148000.json','["淺綠深紅出短籬，望中都是可憐枝。", "要看亂颭寒塘水，更待金風滿意吹。"]'),
('47dcaa00-ab55-46f8-9bfa-df1b4fd5332e','次劉正之芙蓉韻三首  其二','朱熹','宋','宋诗','song-poetry','','[]','凌波直欲渡橫塘，却愛無人獨自芳。',32,'全唐诗/poet.song.148000.json','["凌波直欲渡橫塘，却愛無人獨自芳。", "且倚新漪閑照影，更憑女伴一扶將。"]'),
('69e103bb-f9da-436a-99c6-6e64bb9e68fb','次劉正之芙蓉韻三首  其三','朱熹','宋','宋诗','song-poetry','','[]','微吟澤畔幾扶笻，自笑摧頹一禿翁。',32,'全唐诗/poet.song.148000.json','["微吟澤畔幾扶笻，自笑摧頹一禿翁。", "羞見芙蓉好顔色，且憑詩律傲西風。"]'),
('31ffaae9-cac9-4293-b163-6906908698e2','石馬斜川之集分韻賦詩得燈字','朱熹','宋','宋诗','song-poetry','','[]','改歲風日好，出門欣得朋。',144,'全唐诗/poet.song.148000.json','["改歲風日好，出門欣得朋。", "復招里中彥，及此雲間僧。", "行行涉清波，斯亭一來登。", "徙倚綠樹蔭，摩娑蒼石稜。", "遥瞻原野春，仰視天宇澄。", "一水既紆鬰，群山正崚嶒。", "時禽悅新陽，潛魚躍輕冰。", "却念去年日，俯仰愁予膺。", "長吟斜川詩，日落寒煙凝。", "暝色變晴景，清尊照華燈。", "頹顔感川徂，稚齒歡年增。", "酒盡不能起，朱欄各深凭。"]'),
('761ceafd-841e-463a-8152-aef33deda961','游石馬以駕言出遊分韻賦詩得出字','朱熹','宋','宋诗','song-poetry','','[]','抱病守窮廬，閉戶常罕出。',144,'全唐诗/poet.song.148000.json','["抱病守窮廬，閉戶常罕出。", "坐見春氣深，清陰晝蒙密。", "今朝積雨過，淑景回煦律。", "不有塵外蹤，何由散愁寂。", "行行整巾屨，散漫委書帙。", "野逕自縈紆，前峰但崷崒。", "婆娑茂樹下，左右寒流汩。", "亂石翳蒼根，於焉憩腰膝。", "追遊固才彥，逢遇亦奇逸。", "招邀愧深情，晤言永茲日。", "君有尊中物，我進沂上瑟。", "日夕不得留，餘歡未云畢。"]'),
('a71ac72e-6472-4782-ab3d-7ca8f3506115','三月晦日與諸兄爲真率之約徘徊石馬晚集保福偶成短句奉呈聊發一笑','朱熹','宋','宋诗','song-poetry','','[]','春服明朝換，晴川漲綠陰。',72,'全唐诗/poet.song.148000.json','["春服明朝換，晴川漲綠陰。", "追隨皆勝侶，邂逅即初心。", "社蹟莓苔古，禪扉竹樹深。", "移尊真惜日，畢景共披襟。", "儉德遵賢範，哇詞愧雅音。", "清和應更好，逸想寄雲岑。"]'),
('46b50d2b-8a56-4a72-9213-3c52717cd151','比與鄰曲諸賢修舉歲事携壺石馬追補斜川之遊而公濟適至飲罷首出和陶之句以紀其勝輒亦用韻酬答兼呈諸同遊者請共賦之','朱熹','宋','宋诗','song-poetry','','[]','皇天分四序，代謝無時休。',120,'全唐诗/poet.song.148000.json','["皇天分四序，代謝無時休。", "昔人抱孤念，感此成清遊。", "迥眺曾城臯，朗詠斜川流。", "歲月今幾許，長波沒輕鷗。", "眷言撫佳辰，荒尋靡遺丘。", "且復置往事，及茲命高儔。", "縱策聊並歡，飛觥起相酬。", "未知千載下，亦記此日不。", "商歌有遺音，林樂無餘憂。", "但得長如此，吾生復何求。"]'),
('face3bbf-a006-47a2-a087-e1ac1d2e6f49','行視武夷精舍作','朱熹','宋','宋诗','song-poetry','','[]','神山九折溪，沿泝此中半。',168,'全唐诗/poet.song.148000.json','["神山九折溪，沿泝此中半。", "水深波浪闊，浮綠春渙渙。", "上有蒼石屏，百仞聳雄觀。", "嶄巖露垠堮，突兀倚霄漢。", "淺麓下縈迴，深林久叢灌。", "胡然閟千載，逮此開一旦。", "我乘新村船，輟棹青草岸。", "榛莽喜誅鉏，面勢窮考按。", "居然一環堵，妙處豈輪奐。", "左右矗奇峯，躊躇極佳玩。", "是時芳節闌，紅綠紛有爛。", "好鳥時一鳴，王孫遠相喚。", "暫遊意已愜，獨往身猶絆。", "珍重舍瑟人，重來足幽伴。"]'),
('d81fb9f5-8d93-4003-bb9f-455bd00d1a72','武夷精舍雜詠 精舍','朱熹','宋','宋诗','song-poetry','','[]','琴書四十年，幾作山中客。',24,'全唐诗/poet.song.148000.json','["琴書四十年，幾作山中客。", "一日茅棟成，居然我泉石。"]'),
('a27a942e-6038-470a-ba6e-7f187580ff52','武夷精舍雜詠 仁智堂','朱熹','宋','宋诗','song-poetry','','[]','我慙仁知心，偶自愛山水。',24,'全唐诗/poet.song.148000.json','["我慙仁知心，偶自愛山水。", "蒼崖無古今，碧澗日千里。"]'),
('2ab10a8e-4fc9-425e-800e-a0ffefa69647','武夷精舍雜詠 隠求齋','朱熹','宋','宋诗','song-poetry','','[]','晨窗林影開，夜枕山泉響。',24,'全唐诗/poet.song.148000.json','["晨窗林影開，夜枕山泉響。", "隠去復何求，無言道心長。"]'),
('cd5ba8c0-20f1-4df7-96a9-ba3f4b86918a','武夷精舍雜詠 止宿寮','朱熹','宋','宋诗','song-poetry','','[]','故人肯相尋，共寄一茅宇。',24,'全唐诗/poet.song.148000.json','["故人肯相尋，共寄一茅宇。", "山水爲留行，無勞具雞黍。"]'),
('80f001a1-b993-467f-81da-9ac0c813868d','武夷精舍雜詠 石門塢','朱熹','宋','宋诗','song-poetry','','[]','朝開雲氣擁，暮掩薜蘿深。',24,'全唐诗/poet.song.148000.json','["朝開雲氣擁，暮掩薜蘿深。", "自笑晨門者，那知孔氏心。"]'),
('95b40215-c1b2-403e-9a71-30824e495c24','武夷精舍雜詠 觀善齋','朱熹','宋','宋诗','song-poetry','','[]','負笈何方來，今朝此同席。',24,'全唐诗/poet.song.148000.json','["負笈何方來，今朝此同席。", "日用無餘功，相看俱努力。"]'),
('181a0526-6796-49ab-be35-bde419a36f4a','武夷精舍雜詠 寒栖館','朱熹','宋','宋诗','song-poetry','','[]','竹間彼何人，抱甕靡遺力。',24,'全唐诗/poet.song.148000.json','["竹間彼何人，抱甕靡遺力。", "遥夜更不眠，焚香坐看壁。"]'),
('74888caa-dc95-4f41-9771-c5febaf608c3','武夷精舍雜詠 晚對亭','朱熹','宋','宋诗','song-poetry','','[]','倚笻南山巔，却立有晚對。',24,'全唐诗/poet.song.148000.json','["倚笻南山巔，却立有晚對。", "蒼峭矗寒空，落日明影翠。"]'),
('6d76bed6-0bee-4213-8247-cfe45064a56e','武夷精舍雜詠 鐵笛亭','朱熹','宋','宋诗','song-poetry','','[]','何人轟鐵笛，噴薄兩崖開。',24,'全唐诗/poet.song.148000.json','["何人轟鐵笛，噴薄兩崖開。", "千載留餘響，猶疑笙鶴來。"]'),
('1ebad568-0c6e-41ec-9297-59bc7dccd8af','武夷精舍雜詠 釣磯','朱熹','宋','宋诗','song-poetry','','[]','削成蒼石稜，倒影寒潭碧。',24,'全唐诗/poet.song.148000.json','["削成蒼石稜，倒影寒潭碧。", "永日靜垂竿，茲心竟誰識。"]'),
('382189d8-b8be-49f9-ac17-51b9d2231ac8','武夷精舍雜詠 茶竈','朱熹','宋','宋诗','song-poetry','','[]','仙翁遺石竈，宛在水中央。',24,'全唐诗/poet.song.148000.json','["仙翁遺石竈，宛在水中央。", "飲罷方舟去，茶烟裊細香。"]'),
('4b3d6ef1-1d66-4ef4-a88d-75e98ff68d82','武夷精舍雜詠 漁艇','朱熹','宋','宋诗','song-poetry','','[]','出載長烟重，歸裝片月輕。',24,'全唐诗/poet.song.148000.json','["出載長烟重，歸裝片月輕。", "千巖猿鶴友，愁絕棹歌聲。"]'),
('8481dded-359d-4d51-aa87-768ca0dbc36a','次公濟精舍韻','朱熹','宋','宋诗','song-poetry','','[]','一室空山裏，纖塵迥莫侵。',48,'全唐诗/poet.song.148000.json','["一室空山裏，纖塵迥莫侵。", "若非同臭味，誰肯遠過臨。", "健策凌丹壑，清詩動玉琴。", "溪邊一回首，平地足崎嶔。"]'),
('ea653a3c-25e6-4605-a4a8-2e0a301af806','奉同公濟諸兄自精舍來集沖佑之歲寒軒因邀諸羽客同飲公濟有詩贈守元章師因次其韻','朱熹','宋','宋诗','song-poetry','','[]','蓬萊清淺今幾年，武夷突兀還蒼然。',64,'全唐诗/poet.song.148000.json','["蓬萊清淺今幾年，武夷突兀還蒼然。", "但忻丹籍有期運，不悟翠壁無寅緣。", "鼎中龍虎應浪語，紙上爻彖非真傳。", "明朝猿叫三峽路，一葉徑上滄浪船。"]'),
('57f50078-a61e-452f-a316-5d11b77616a8','出山道中口占','朱熹','宋','宋诗','song-poetry','','[]','川原紅綠一時新，暮雨朝晴更可人。',32,'全唐诗/poet.song.148000.json','["川原紅綠一時新，暮雨朝晴更可人。", "書冊埋頭無了日，不如拋却去尋春。"]'),
('a02fb470-a8ea-42b9-85f1-d6382336375b','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其一','朱熹','宋','宋诗','song-poetry','','[]','武夷山上有仙靈，山下寒流曲曲清。',32,'全唐诗/poet.song.148000.json','["武夷山上有仙靈，山下寒流曲曲清。", "欲識箇中奇絕處，櫂歌閑聽兩三聲。"]'),
('7b7cde86-95d8-47c0-8d05-73147166ceb2','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其二','朱熹','宋','宋诗','song-poetry','','[]','一曲溪邊上釣船，幔亭峯影蘸晴川。',32,'全唐诗/poet.song.148000.json','["一曲溪邊上釣船，幔亭峯影蘸晴川。", "虹橋一斷無消息，萬壑千巖鎖翠煙。"]'),
('25726048-2195-4702-a8ba-ebb9910e18a0','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其三','朱熹','宋','宋诗','song-poetry','','[]','二曲亭亭玉女峰，插花臨水爲誰容。',32,'全唐诗/poet.song.148000.json','["二曲亭亭玉女峰，插花臨水爲誰容。", "道人不復荒臺夢，興入前山翠幾重。"]'),
('4322428a-f982-4082-9810-f601c8c8a2af','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其四','朱熹','宋','宋诗','song-poetry','','[]','三曲君看架壑船，不知停櫂幾何年。',32,'全唐诗/poet.song.148000.json','["三曲君看架壑船，不知停櫂幾何年。", "桑田海水今如許，泡沫風燈敢自憐。"]'),
('b2d52e7c-ba5a-4fc4-9ab0-42e8f56b0a8d','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其五','朱熹','宋','宋诗','song-poetry','','[]','四曲東西兩石巖，巖花垂露碧𣰦毿。',32,'全唐诗/poet.song.148000.json','["四曲東西兩石巖，巖花垂露碧𣰦毿。", "金雞叫罷無人見，月滿空山水滿潭。"]'),
('6b12cc83-e3bc-4723-b1ac-c5a893ad8cbb','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其六','朱熹','宋','宋诗','song-poetry','','[]','五曲山高雲氣深，長時煙雨暗平林。',32,'全唐诗/poet.song.148000.json','["五曲山高雲氣深，長時煙雨暗平林。", "林間有客無人識，欵乃聲中萬古心。"]'),
('9f707edf-e86f-4813-9009-cc302c6a8182','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其七','朱熹','宋','宋诗','song-poetry','','[]','六曲蒼屏遶碧灣，茅茨終日掩柴關。',32,'全唐诗/poet.song.148000.json','["六曲蒼屏遶碧灣，茅茨終日掩柴關。", "客來倚櫂巖花落，猿鳥不驚春意閑。"]'),
('de629f31-d1c4-4a8e-a832-f98e0253cb0a','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其八','朱熹','宋','宋诗','song-poetry','','[]','七曲移船上碧灘，隠屏仙掌更回看。',32,'全唐诗/poet.song.148000.json','["七曲移船上碧灘，隠屏仙掌更回看。", "人言此處無佳景，只有石堂空翠寒。"]'),
('98b21525-c068-4f4e-b6d5-515bbb9d20aa','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其九','朱熹','宋','宋诗','song-poetry','','[]','八曲風煙勢欲開，鼓樓巖下水縈洄。',32,'全唐诗/poet.song.148000.json','["八曲風煙勢欲開，鼓樓巖下水縈洄。", "莫言此處無佳景，自是遊人不上來。"]'),
('97e63794-ae9e-49b3-904d-cc3caec65d85','淳熙甲辰中春精舍閒居戲作武夷櫂歌十首呈諸同遊相與一笑  其一○','朱熹','宋','宋诗','song-poetry','','[]','九曲將窮眼豁然，桑麻雨露見平川。',32,'全唐诗/poet.song.148000.json','["九曲將窮眼豁然，桑麻雨露見平川。", "漁郎更覓桃源路，除是人間別有天。"]'),
('a3754f26-c08b-4ab5-9d0a-256b2499b5c5','伏蒙致政少傅相公寵賜寄題武夷精舍詩一首拜受捧讀不勝仰歎無以自見區區感幸之誠輒繼高韻繕寫拜呈冒瀆威尊下情恐悚之至','朱熹','宋','宋诗','song-poetry','','[]','望斷鈞天白玉都，石田茅屋詎應無。',64,'全唐诗/poet.song.148000.json','["望斷鈞天白玉都，石田茅屋詎應無。", "况蒙一字榮褒衮，便覺千峰勝畫圖。", "舊弼詩情高綠野，狂奴心事只風雩。", "蒲輪幾日符嘉夢，恰有流霞酒一壺。"]'),
('f57e07d8-b3be-4136-94df-bb70885aed44','劉子澄遠寄羊裘且有懷仁輔義之語戲成兩絕爲謝以發千里一笑  其一','朱熹','宋','宋诗','song-poetry','','[]','短棹長簑九曲灘，晚來閑弄釣魚竿。',32,'全唐诗/poet.song.148000.json','["短棹長簑九曲灘，晚來閑弄釣魚竿。", "幾回欲過前灣去，却怕斜風特地寒。"]'),
('25e48fd5-abca-45ef-a5e9-e21c817e1edc','劉子澄遠寄羊裘且有懷仁輔義之語戲成兩絕爲謝以發千里一笑  其二','朱熹','宋','宋诗','song-poetry','','[]','誰把羊裘與醉披，故人心事不相違。',32,'全唐诗/poet.song.148000.json','["誰把羊裘與醉披，故人心事不相違。", "狂奴今夜知何處，月冷風凄未肯歸。"]'),
('cb891e65-2cd3-45db-8411-f28e93776199','過蓋竹作二首  其一','朱熹','宋','宋诗','song-poetry','','[]','二月春風特地寒，江樓獨自倚欄干。',32,'全唐诗/poet.song.148000.json','["二月春風特地寒，江樓獨自倚欄干。", "箇中詎有行藏意，且把前峰細數看。"]'),
('bf65ff20-eb23-48fb-b38f-2f1d55a6d178','過蓋竹作二首  其二','朱熹','宋','宋诗','song-poetry','','[]','浩蕩鷗盟久未寒，征驂聊此駐江干。',32,'全唐诗/poet.song.148000.json','["浩蕩鷗盟久未寒，征驂聊此駐江干。", "何時買得魚船就，乞與人間畫裏看。"]'),
('0349a2ca-e6b3-439c-9e2f-a8ae770f2d00','送建陽陳丞伯厚還鄉','朱熹','宋','宋诗','song-poetry','','[]','括蒼雲壑入秋夢，閩嶺風霜侵鬢絲。',64,'全唐诗/poet.song.148000.json','["括蒼雲壑入秋夢，閩嶺風霜侵鬢絲。", "歲晚未收稽古力，徑荒曾擬賦歸辭。", "一官坎壈嗟丞負，百歲歡榮慶母慈。", "去步逶迤無慍色，此心惟有古人知。"]'),
('84c3b78a-85ce-46f9-be58-98c91320c931','拜鴻慶宮有感','朱熹','宋','宋诗','song-poetry','','[]','舊京原廟久煙塵，白髮祠官感慨新。',32,'全唐诗/poet.song.148000.json','["舊京原廟久煙塵，白髮祠官感慨新。", "北望千門空引籍，不知何日去朝真。"]'),
('7e1658f2-921a-49fb-80a9-fd2e459babc7','答袁機仲論啟蒙','朱熹','宋','宋诗','song-poetry','','[]','忽然半夜一聲雷，萬戶千門次第開。',32,'全唐诗/poet.song.148000.json','["忽然半夜一聲雷，萬戶千門次第開。", "若識無心含有象，許君親見伏羲來。"]'),
('b02f2ed5-01b9-4001-ab61-3a895db3747f','觀林長仁書卷戲題問答  其一','朱熹','宋','宋诗','song-poetry','','[]','猿去山空鶴亦飛，柴門空掩釣魚磯。',32,'全唐诗/poet.song.148000.json','["猿去山空鶴亦飛，柴門空掩釣魚磯。", "門前樹葉都黄了，何事幽人久不歸。"]'),
('b64e3ddd-9c94-46bd-8581-25caf26c7b5d','觀林長仁書卷戲題問答  其二','朱熹','宋','宋诗','song-poetry','','[]','爲愛雲泉百尺飛，故將茅屋傍苔磯。',32,'全唐诗/poet.song.148000.json','["爲愛雲泉百尺飛，故將茅屋傍苔磯。", "幾年清夢黄塵裏，此日秋風一棹歸。"]'),
('874fc82c-1791-4381-b3ae-7783e7c62bc9','題嚴居厚溪莊圖','朱熹','宋','宋诗','song-poetry','','[]','平日生涯一短篷，只今回首畫圖中。',32,'全唐诗/poet.song.148000.json','["平日生涯一短篷，只今回首畫圖中。", "平章箇裏無窮事，要見三山老放翁。"]'),
('8503b236-10de-47e8-a084-86b6d3723ad6','擬縣補以蟲鳴秋詩','朱熹','宋','宋诗','song-poetry','','[]','天籟誰爲主，乘時各自鳴。',72,'全唐诗/poet.song.148000.json','["天籟誰爲主，乘時各自鳴。", "如分百蟲響，來助九秋清。", "未歇吟風調，先催泣露聲。", "乾坤闢氛氣，草木斂華英。", "易斷愁人夢，難安懶婦驚。", "唯應廣成子，萬感不關情。"]'),
('9d4dd229-7409-494d-be49-deb4c9caaad6','挽蔡太博','朱熹','宋','宋诗','song-poetry','','[]','疇昔相逢地，知君意矯强。',48,'全唐诗/poet.song.148000.json','["疇昔相逢地，知君意矯强。", "旋聞將使指，勁節動朝行。", "方爲人材喜，相期事業長。", "知何遽不淑，未及鬢毛蒼。"]'),
('b093469f-367c-446b-9917-523cb8bbeaa3','乙卯八月晦日浮翠亭次叔通韻','朱熹','宋','宋诗','song-poetry','','[]','弱植有孤念，獨住窮名山。',84,'全唐诗/poet.song.148000.json','["弱植有孤念，獨住窮名山。", "那知歲月逝，白首塵埃間。", "今朝定何朝，憑高睨清灣。", "羣賢亦戾止，共此一日閑。", "晤言不知疲，林昏鳥飛還。", "勝踐可無紀，重來諒非艱。", "留語巖上石，毋使門常關。"]'),
('d804e23d-61e7-4037-9adc-714cdf392af1','用丘子服弟韻呈儲行之明府伯玉卓丈及坐上諸友','朱熹','宋','宋诗','song-poetry','','[]','我是溪山舊主人，歸來魚鳥便相親。',32,'全唐诗/poet.song.148000.json','["我是溪山舊主人，歸來魚鳥便相親。", "一盃與爾同生死，萬事從渠更故新。"]'),
('a11bae13-661a-4b8f-bde4-355f4e1e47c4','謹次縣大夫見屬之韻','朱熹','宋','宋诗','song-poetry','','[]','撫摩凋瘵爲心切，摹寫風烟著語親。',32,'全唐诗/poet.song.148000.json','["撫摩凋瘵爲心切，摹寫風烟著語親。", "只願從今更無倦，清詩美政逐年新。"]'),
('39e9e832-858c-49ca-bd89-8121e40633b5','承事卓丈置酒白雲山居飲餞致政儲丈叔通因出佳句諸公皆和熹輒亦繼韻聊發坐中一笑','朱熹','宋','宋诗','song-poetry','','[]','老去讀書秋樹根，山林兒女定誰尊。',64,'全唐诗/poet.song.148000.json','["老去讀書秋樹根，山林兒女定誰尊。", "偶緣送客來僧寺，却似披雲卧石門。", "物外祇今成跌蕩，人間何處不啾喧。", "一杯且爲陽關盡，雙目從教別淚昏。"]'),
('123b913c-4c20-49c5-b25c-04038d1b4a32','丙辰正月三日贈彭世昌歸山','朱熹','宋','宋诗','song-poetry','','[]','象山聞說是君開，雲木參天瀑響雷。',32,'全唐诗/poet.song.148000.json','["象山聞說是君開，雲木參天瀑響雷。", "好去山頭且堅坐，等閑莫要下山來。"]'),
('3a66c84f-6bc6-4595-a942-3b3d0be6b404','和人都試之韻','朱熹','宋','宋诗','song-poetry','','[]','儲胥聞道落初成，共喜兒郎意氣生。',64,'全唐诗/poet.song.148000.json','["儲胥聞道落初成，共喜兒郎意氣生。", "初恨雨聲迷疊鼓，忽驚晴色動高旌。", "盤牟入詠詩情壯，破的傳觴酒今明。", "縱使腐儒東鄉坐，不妨堂上有奇兵。"]'),
('57b6148e-7a3d-48b6-ac0a-21fc015f8af4','聚星落成致政陳丈舉酒屬客出示新詩而仲卿朝瑞及劉范二兄相與繼作熹幸以卜鄰得陪勝集率爾次韻聊發一笑','朱熹','宋','宋诗','song-poetry','','[]','適親德範仰循循，遽喜名章肆筆成。',64,'全唐诗/poet.song.148000.json','["適親德範仰循循，遽喜名章肆筆成。", "賸說臺高今勝昔，極知星聚暗還明。", "當家翰藻爭春麗，上客詞源徹底清。", "更共鄰翁閑指點，千峰環合水無聲。"]'),
('b020814e-3c30-4bc4-9ef4-4350c758b73b','謹次陳昭遠丈龍洲鄉社高韻并呈諸兄友','朱熹','宋','宋诗','song-poetry','','[]','幾年社酒醉班荆，此日祠壇喜落成。',64,'全唐诗/poet.song.148000.json','["幾年社酒醉班荆，此日祠壇喜落成。", "誤許俗書輕染汙，急傳佳語頌登平。", "年豐已荷天垂慶，人傑還欣地炳靈。", "不信鄰村是塵境，請看綠水鎖紅亭。"]'),
('da1c29d1-677f-4b09-8833-18f4a19ead68','懷潭溪舊居','朱熹','宋','宋诗','song-poetry','','[]','憶住潭溪四十年，好峰無數列窗前。',64,'全唐诗/poet.song.148000.json','["憶住潭溪四十年，好峰無數列窗前。", "雖非水抱山環地，却是冬溫夏冷天。", "遶舍扶踈千箇竹，傍崖寒冽一泓泉。", "誰教失計東遷繆，憊卧西窗日滿川。"]'),
('29b707b3-3be0-48d1-9d5d-ee17ee40a659','甘澤應祈一蘇焦槁皆昭遠致政宣義丈及仲卿諸友晝夜精虔不出道場之力而昭遠丈惠詩反以見屬非所敢當輒依高韻和呈以見鄙懷并簡同社諸兄友','朱熹','宋','宋诗','song-poetry','','[]','精禱由來未浹辰，如何嘉澍便遄臻。',64,'全唐诗/poet.song.148000.json','["精禱由來未浹辰，如何嘉澍便遄臻。", "誠通幽隠如無間，喜動龍天信有因。", "適歎惔焚千畝盡，忽驚滂潤一時均。", "誰云化育流行妙，只屬乾坤不屬人。"]'),
('156a0015-9faf-41e1-a319-ffc4bb25fbcc','奉題李彥中所藏俞侯墨戲','朱熹','宋','宋诗','song-poetry','','[]','不是胸中飽丘壑，誰能筆下吐雲煙。',32,'全唐诗/poet.song.148000.json','["不是胸中飽丘壑，誰能筆下吐雲煙。", "故應祇有王摩詰，解寫離騷極目天。"]'),
('642374f4-d724-4e8d-a245-cc61515f3f06','題劉志夫嚴居厚瀟湘詩卷後','朱熹','宋','宋诗','song-poetry','','[]','瀟湘門外水如天，說著令人意慘然。',32,'全唐诗/poet.song.148000.json','["瀟湘門外水如天，說著令人意慘然。", "試問登高能賦客，箇中何似汨羅淵。"]'),
('37311a26-953b-4c9d-85a9-aa4f764a1967','聞蛙','朱熹','宋','宋诗','song-poetry','','[]','兩樞盛怒鬭春池，羣吠同聲徹曉帷。',32,'全唐诗/poet.song.148000.json','["兩樞盛怒鬭春池，羣吠同聲徹曉帷。", "等是一場狼籍事，更無人與問官私。"]'),
('e10d8f81-4886-446c-8e10-22ea97018146','延平水南天慶觀夜作','朱熹','宋','宋诗','song-poetry','','[]','石樓雲卧對江城，城角吟霜永夜清。',32,'全唐诗/poet.song.148000.json','["石樓雲卧對江城，城角吟霜永夜清。", "料得南枝正愁絕，不堪聞此斷腸聲。"]'),
('10e0f64b-dad6-4c84-bb7f-479caca4e64e','墨梅','朱熹','宋','宋诗','song-poetry','','[]','夢裏清江醉墨香，蕊寒枝瘦凜冰霜。',32,'全唐诗/poet.song.148000.json','["夢裏清江醉墨香，蕊寒枝瘦凜冰霜。", "如今白黑渾休問，且作人間時世裝。"]'),
('c4f76a11-f901-4841-8b5b-dcf1002c5e77','秋華四首 木芙蓉','朱熹','宋','宋诗','song-poetry','','[]','紅芳曉露濃，綠樹秋風冷。',24,'全唐诗/poet.song.148000.json','["紅芳曉露濃，綠樹秋風冷。", "共喜巧回春，不妨閑弄影。"]'),
('fc45652e-c7a7-4f7a-bbd0-417066cbcdf1','秋華四首 蕙','朱熹','宋','宋诗','song-poetry','','[]','今花得古名，旖旎香更好。',24,'全唐诗/poet.song.148000.json','["今花得古名，旖旎香更好。", "適意欲忘言，塵編詎能考。"]'),
('83b120d4-f686-4d08-b6df-18a3bd10491f','秋華四首 木犀','朱熹','宋','宋诗','song-poetry','','[]','喬木生夏凉，芳蕤散秋馥。',24,'全唐诗/poet.song.148000.json','["喬木生夏凉，芳蕤散秋馥。", "未覺歲將寒，扶踈方遶屋。"]'),
('9da0b311-7abf-4a0a-b06e-a538d44fec42','秋華四首 菊','朱熹','宋','宋诗','song-poetry','','[]','青蕊冒珍叢，幽姿含曉露。',24,'全唐诗/poet.song.148000.json','["青蕊冒珍叢，幽姿含曉露。", "政爾破荒寒，詎免傷遲暮。"]'),
('46dfbe24-60c3-4fc2-88f3-e510aa8b5a14','晦翁足疾得程道人鍼之而愈戲贈此詩','朱熹','宋','宋诗','song-poetry','','[]','十載扶行恃短筇，一鍼相值有奇功。',32,'全唐诗/poet.song.148000.json','["十載扶行恃短筇，一鍼相值有奇功。", "出門放步人爭看，不是前來勃窣翁。"]'),
('57938ee0-f7b1-4d4f-9d84-78de134f85da','戲答楊廷秀問訊離騷之句二首  其一','朱熹','宋','宋诗','song-poetry','','[]','昔誦離騷夜扣舷，江湖滿地水浮天。',32,'全唐诗/poet.song.148000.json','["昔誦離騷夜扣舷，江湖滿地水浮天。", "只今擁鼻寒窗底，爛却沙頭月一船。"]'),
('cc0e3382-47e4-4449-bb99-584383055c03','戲答楊廷秀問訊離騷之句二首  其二','朱熹','宋','宋诗','song-poetry','','[]','春到寒汀百草生，馬蹄香動楚江聲。',32,'全唐诗/poet.song.148000.json','["春到寒汀百草生，馬蹄香動楚江聲。", "不甘强借三峰面，且爲靈均作杜蘅。"]'),
('d71cd9aa-d52d-4cdd-80e1-76e1790ce971','孝宗皇帝挽歌詞','朱熹','宋','宋诗','song-poetry','','[]','精一傳心妙，文明撫運昌。',216,'全唐诗/poet.song.148000.json','["精一傳心妙，文明撫運昌。", "乾坤歸獨御，日月要重光。", "不值亡胡歲，何由復漢疆。", "遽移丹極仗，便上白雲鄉。", "九有哀同切，孤臣淚特滂。", "詎因逢舜日，曾得厠周行。", "但憶彤墀引，頻趨黼坐旁。", "衮華叨假寵，縞素識通喪。", "似有鹽梅契，還嗟貝錦傷。", "戴盆驚委照，增秩待行香。", "手疏攄丹悃，衡程發皂囊。", "神心應斗轉，巽令亟風揚。", "未答隆儒厚，俄聞脫蹝忙。", "此生知永已，沒世恨空長。", "內難開新主，遄歸立右廂。", "因山方慘澹，去國又愴惶。", "疾病今如許，形骸可自量。", "報恩寧復日，忍死續殘章。"]'),
('15e914ec-6fcd-455d-bcc1-a64e49838a2e','詩送碧崖甘叔懷游廬阜兼簡白鹿山長吳兄唐卿及諸耆舊三首  其一','朱熹','宋','宋诗','song-poetry','','[]','羌廬不見幾經年，一話清遊一悵然。',32,'全唐诗/poet.song.148000.json','["羌廬不見幾經年，一話清遊一悵然。", "此日送君憑問訊，千峰影裏舊潺湲。"]'),
('f76bd055-ac7b-4a0e-9a03-ee99a4a7c8ee','詩送碧崖甘叔懷游廬阜兼簡白鹿山長吳兄唐卿及諸耆舊三首  其二','朱熹','宋','宋诗','song-poetry','','[]','知君掛席下清江，未見香爐意已降。',32,'全唐诗/poet.song.148000.json','["知君掛席下清江，未見香爐意已降。", "直上新泉得雄觀，便將傑句寫長杠。"]'),
('ff107983-44a4-4c92-abf9-c42e99074f80','詩送碧崖甘叔懷游廬阜兼簡白鹿山長吳兄唐卿及諸耆舊三首  其三','朱熹','宋','宋诗','song-poetry','','[]','遺君蹤跡莽荆榛，曾把詩書爲作新。',32,'全唐诗/poet.song.148000.json','["遺君蹤跡莽荆榛，曾把詩書爲作新。", "今日總輸吳季子，枕流漱石自由身。"]'),
('dba173cf-8de0-4d49-b480-a953a04525d3','丘子服來訪道間得古梅折以爲贈劉叔通江文卿俱來各有佳句因各次韻爲答三首  其一','朱熹','宋','宋诗','song-poetry','','[]','老枝橫出數花新，誰寄寒齋雪夜春。',32,'全唐诗/poet.song.148000.json','["老枝橫出數花新，誰寄寒齋雪夜春。", "江路猶應有幽伴，祇愁難得賞心人。"]'),
('231730ca-cd14-4fcd-93dc-814fa449bc03','丘子服來訪道間得古梅折以爲贈劉叔通江文卿俱來各有佳句因各次韻爲答三首  其二','朱熹','宋','宋诗','song-poetry','','[]','獨樹臨孤岸，橫枝放淺花。',24,'全唐诗/poet.song.148000.json','["獨樹臨孤岸，橫枝放淺花。", "不須煩驛使，正耐雪斜斜。"]'),
('8cb6840d-bb8e-464d-af0d-f35590e8803f','丘子服來訪道間得古梅折以爲贈劉叔通江文卿俱來各有佳句因各次韻爲答三首  其三','朱熹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖居士尋詩處，今墮軟紅車馬塵。',32,'全唐诗/poet.song.148000.json','["西湖居士尋詩處，今墮軟紅車馬塵。", "半樹橫枝空好在，祇應無地覓高人。"]'),
('da51d82e-6f35-4070-a338-4fcc88867a6e','用子服韻謝水僊花','朱熹','宋','宋诗','song-poetry','','[]','水中僊子來何處，翠袖黄冠白玉英。',32,'全唐诗/poet.song.148000.json','["水中僊子來何處，翠袖黄冠白玉英。", "報道幽人被渠惱，著詩送與老難兄。"]'),
('8a4ed087-35c2-42eb-8126-eb96d55305d9','引年得請伏蒙致政學士契丈特垂慶問寵以佳篇捧玩之餘感愧亡量輒借高韻少見謝誠伏幸笑覽','朱熹','宋','宋诗','song-poetry','','[]','一氣無私物自棄，放臣偏荷主恩寬。',64,'全唐诗/poet.song.148000.json','["一氣無私物自棄，放臣偏荷主恩寬。", "方慙妄竊老夫號，詎敢重簪博士冠。", "身退未妨閑養病，年豐何幸且偷安。", "新篇似許參同社，願刺仙舟上釣灘。"]'),
('98beec88-4627-456c-979c-c636a5bbe124','蒙恩許遂休致陳昭遠丈以詩見賀已和答之復賦一首','朱熹','宋','宋诗','song-poetry','','[]','闌干苜蓿久空槃，未覺清羸带眼寬。',64,'全唐诗/poet.song.148000.json','["闌干苜蓿久空槃，未覺清羸带眼寬。", "老去光華姦黨籍，向來羞辱侍臣冠。", "極知此道無終否，且喜閑身得暫安。", "漢祚中天那可料，明年太歲又涒灘。"]'),
('ee128194-9a56-4549-bc2a-c47eb46ec7e9','己未九日子服老弟及仲宣諸友載酒見過坐間居厚廟令出示佳句歎伏之餘次韻爲謝并呈同社諸名勝','朱熹','宋','宋诗','song-poetry','','[]','籬菊斑斑半吐黄，沜中又報紫萸香。',64,'全唐诗/poet.song.148000.json','["籬菊斑斑半吐黄，沜中又報紫萸香。", "裝成令節秋還晚，撩得高情老更狂。", "載酒極知乖勝踐，沾衣却免嘆斜陽。", "餘年只恐逢辰少，吟罷君詩引興長。"]'),
('e53cd812-903e-4d38-ab46-269487cd2065','奉和子服老弟黄楊游巖二詩  其一','朱熹','宋','宋诗','song-poetry','','[]','聞道黄楊山上頭，千峰環抱百泉幽。',32,'全唐诗/poet.song.148000.json','["聞道黄楊山上頭，千峰環抱百泉幽。", "羨君柱杖年年去，飽看人間萬頃秋。"]'),
('eae2a353-68ee-4aa2-9f96-f043ecdc019f','奉和子服老弟黄楊游巖二詩  其二','朱熹','宋','宋诗','song-poetry','','[]','游洲巖下水泠泠，枕石何妨夢裏聽。',32,'全唐诗/poet.song.148000.json','["游洲巖下水泠泠，枕石何妨夢裏聽。", "要與他年成故事，謾尋幽處著新亭。"]'),
('bdc2b226-8f94-4911-9adf-1177691a854e','和劉叔通懷游子蒙之韻','朱熹','宋','宋诗','song-poetry','','[]','扣角聽君悲復悲，壯心未已欲何之。',64,'全唐诗/poet.song.148000.json','["扣角聽君悲復悲，壯心未已欲何之。", "交游半落丘山外，離別偏傷老大時。", "尚喜淵潛容賈誼，不須日飲教袁絲。", "病餘我更無憀頼，勉爲同懷一賦詩。"]'),
('c4602e80-1d86-4aad-b369-d35b14ee44dd','叔通老友探梅得句不鄙垂示且有領客携壺之約次韻爲謝聊發一笑','朱熹','宋','宋诗','song-poetry','','[]','迎霜破雪是寒梅，何事今年獨晚開。',64,'全唐诗/poet.song.148000.json','["迎霜破雪是寒梅，何事今年獨晚開。", "應爲花神無意管，故煩我輩著詩催。", "繁英未怕隨清角，踈影誰憐蘸綠盃。", "珍重南鄰諸酒伴，又尋江路覓香來。"]'),
('351aa5a0-cf97-4920-a995-4d8204ebd6b8','病中承子服老弟同居厚叔通居中居晦諸兄友載酒見過子服有詩牽勉奉和并呈在席幸發一笑','朱熹','宋','宋诗','song-poetry','','[]','心期萬壑與千巖，屢向君詩得指南。',64,'全唐诗/poet.song.148000.json','["心期萬壑與千巖，屢向君詩得指南。", "久恨泠然孤宿諾，偶逢兀者便同參。", "儻蒙大藥分金匕，豈羨奇方出玉函。", "誰識留連今夕意，沈痾未散莫回驂。"]'),
('3198d753-a4b8-45ff-bf3c-ba81823b25d7','寄江文卿劉叔通  其一','朱熹','宋','宋诗','song-poetry','','[]','文卿句律如師律，通叔詩情絕世情。',32,'全唐诗/poet.song.148000.json','["文卿句律如師律，通叔詩情絕世情。", "政使暮年窮到骨，不教吟出斷腸聲。"]'),
('024d8025-ed6f-4835-98f9-d3625377bd78','寄江文卿劉叔通  其二','朱熹','宋','宋诗','song-poetry','','[]','詩人從古例多窮，林下如今又兩翁。',32,'全唐诗/poet.song.148000.json','["詩人從古例多窮，林下如今又兩翁。", "應笑湖南老賓友，兩年吹落市塵中。"]'),
('c7994cd1-4687-49e9-ae06-0fdabe4927b7','寄江文卿劉叔通  其三','朱熹','宋','宋诗','song-poetry','','[]','我窮初不爲能詩，笑殺吹竽濫得癡。',32,'全唐诗/poet.song.148000.json','["我窮初不爲能詩，笑殺吹竽濫得癡。", "莫向人前浪分雪，世間真僞有誰知。"]'),
('e20c885f-b0c7-49a1-a35b-f568bf5ef899','梅','朱熹','宋','宋诗','song-poetry','','[]','姑射仙人冰雪容，塵心已共彩雲空。',32,'全唐诗/poet.song.148000.json','["姑射仙人冰雪容，塵心已共彩雲空。", "年年一笑相逢處，長在愁烟苦霧中。"]'),
('b318114c-a5bf-4010-9161-2ce0b3f4107a','香茶供養黄蘗長老悟公故人之塔并以小詩見意二首  其一','朱熹','宋','宋诗','song-poetry','','[]','擺手臨行一寄聲，故應離合未忘情。',32,'全唐诗/poet.song.148000.json','["擺手臨行一寄聲，故應離合未忘情。", "炷香瀹茗知何處，十二峰前海月明。"]'),
('56e91e6e-271f-4e95-9ba1-069524de7cfe','香茶供養黄蘗長老悟公故人之塔并以小詩見意二首  其二','朱熹','宋','宋诗','song-poetry','','[]','一別人間萬事空，他年何處却相逢。',32,'全唐诗/poet.song.148000.json','["一別人間萬事空，他年何處却相逢。", "不須更話三生石，紫翠參天十二峰。"]'),
('427b8610-27ce-42ef-9b08-95b1ea3765d5','庚申立春前一日','朱熹','宋','宋诗','song-poetry','','[]','雪花寒送蠟，梅萼暖生春。',24,'全唐诗/poet.song.148000.json','["雪花寒送蠟，梅萼暖生春。", "歲晚江村路，雲迷景更新。"]'),
('b8c306af-e790-46b8-b971-9b9c44b8d8bf','南城吳氏社倉書樓爲余寫真如此因題其上慶元庚申二月八日滄洲病叟朱熹仲晦父','朱熹','宋','宋诗','song-poetry','','[]','蒼顔已是十年前，把鏡回看一悵然。',32,'全唐诗/poet.song.148000.json','["蒼顔已是十年前，把鏡回看一悵然。", "履薄臨深諒無幾，且將餘日付殘編。"]'),
('79a1fa44-64dc-4dbd-82bd-06cf009c343e','謁表伯余宋祐','朱熹','宋','宋诗','song-poetry','','[]','江上雪意滿，風吹竹林平。',24,'全唐诗/poet.song.148000.json','["江上雪意滿，風吹竹林平。", "先生但堅坐，稚子開柴荆。"]'),
('08404e87-8105-4f4e-8d70-17aeeaa4107a','趁韻','朱熹','宋','宋诗','song-poetry','','[]','千山木脫但空林，天外哀鴻亦叫音。',32,'全唐诗/poet.song.148000.json','["千山木脫但空林，天外哀鴻亦叫音。", "認取溪亭今日意，四更山月湧波心。"]'),
('c7d1afa1-6d27-4f0c-adba-0c28017be9c1','次晦叔寄弟韻二首  其一','朱熹','宋','宋诗','song-poetry','','[]','聞道君歸湘水東，經行長在白雲中。',64,'全唐诗/poet.song.148000.json','["聞道君歸湘水東，經行長在白雲中。", "詩成天柱峰頭月，酒醒朱陵洞裏風。", "舊學難酬香一瓣，流年誰管鬢雙蓬。", "書來爲指誵訛處，不涉言詮不落空。"]'),
('f256be07-855d-4823-9b2a-dd1aaea0a2ea','次晦叔寄弟韻二首  其二','朱熹','宋','宋诗','song-poetry','','[]','試上閩山望楚天，鴈飛欲斷勢還連。',64,'全唐诗/poet.song.148000.json','["試上閩山望楚天，鴈飛欲斷勢還連。", "憑將袖裏數行字，與問雲間雙髻仙。", "我訪舊遊終有日，君歸故里定何年。", "祇今千里同心事，靜對簞瓢獨喟然。"]'),
('a5b67067-3c87-496d-a60c-13504df10a9e','次范碩夫題景福僧開窗韻','朱熹','宋','宋诗','song-poetry','','[]','昨日土牆當面立，今朝竹牖向陽開。',32,'全唐诗/poet.song.148000.json','["昨日土牆當面立，今朝竹牖向陽開。", "此心若道無通塞，明暗何緣有去來。"]'),
('39532596-84b0-4a18-b6e5-fab1845e2fb8','題謝安石東山圖','朱熹','宋','宋诗','song-poetry','','[]','家山花柳春，侍女髻鬟綠。',24,'全唐诗/poet.song.148000.json','["家山花柳春，侍女髻鬟綠。", "出處亦何心，晴雲在空谷。"]'),
('94f0c13c-b00d-4f0c-a685-43686f2549d2','江月圖','朱熹','宋','宋诗','song-poetry','','[]','江空秋月明，夜久寒露滴。',24,'全唐诗/poet.song.148000.json','["江空秋月明，夜久寒露滴。", "扁舟何處歸，吟嘯永佳夕。"]'),
('f5a0d702-a3bc-4fcd-b7b0-c9d514a2756f','吳山高','朱熹','宋','宋诗','song-poetry','','[]','行盡吳山過越山，白雲猶是幾重關。',32,'全唐诗/poet.song.148000.json','["行盡吳山過越山，白雲猶是幾重關。", "若尋汗漫相期處，更在孤鴻滅沒間。"]'),
('8aac862c-eb4a-4eba-8e24-70f00aae525d','題蕃騎圖','朱熹','宋','宋诗','song-poetry','','[]','傳聞姑𫅑欲南侵，愁破雄邊老將心。',32,'全唐诗/poet.song.148000.json','["傳聞姑𫅑欲南侵，愁破雄邊老將心。", "却是燕姬能捍虜，不教行到殺胡林。"]'),
('b124d374-061c-4c8c-9098-2bd1541505a2','題尤溪宗室所藏二妃圖  其一','朱熹','宋','宋诗','song-poetry','','[]','瀟湘木落時，玉佩秋風起。',24,'全唐诗/poet.song.148000.json','["瀟湘木落時，玉佩秋風起。", "日暮悵何之，寂寞寒江水。"]'),
('8bdb4eba-5e16-48a0-bdaa-1cca933dec62','題尤溪宗室所藏二妃圖  其二','朱熹','宋','宋诗','song-poetry','','[]','夫君行不歸，日夕空凝佇。',24,'全唐诗/poet.song.148000.json','["夫君行不歸，日夕空凝佇。", "目斷九疑岑，回頭淚如雨。"]'),
('6040dc8a-1051-4ef5-8862-b6bfebf04343','夜','朱熹','宋','宋诗','song-poetry','','[]','獨宿山房夜氣清，一窗凉月共虛明。',32,'全唐诗/poet.song.148000.json','["獨宿山房夜氣清，一窗凉月共虛明。", "鄰雞未作人聲絕，時聽高梧滴露鳴。"]'),
('a1a73726-2894-46b0-b23c-0417213fc633','醉作三首  其一','朱熹','宋','宋诗','song-poetry','','[]','淅淅西風起，嗷嗷寒鴈多。',24,'全唐诗/poet.song.148000.json','["淅淅西風起，嗷嗷寒鴈多。", "稻粱隨處有，珍重采薇歌。"]'),
('0ebc471d-93e2-41c5-b29d-0827be5f94cb','醉作三首  其二','朱熹','宋','宋诗','song-poetry','','[]','淅淅西風起，候蟲寒夜分。',24,'全唐诗/poet.song.148000.json','["淅淅西風起，候蟲寒夜分。", "千山杳沉寂，竟夕斷知聞。"]'),
('4b7e7535-877e-4090-a8c1-317dda9bedbb','醉作三首  其三','朱熹','宋','宋诗','song-poetry','','[]','淅淅西風起，濺濺石瀨鳴。',24,'全唐诗/poet.song.148000.json','["淅淅西風起，濺濺石瀨鳴。", "有情從是妄，箇裏定無情。"]'),
('63c3bafb-dac4-482e-afb7-e09040ef6395','苦雨用俳諧體','朱熹','宋','宋诗','song-poetry','','[]','仰訴天公雨太多，纔方欲住又滂沱。',32,'全唐诗/poet.song.148000.json','["仰訴天公雨太多，纔方欲住又滂沱。", "九關虎豹還知否，爛盡田中白死禾。"]'),
('844b8d21-e9c2-4c32-99f1-1c9eb73f9d8a','杉木長澗四首  其一','朱熹','宋','宋诗','song-poetry','','[]','我行杉木道，弛轡長澗東。',144,'全唐诗/poet.song.148000.json','["我行杉木道，弛轡長澗東。", "傷哉半菽子，復此巨浸攻。", "沙石半川原，阡陌無遺蹤。", "室廬或僅存，釜甑久已空。", "壓溺餘鰥孤，悲號走哀恫。", "賻恤豈不勤，喪養何能供。", "我非肉食徒，自閉一畝宮。", "簞瓢正可樂，禹稷安能同。", "朅來一經行，歔欷涕無從。", "所慙越尊俎，豈憚勞吾躬。", "攀躋倦冢頂，永嘯回凄風。", "眷焉撫四海，失志嗟何窮。"]'),
('988821dc-ac64-402f-a4b0-e51d54aa5e0c','杉木長澗四首  其二','朱熹','宋','宋诗','song-poetry','','[]','朝發長澗頭，夕宿長澗尾。',24,'全唐诗/poet.song.148000.json','["朝發長澗頭，夕宿長澗尾。", "傷哉長澗人，禍變乃如此。"]'),
('bf38fcaa-6958-4d48-8755-b7f5e62e4f89','杉木長澗四首  其三','朱熹','宋','宋诗','song-poetry','','[]','縣官發廩存鰥孤，民氣未覺回昭蘇。',32,'全唐诗/poet.song.148000.json','["縣官發廩存鰥孤，民氣未覺回昭蘇。", "老農向我更揮涕，陂壞渠絕田苗枯。"]'),
('d88da9ed-2110-4c18-9ba5-f81f65d312e7','杉木長澗四首  其四','朱熹','宋','宋诗','song-poetry','','[]','阡陌縱橫不可尋，死傷狼籍正悲吟。',32,'全唐诗/poet.song.148000.json','["阡陌縱橫不可尋，死傷狼籍正悲吟。", "若知赤子元無罪，合有人間父母心。"]'),
('053535c2-0b53-43d9-bd39-17e3dce3a6ec','題中峰杉徑','朱熹','宋','宋诗','song-poetry','','[]','盤回山腹轉脩蛇，橫入中峰小隠家。',32,'全唐诗/poet.song.148000.json','["盤回山腹轉脩蛇，橫入中峰小隠家。", "好把穉杉緣徑插，待迎凉月看清華。"]'),
('ed690a3f-2a04-4ec4-942e-75840ba640b7','山寺逢僧談命','朱熹','宋','宋诗','song-poetry','','[]','此地相逢亦偶然，漫將牛斗話生緣。',32,'全唐诗/poet.song.148000.json','["此地相逢亦偶然，漫將牛斗話生緣。", "時行時止非人力，莫問流年祇問天。"]'),
('5ff980ab-7b3a-47ef-bfa0-f88ba63246a9','贈書工','朱熹','宋','宋诗','song-poetry','','[]','平生欠要毛錐子，歲晚相看兩禿翁。',32,'全唐诗/poet.song.148000.json','["平生欠要毛錐子，歲晚相看兩禿翁。", "却笑孟嘗門下士，祇能彈鋏傲西風。"]'),
('0f25896f-4306-43a2-b11e-0f62c98086d1','蘭','朱熹','宋','宋诗','song-poetry','','[]','謾種秋蘭四五莖，踈簾底事太關情。',32,'全唐诗/poet.song.148000.json','["謾種秋蘭四五莖，踈簾底事太關情。", "可能不作凉風計，護得幽香到晚清。"]'),
('d2a94675-7f11-4260-9d2e-d81dfd038e9e','讀十二辰詩卷掇其餘作此聊奉一笑','朱熹','宋','宋诗','song-poetry','','[]','夜聞空簞齧饑鼠，曉駕羸牛耕廢圃。',96,'全唐诗/poet.song.148000.json','["夜聞空簞齧饑鼠，曉駕羸牛耕廢圃。", "時才虎圈聽豪夸，舊業兔園嗟莽鹵。", "君看蟄龍卧三冬，頭角不與蛇爭雄。", "毀車殺馬罷馳逐，烹羊酤酒聊從容。", "手種猴桃垂架綠，養得鵾雞鳴角角。", "客來犬吠催煮茶，不用東家買豬肉。"]'),
('04353bd9-3c07-4693-ab00-a789ce745d96','伏承示及毛公平仲墓銘且索挽詩熹不及識毛公而愛重其文舊矣義不可辭顧已不及其虞殯姑以數句題於墓銘後幸辱裁訂或轉而致之其家幸甚','朱熹','宋','宋诗','song-poetry','','[]','毛公神仙骨，誤落世網中。',132,'全唐诗/poet.song.148000.json','["毛公神仙骨，誤落世網中。", "髫齔出奇語，砉然驚乃翁。", "弱齡翰墨場，不言已收功。", "亭亭絕世姿，皎皎冰雪容。", "顧步一長嘯，笙鶴翔秋空。", "調高聽者稀，老去竟不逢。", "一朝謝塵濁，泠然跨剛風。", "回頭叫安期，舉手邀韓終。", "千秋有遺想，一往無留蹤。", "平生故人心，灑涕銘幽宮。", "斯人不可見，斯文鬼神通。"]'),
('2ed4aab9-96dc-45d6-9770-8bfa059aab45','挽鹿伯可郎中二首  其一','朱熹','宋','宋诗','song-poetry','','[]','造辟謀謨遠，勤民志慮專。',48,'全唐诗/poet.song.148000.json','["造辟謀謨遠，勤民志慮專。", "中身謝軒冕，畢志友林泉。", "出祖傾群彥，歸來足二賢。", "誰令行樂地，容易鎖寒烟。"]'),
('1ff3cba7-b608-43c7-aa78-4579cadba2b9','挽鹿伯可郎中二首  其二','朱熹','宋','宋诗','song-poetry','','[]','疇昔東州路，音書僅一通。',48,'全唐诗/poet.song.148000.json','["疇昔東州路，音書僅一通。", "承顔終未遂，仰德竟何窮。", "野哭悲能遽，巖居計莫同。", "關心九原路，無樹不高風。"]'),
('982bf4cb-e4ff-4ac5-8442-6ba9c08e044f','挽陳檢正二首  其一','朱熹','宋','宋诗','song-poetry','','[]','厚德高賢躅，清名起懦襟。',48,'全唐诗/poet.song.148000.json','["厚德高賢躅，清名起懦襟。", "承宣幾年最，明恕一生心。", "勢屈飛騰晚，忠存獻納深。", "忽騎箕尾去，陵柏爲誰陰。"]'),
('617a967d-98e1-435e-aa9e-3e52f5869ab9','挽陳檢正二首  其二','朱熹','宋','宋诗','song-poetry','','[]','憶昔都門道，光華辱宰卿。',48,'全唐诗/poet.song.148000.json','["憶昔都門道，光華辱宰卿。", "丁寧話鹽筴，纖悉見民情。", "一別驚時論，三年想頌聲。", "祇今空老淚，難使濁河清。"]'),
('f83815a6-c51e-4894-804b-4cfb245d0f04','哭劉嶽卿','朱熹','宋','宋诗','song-poetry','','[]','曾說幽棲地，君家近接連。',48,'全唐诗/poet.song.148000.json','["曾說幽棲地，君家近接連。", "要携邀月酒，同棹釣溪船。", "遽爾悲聞笛，真成嘆絕絃。", "林猿催老淚，爲爾一潸然。"]'),
('77813359-d4c0-4944-80c0-2c0bcc33f84e','詩餞陳兄朝章居士永歸本宅授諸挽者','朱熹','宋','宋诗','song-poetry','','[]','蚤歲醇儒業，中年居士身。',48,'全唐诗/poet.song.148000.json','["蚤歲醇儒業，中年居士身。", "功名虛竹帛，德義滿鄉鄰。", "一笑藏舟失，千秋宰樹新。", "傷心耆舊傳，那復有斯人。"]'),
('2bf27663-14bf-46f9-85ee-eb46c43a7d57','宿石岊館二首  其一','朱熹','宋','宋诗','song-poetry','','[]','春江日東注，我行遡其波。',72,'全唐诗/poet.song.148000.json','["春江日東注，我行遡其波。", "揚帆指西澨，兩岸青山多。", "青山自逶迤，飛石空嵯峨。", "綠樹生其間，幽鳥鳴相和。", "搴篷騁遐眺，擊楫成幽歌。", "獨語無與晤，茲懷竟如何。"]'),
('4b67d1f6-ce52-4047-bc36-23ed15c344d9','宿石岊館二首  其二','朱熹','宋','宋诗','song-poetry','','[]','停驂石岊館，觧纜清江濱。',72,'全唐诗/poet.song.148000.json','["停驂石岊館，觧纜清江濱。", "中流櫂歌發，天風水生鱗。", "名都固多才，我來友其仁。", "茲焉同舟濟，詎止胡越親。", "舞雩諒非遠，春服亦已成。", "相期豈今夕，歲晚無緇磷。"]'),
('06ff55dc-cc5c-457d-b16b-5dd20b846ccc','水口行舟二首  其一','朱熹','宋','宋诗','song-poetry','','[]','昨夜扁舟雨一簑，滿江風浪夜如何。',32,'全唐诗/poet.song.148000.json','["昨夜扁舟雨一簑，滿江風浪夜如何。", "今朝試捲孤篷看，依舊青山綠樹多。"]'),
('942d8876-294c-4919-bacf-5e29075d22b4','水口行舟二首  其二','朱熹','宋','宋诗','song-poetry','','[]','鬰鬰層巒夾岸青，春山綠水去無聲。',32,'全唐诗/poet.song.148000.json','["鬰鬰層巒夾岸青，春山綠水去無聲。", "煙波一棹知何許，鶗鴂兩山相對鳴。"]'),
('e012aa33-ce4b-472c-8861-780c2896d493','詠巖桂二首  其一','朱熹','宋','宋诗','song-poetry','','[]','亭亭巖下桂，歲晚獨芬芳。',48,'全唐诗/poet.song.148000.json','["亭亭巖下桂，歲晚獨芬芳。", "葉密千層綠，花開萬點黄。", "天香生浄想，雲影護仙粧。", "誰識王孫意，空吟招隠章。"]'),
('8c77c74a-c96c-4156-9dfa-da5928c3b19f','詠巖桂二首  其二','朱熹','宋','宋诗','song-poetry','','[]','露浥黄金蘂，風生碧玉枝。',48,'全唐诗/poet.song.148000.json','["露浥黄金蘂，風生碧玉枝。", "千林向摇落，此樹獨華滋。", "木末難同調，籬邊不並時。", "攀援香滿袖，歎息共心期。"]'),
('4bcfcb5a-e597-4bae-af98-029173fcd6d8','次韻芮察院送□寶文赴浙漕二首  其一','朱熹','宋','宋诗','song-poetry','','[]','遠俗何勞問，威名舊已孚。',48,'全唐诗/poet.song.148000.json','["遠俗何勞問，威名舊已孚。", "百城方仰澤，一節遽還都。", "聖主勤脩政，今年决破胡。", "期公寧餽輓，注想在謀謨。"]'),
('74bb8bc5-8500-499a-add1-8cdef7af1e0b','次韻芮察院送□寶文赴浙漕二首  其二','朱熹','宋','宋诗','song-poetry','','[]','考卜川清曠，端居柰樂何。',48,'全唐诗/poet.song.148000.json','["考卜川清曠，端居柰樂何。", "風雲一以便，歲月不勝多。", "節傳無淹駕，林園得屢過。", "功名從迫逐，志業豈蹉跎。"]'),
('d0581d27-4e25-4ea5-8092-5063ea92a399','挽梁文靖公二首  其一','朱熹','宋','宋诗','song-poetry','','[]','擢第初龍首，登庸再鳳池。',48,'全唐诗/poet.song.148000.json','["擢第初龍首，登庸再鳳池。", "心期詎溫飽，身任必安危。", "幾歲調娛政，今年殄瘁詩。", "恭惟衮斂意，不盡鑒亡悲。"]'),
('4c10f5f1-84bd-4409-9af6-98302ab2941f','挽梁文靖公二首  其二','朱熹','宋','宋诗','song-poetry','','[]','踈寵無前比，騰章又夙心。',48,'全唐诗/poet.song.148000.json','["踈寵無前比，騰章又夙心。", "極知求士切，端爲愛君深。", "鹵簿寒笳遠，塵埃斷藁侵。", "空令殺公掾，衰涕滿寒襟。"]'),
('adaf99d1-84d8-428d-bb7e-078f41079366','挽周侍郎二首  其一','朱熹','宋','宋诗','song-poetry','','[]','德量推容物，才猷足濟時。',48,'全唐诗/poet.song.148000.json','["德量推容物，才猷足濟時。", "陰功覃遠徼，餘算飽雄師。", "行李淹星歲，還鄉感羽儀。", "一朝成殄瘁，九牧共傷悲。"]'),
('5d3ad606-415d-4133-b499-721899034955','挽周侍郎二首  其二','朱熹','宋','宋诗','song-poetry','','[]','憶昔趨丹闕，看公上玉除。',48,'全唐诗/poet.song.148000.json','["憶昔趨丹闕，看公上玉除。", "民饑深獻納，主聖極欷歔。", "解手寒江闊，驚心夜壑虛。", "朅來空老淚，無地別輀車。"]'),
('211fb6fb-2476-4fee-8e44-8c251384dc42','挽董安人二首  其一','朱熹','宋','宋诗','song-poetry','','[]','雅望推前輩，承愛頼女師。',48,'全唐诗/poet.song.148000.json','["雅望推前輩，承愛頼女師。", "閨門傳懿範，湯沐盛恩私。", "萬里驂鸞去，千秋宰樹悲。", "自應銘婦德，誰與篆豐碑。"]'),
('e2c0523a-6bae-46f6-994a-25d83e9b06be','挽董安人二首  其二','朱熹','宋','宋诗','song-poetry','','[]','令尹古循吏，郡君今勝流。',48,'全唐诗/poet.song.148000.json','["令尹古循吏，郡君今勝流。", "平生餘事業，晚歲極熏脩。", "繐帳真成夢，靈辰竟不留。", "遺風被簫挽，未覺九泉幽。"]'),
('784177eb-0080-4ad8-afcc-75d7e64bb1da','題霜傑集','朱熹','宋','宋诗','song-poetry','','[]','先生人物魏晉間，題詩便欲傾天慳。',96,'全唐诗/poet.song.148000.json','["先生人物魏晉間，題詩便欲傾天慳。", "向來無地識眉宇，今日天遣窺波瀾。", "平生尚友陶彭澤，未肯輕爲折腰客。", "胸中合處不作難，霜下風姿自奇特。", "小儒閲閥金匱書，不滯周南滯海隅。", "枌榆連陰一見晚，何當挽袖凌空虛。"]'),
('708a3978-9975-41f8-9dc6-809f24e8fc08','謝吳公濟菖蒲','朱熹','宋','宋诗','song-poetry','','[]','翠羽紛披一尺長，带煙和雨過書堂。',32,'全唐诗/poet.song.148000.json','["翠羽紛披一尺長，带煙和雨過書堂。", "知君別有臞仙種，容易難教出洞房。"]'),
('d019132f-d71e-4ded-bf30-fdc0ec501723','易二首  其一','朱熹','宋','宋诗','song-poetry','','[]','立卦生爻事有因，兩儀四象已前陳。',32,'全唐诗/poet.song.148000.json','["立卦生爻事有因，兩儀四象已前陳。", "須知三絕韋編者，不是尋行數墨人。"]'),
('7c59ac03-ae31-4d11-8642-1363db8603a8','易二首  其二','朱熹','宋','宋诗','song-poetry','','[]','潜心雖出重爻後，著眼何妨未畫前。',32,'全唐诗/poet.song.148000.json','["潜心雖出重爻後，著眼何妨未畫前。", "識得兩儀根太極，此時方好絕韋編。"]'),
('5cd805cb-cddc-4170-9023-983a55d25d37','客來二首  其一','朱熹','宋','宋诗','song-poetry','','[]','客來何處覓紅雲，唯見風前萬點春。',32,'全唐诗/poet.song.148000.json','["客來何處覓紅雲，唯見風前萬點春。", "心賞未妨隨處好，綠楊陰裏換綸巾。"]'),
('e2e82468-5198-49ba-9314-79890362fecd','客來二首  其二','朱熹','宋','宋诗','song-poetry','','[]','悵望君家嶺上雲，便携佳友去尋春。',32,'全唐诗/poet.song.148000.json','["悵望君家嶺上雲，便携佳友去尋春。", "論詩劇飲無他意，未管殘紅落佩巾。"]'),
('60e181b9-889f-4e05-a7a2-a99bb4839171','題沈公雅卜居圖','朱熹','宋','宋诗','song-poetry','','[]','往者仲長子，高情世無儔。',132,'全唐诗/poet.song.148000.json','["往者仲長子，高情世無儔。", "一朝謝塵躅，卜築娛清幽。", "茅屋八九間，下有良田疇。", "後簷果垂實，前庭樹相樛。", "勝日賓友來，琴觴共舒憂。", "言論覈幽妙，理亂窮端由。", "至今一卷書，凜然昭千秋。", "沈侯經濟業，夙尚本林丘。", "談笑出幻境，寤言躡斯遊。", "仰睇白石崗，俯濯青瑶流。", "曠然宇宙外，邈矣將焉求。"]'),
('488a94aa-c810-45cd-9aef-273d660ce44f','武林','朱熹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春風不放桃花笑，陰雨能生客子愁。',32,'全唐诗/poet.song.148000.json','["春風不放桃花笑，陰雨能生客子愁。", "只我無心可愁得，西湖風月弄扁舟。"]'),
('1603c133-2ed6-42ea-b444-07c5ff4bff50','桐廬舟中見山寺','朱熹','宋','宋诗','song-poetry','','[]','一山雲水擁禪居，萬里江樓遶屋除。',64,'全唐诗/poet.song.148000.json','["一山雲水擁禪居，萬里江樓遶屋除。", "行色怱怱吾正爾，春風處處子何如。", "江湖此去隨漚鳥，粥飯何時共木魚。", "孤塔向人如有意，他年來借一蘧蒢。"]'),
('9c4a7664-0f0e-4d5d-8896-0bdc7745fc21','伏讀尤美軒詩卷謹賦一篇寄呈伯時季路二兄','朱熹','宋','宋诗','song-poetry','','[]','我聞洞巖幽，結友事臨眺。',96,'全唐诗/poet.song.148000.json','["我聞洞巖幽，結友事臨眺。", "浮言妨勝踐，悵望空永嘯。", "歸來眩奇語，更欲窮䆗窱。", "却尋兩翁意，宴坐得觀照。", "鳴泉俯淙琤，穹石仰蒼峭。", "共與前創古，三歎遺墨妙。", "神遊恍不隔，仁宅忻有要。", "回首鹿門期，寒雲生遠嶠。"]'),
('9f254a85-01f2-48b6-a565-3288f0995043','熹次延之年兄韻敬題紹德菴真如軒寫呈伯時季路二兄','朱熹','宋','宋诗','song-poetry','','[]','先生可是愛吾廬，來往鄰菴幾閏餘。',64,'全唐诗/poet.song.148000.json','["先生可是愛吾廬，來往鄰菴幾閏餘。", "柏下竟開千歲室，竹間猶插萬籤書。", "悲凉共識臨風處，遊戲誰知落筆初。", "寄語山靈勤守護，莫將題柱比相如。"]'),
('9f168765-62e0-4f87-8ed5-bf62b2875bd5','益公道人相見信安道溫陵舊遊出示近詩因次其韻  其一','朱熹','宋','宋诗','song-poetry','','[]','別來幾度見歸鴻，歲月悠悠一夢中。',32,'全唐诗/poet.song.148000.json','["別來幾度見歸鴻，歲月悠悠一夢中。", "莫道相望湖海闊，爭知千里不同風。"]'),
('2994c63f-a5d1-4f94-99f7-75f8abaff56b','益公道人相見信安道溫陵舊遊出示近詩因次其韻  其二','朱熹','宋','宋诗','song-poetry','','[]','一身千里伴征鴻，北去南來羈旅中。',32,'全唐诗/poet.song.148000.json','["一身千里伴征鴻，北去南來羈旅中。", "珍重故人相認得，新詩重舉舊家風。"]'),
('cf46e5ed-0bd0-4861-b266-a227e259f325','次益老韻','朱熹','宋','宋诗','song-poetry','','[]','乾坤極處無今古，道術多岐自短長。',32,'全唐诗/poet.song.148000.json','["乾坤極處無今古，道術多岐自短長。", "儻有新思還告我，不應無鴈到衡陽。"]'),
('cba79f68-0e3e-42ea-8ef8-3163e107be0d','秋日','朱熹','宋','宋诗','song-poetry','','[]','一雨生凉杜若洲，月波微漾綠溪流。',32,'全唐诗/poet.song.148000.json','["一雨生凉杜若洲，月波微漾綠溪流。", "茅簷歸去無塵土，淡薄閑花遶舍秋。"]'),
('f2cc4f84-bbad-41d4-9a4b-47252425a66b','放船二首  其一','朱熹','宋','宋诗','song-poetry','','[]','浩蕩清江水，依微綠樹風。',48,'全唐诗/poet.song.148000.json','["浩蕩清江水，依微綠樹風。", "解維春雨外，弭櫂夕陽中。", "江草生新徑，巖花點舊叢。", "詩翁不愁思，逸興莽何窮。"]'),
('0446d0ea-e806-4c5e-9b78-a0f33b21d861','放船二首  其二','朱熹','宋','宋诗','song-poetry','','[]','疇昔清溪峽，船頭戲彩翰。',48,'全唐诗/poet.song.148000.json','["疇昔清溪峽，船頭戲彩翰。", "十年空往事，一夢記前灘。", "陡絕垂蒼壁，澄虛列翠巒。", "今宵詩卷裏，重得縱遐觀。"]'),
('34ae5569-ebde-47f2-8c4b-c44ea0dd0e5f','與一維那','朱熹','宋','宋诗','song-poetry','','[]','當年事幽討，結友窮名山。',96,'全唐诗/poet.song.148000.json','["當年事幽討，結友窮名山。", "曾逢許斧子，去採玉芝還。", "歸來坐空房，神清骨毛寒。", "起視塵中人，一見了肺肝。", "探囊出刀圭，生死毫釐間。", "相逢瘴海秋，遺我黄金丹。", "高堂得聽瑩，班衣有餘歡。", "謝師無言說，古井生波瀾。"]'),
('8ef2dc93-778c-420f-b3fc-81d1bd0d6a3a','上廣文','朱熹','宋','宋诗','song-poetry','','[]','廣文何事創樓居，收拾家藏理蠹餘。',64,'全唐诗/poet.song.148000.json','["廣文何事創樓居，收拾家藏理蠹餘。", "尚有簡編充棟宇，擬陳車馬大門閭。", "移床客去邀明月，送酒人來遞異書。", "縱使清貧無長物，猶勝四壁似相如。"]'),
('188ba6d8-610c-44f3-ad8d-deb6b96f8259','考試感事戲作','朱熹','宋','宋诗','song-poetry','','[]','海邑三年吏，勤勞不爲身。',24,'全唐诗/poet.song.148000.json','["海邑三年吏，勤勞不爲身。", "但令官事了，從遣黠兒嗔。"]'),
('bd9b2c9c-6867-4b99-bb82-779f8d7f4aa1','題米倉壁','朱熹','宋','宋诗','song-poetry','','[]','度量無私本至公，寸心貪得意何窮。',32,'全唐诗/poet.song.148000.json','["度量無私本至公，寸心貪得意何窮。", "若教老子莊周見，剖斗除衡付一空。"]'),
('a42b8497-d130-4813-a1cc-050cdc31f18c','題安隠壁','朱熹','宋','宋诗','song-poetry','','[]','征車少憩林間寺，試問南枝開未開。',32,'全唐诗/poet.song.148000.json','["征車少憩林間寺，試問南枝開未開。", "日暮天寒無酒飲，不須空喚莫愁來。"]'),
('17267a78-be35-4dd1-80e8-f87fbf1c18d6','題梵天方丈壁','朱熹','宋','宋诗','song-poetry','','[]','輸盡王租生理微，野僧行乞暮還歸。',32,'全唐诗/poet.song.148000.json','["輸盡王租生理微，野僧行乞暮還歸。", "山空日落無鐘鼓，只有虛堂蝙蝠飛。"]'),
('f75bd4a4-3d46-4aac-81ac-c1260a6b640e','五月五日海上遇風雨作','朱熹','宋','宋诗','song-poetry','','[]','疾風吹雨滿征衫，陸走川行兩不堪。',32,'全唐诗/poet.song.148000.json','["疾風吹雨滿征衫，陸走川行兩不堪。", "塵事縈人心事遠，濯纓何必在江潭。"]'),
('c8f04581-34ed-4792-89b0-a9eef8324658','兩絕句送順之南歸  其一','朱熹','宋','宋诗','song-poetry','','[]','門前三徑長蒿萊，愧予慇懃千里來。',32,'全唐诗/poet.song.148000.json','["門前三徑長蒿萊，愧予慇懃千里來。", "校罷遺書却歸去，此心元自不曾灰。"]'),
('619865e2-27de-4d64-94d9-687ebcd642ef','兩絕句送順之南歸  其二','朱熹','宋','宋诗','song-poetry','','[]','幾年江海事幽尋，徧興雲僧話此心。',32,'全唐诗/poet.song.148000.json','["幾年江海事幽尋，徧興雲僧話此心。", "今日肯來論舊學，歲寒猶恐雪霜侵。"]'),
('9cb1b4d2-c772-47e5-af8e-2add7677c168','寄陳講師','朱熹','宋','宋诗','song-poetry','','[]','聞道山中客，年來鬢欲皤。',48,'全唐诗/poet.song.148000.json','["聞道山中客，年來鬢欲皤。", "靜便三徑小，貧覺一身多。", "且喜詩無病，從教睡作魔。", "故人今領衆，猶足慰蹉跎。"]'),
('c2f9b93e-7dc7-4ec7-9220-b25ca0988a25','別陳講師','朱熹','宋','宋诗','song-poetry','','[]','幾年勞夢想，今日慰登臨。',48,'全唐诗/poet.song.148000.json','["幾年勞夢想，今日慰登臨。", "况入芝蘭室，又聞金玉音。", "與君連夜語，盡我一生心。", "此外成華髮，無因得重尋。"]'),
('6e43bdee-ed6d-4e40-9a78-de02956c88a4','登閤皂山  其一','朱熹','宋','宋诗','song-poetry','','[]','疊疊層巒鎖閟宮，我來舊地訪靈蹤。',32,'全唐诗/poet.song.148000.json','["疊疊層巒鎖閟宮，我來舊地訪靈蹤。", "葛仙去後無丹竈，弟子今成白髮翁。"]'),
('839ccc31-8388-4461-b104-4e81e0f8c705','登閤皂山  其二','朱熹','宋','宋诗','song-poetry','','[]','一派泠泠臺下水，半空漠漠嶺頭雲。',32,'全唐诗/poet.song.148000.json','["一派泠泠臺下水，半空漠漠嶺頭雲。", "祖師成道沖天去，只有無窮受籙人。"]'),
('158bd589-55a9-4fee-ab70-94fb9e0cd71b','送單應之往閤山  其一','朱熹','宋','宋诗','song-poetry','','[]','杖頭挑月入烟蘿，城郭塵埃柰爾何。',32,'全唐诗/poet.song.148000.json','["杖頭挑月入烟蘿，城郭塵埃柰爾何。", "若到名山高著眼，洞天深處異人多。"]'),
('15a9947d-a064-47ff-b771-d26d1c4ea4d8','送單應之往閤山  其二','朱熹','宋','宋诗','song-poetry','','[]','回首名山我舊遊，曾將風袂挹浮丘。',32,'全唐诗/poet.song.148000.json','["回首名山我舊遊，曾將風袂挹浮丘。", "如今不及臺邊水，長向山前山後流。"]'),
('c4d2f4c1-7564-4c68-ab48-4198c524d622','送李道士歸玉笥三首  其一','朱熹','宋','宋诗','song-poetry','','[]','偶隨雲去伴雲歸，笑指清都在翠微。',32,'全唐诗/poet.song.148000.json','["偶隨雲去伴雲歸，笑指清都在翠微。", "爲我中間留一榻，他年去著薜蘿衣。"]'),
('3e7b21c5-2cb3-4eae-bd79-e13d0e72d1d9','送李道士歸玉笥三首  其二','朱熹','宋','宋诗','song-poetry','','[]','玉笥山連都水坑，拂雲樓殿對崢嶸。',32,'全唐诗/poet.song.148000.json','["玉笥山連都水坑，拂雲樓殿對崢嶸。", "君歸後夜無餘事，卧聽寒泉落澗聲。"]'),
('84c587e1-d6ac-408e-a88f-126219ea8b2d','送李道士歸玉笥三首  其三','朱熹','宋','宋诗','song-poetry','','[]','莫惜臨行酒一杯，看君上馬古城隈。',32,'全唐诗/poet.song.148000.json','["莫惜臨行酒一杯，看君上馬古城隈。", "相望兩地無多遠，頻寄音書與鴈來。"]'),
('7e62fce7-c0f2-4e38-990b-d961097c734a','題赤城觀','朱熹','宋','宋诗','song-poetry','','[]','落日空山秋氣清，泠泠古木亂蟬鳴。',64,'全唐诗/poet.song.148000.json','["落日空山秋氣清，泠泠古木亂蟬鳴。", "僊人一去鶴不返，劍客重來丹已成。", "靜對竹爐烟縷直，細看月窟桂華生。", "此身舊有蓬瀛約，玉簡歸來問姓名。"]'),
('eddc676f-efe4-4a2e-b548-4d66a6aacc87','尤溪縣學觀大閣','朱熹','宋','宋诗','song-poetry','','[]','令尹絃歌不下堂，叱嗟層觀麗扶桑。',64,'全唐诗/poet.song.148000.json','["令尹絃歌不下堂，叱嗟層觀麗扶桑。", "朱甍碧瓦臨無地，散帙投壺樂未央。", "得意溪山供徙倚，忘情魚鳥共徜徉。", "應觀物我同根處，剖破藩籬即大方。"]'),
('2393f1b6-aba1-4916-af76-7fa2e12dc02b','十月上休日遊卧龍玉淵三峽用山谷驚鹿須要野學盟鷗本願秋江分韻得鷗字','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬霜天後，不見雲氣浮。',228,'全唐诗/poet.song.148000.json','["匡廬霜天後，不見雲氣浮。", "木葉紅已踈，山顔轉清幽。", "向聞有絕壑，乃在卧龍湫。", "及此遂一徃，幸無烟景愁。", "隮攀欲其深，泉石固所求。", "况有百尺崖，噴雪飛寒流。", "幽岑自回抱，直下鳴青璆。", "便可洗我耳，枕石忘所憂。", "精神共虛廓，方物皆悠悠。", "所恨非獨往，不能恣夷猶。", "仰歎雲間鶴，俯羨谷中鷗。", "先生先我來，結屋陽岡頭。", "虛名付忠武，滅迹慕巢由。", "是間頗足居，不田亦平疇。", "野人種椒橘，崖蜜易歲收。", "西源有老翁，卷舌藏戈矛。", "似學辟世士，乃欲邀聖丘。", "先生且無然，但作一月留。", "俟我有决計，它時卜從游。"]'),
('7daea013-91e6-4db5-aac8-f6b4ee1c22a7','次周師溫遊書堂韻兼簡坐上諸同志','朱熹','宋','宋诗','song-poetry','','[]','疇昔因來行水餘，依依唯認昔人居。',64,'全唐诗/poet.song.148000.json','["疇昔因來行水餘，依依唯認昔人居。", "新堂已幸經重構，舊事難追更特書。", "所願絃歌聞十室，休誇文字賦三都。", "同來况有濂溪裔，心印相傳儘未踈。"]'),
('aaf5a33b-4dbc-401a-a8f2-52a3cb6640b8','西源居士斸寄秋蘭小詩爲謝','朱熹','宋','宋诗','song-poetry','','[]','知有幽芳近水開，故攀危磴斸蒼苔。',32,'全唐诗/poet.song.148000.json','["知有幽芳近水開，故攀危磴斸蒼苔。", "却憐病客空齋冷，带雨和煙遠寄來。"]'),
('19ad1317-4e0f-4c7b-a880-99f29c984c7c','渡興樂江望祝融次擇之韻','朱熹','宋','宋诗','song-poetry','','[]','江頭曉渡野雲遮，惆望山岐映暮霞。',32,'全唐诗/poet.song.148000.json','["江頭曉渡野雲遮，惆望山岐映暮霞。", "人值風波幾千里，濟川舟楫我儂誇。"]'),
('85bbdd44-d551-4194-89ea-65bf89a7370c','嶽後步月','朱熹','宋','宋诗','song-poetry','','[]','清光冰魄浩無邊，桂影扶疏吐玉娟。',32,'全唐诗/poet.song.148000.json','["清光冰魄浩無邊，桂影扶疏吐玉娟。", "人在峰頭遥指望，舉杯對影夜無眠。"]'),
('6c486991-0fa7-48cc-9451-3c995410fb73','自上封下福巖道傍訪李鄴侯書堂山路榛合不可往矣遂賦  其一','朱熹','宋','宋诗','song-poetry','','[]','此。',2,'全唐诗/poet.song.148000.json','["此。"]'),
('d8c54216-ca9d-49a8-a21e-b4886c2f6559','自上封下福巖道傍訪李鄴侯書堂山路榛合不可往矣遂賦  其二','朱熹','宋','宋诗','song-poetry','','[]','山道榛蕪大道荒，令人瞻望鄴侯堂。',32,'全唐诗/poet.song.148000.json','["山道榛蕪大道荒，令人瞻望鄴侯堂。", "懷賢空白悲今昔，淚滴西風恨夕陽。"]'),
('e586359f-0c04-4df0-8e39-3b23b23d1ea5','題南臺','朱熹','宋','宋诗','song-poetry','','[]','步入招提境，雲間有古臺。',48,'全唐诗/poet.song.148000.json','["步入招提境，雲間有古臺。", "管絃山鳥弄，瓊玖雪花開。", "方外人稀到，山頭勢更巍。", "登臨思不盡，何日再重來。"]'),
('775df923-8d5d-4326-a72e-109286950739','將下山有作','朱熹','宋','宋诗','song-poetry','','[]','芒鞋踏破萬重山，五日淹留在此間。',32,'全唐诗/poet.song.148000.json','["芒鞋踏破萬重山，五日淹留在此間。", "行客歸來山下望，却疑身自九天還。"]'),
('76dfe129-e8e4-427b-99cd-6008ddc67462','和王晦叔寄德瑩弟韻  其一','朱熹','宋','宋诗','song-poetry','','[]','聞道君歸湘水東，經行長在白雲中。',64,'全唐诗/poet.song.148000.json','["聞道君歸湘水東，經行長在白雲中。", "詩成天柱峰頭月，酒醒朱陵洞裏風。", "舊學難酬香一瓣，流年誰管鬢雙蓬。", "書來爲指誵誤處，不涉言詮不落空。"]'),
('913ec91d-9c25-480d-8ab5-7c4cf7f880f1','和王晦叔寄德瑩弟韻  其二','朱熹','宋','宋诗','song-poetry','','[]','試上閩山望楚天，雁飛欲斷勢還連。',64,'全唐诗/poet.song.148000.json','["試上閩山望楚天，雁飛欲斷勢還連。", "憑將袖裏數行字，與問雲間雙髻仙。", "我訪舊游經有日，君歸故里定何年。", "祇今心事同千里，靜對簞瓢獨喟然。"]'),
('f339cb14-c60a-4169-9799-db04b3f30704','詠紅白蓮','朱熹','宋','宋诗','song-poetry','','[]','紅白蓮花共一塘，兩般顔色一般香。',32,'全唐诗/poet.song.148000.json','["紅白蓮花共一塘，兩般顔色一般香。", "宮娥梳洗爭先後，半是濃粧半淡粧。"]'),
('90c5a8ce-12f6-4e4e-93e6-aa80fec1a65a','梅二首  其一','朱熹','宋','宋诗','song-poetry','','[]','莫遣扁舟興盡回，正須衝雪看江梅。',32,'全唐诗/poet.song.148000.json','["莫遣扁舟興盡回，正須衝雪看江梅。", "楚人元未知真色，施粉何曾太白來。"]'),
('6a1f3bb6-4a29-40e0-97f3-1e6d3b01d19a','梅二首  其二','朱熹','宋','宋诗','song-poetry','','[]','幽香淡淡影疎疎，雪虐風威亦自如。',32,'全唐诗/poet.song.148000.json','["幽香淡淡影疎疎，雪虐風威亦自如。", "正是花中巢許輩，人間富貴不關渠。"]'),
('619f88f8-9dfc-4a23-aec5-8c3b95c31e8a','謁二徐先生墓','朱熹','宋','宋诗','song-poetry','','[]','道學傳千古，東甌說二徐。',48,'全唐诗/poet.song.148000.json','["道學傳千古，東甌說二徐。", "門清一壺水，家富五車書。", "但喜青氊在，何憂白屋居。", "我懷人已遠，揮淚表丘墟。"]'),
('ae4aeddf-9e2f-4aa8-aaab-7d4c4c6d19cf','贈內弟程允夫三首  其一','朱熹','宋','宋诗','song-poetry','','[]','外家人物有吾子，我乃平生未見嘗。',32,'全唐诗/poet.song.148000.json','["外家人物有吾子，我乃平生未見嘗。", "文字只今多可喜，江湖他日莫相忘。"]'),
('c36252b7-e7fd-410a-9ad7-0e4be277aaf3','贈內弟程允夫三首  其二','朱熹','宋','宋诗','song-poetry','','[]','故家歸來雲樹長，向來辛苦夢家鄉。',32,'全唐诗/poet.song.148000.json','["故家歸來雲樹長，向來辛苦夢家鄉。", "行藏正爾未堅快，又見春風登俊良。"]'),
('9c2f544b-f0d7-4eaf-bd63-e78be22fab28','贈內弟程允夫三首  其三','朱熹','宋','宋诗','song-poetry','','[]','我憶當年諸老翁，經綸事業久參同。',32,'全唐诗/poet.song.148000.json','["我憶當年諸老翁，經綸事業久參同。", "只今零落三星曉，未厭棲遲一畝宮。"]'),
('65c8e4c7-bacf-48fe-8cb2-4ec7638f422c','秋日成詩','朱熹','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u4eba\u751f", "\u54f2\u7406"]','閑來無事不從容，睡覺東窗日已紅。',64,'全唐诗/poet.song.148000.json','["閑來無事不從容，睡覺東窗日已紅。", "萬物靜觀皆自得，四時佳興與人同。", "道通天地有形外，思入風雲變態中。", "富貴不淫貧賤樂，男兒到此是豪雄。"]'),
('6db91415-8a70-442f-b4a0-87249fc27166','竹','朱熹','宋','宋诗','song-poetry','','[]','瀟瀟凌霜雪，濃翠異三湘。',24,'全唐诗/poet.song.148000.json','["瀟瀟凌霜雪，濃翠異三湘。", "疎影月移壁，寒聲風滿堂。"]'),
('ed20ebab-197d-4a28-a475-cab2e816d781','題魏府藏趙公飲器','朱熹','宋','宋诗','song-poetry','','[]','趙公飲器魏府藏，我思兩公愛甘棠。',32,'全唐诗/poet.song.148000.json','["趙公飲器魏府藏，我思兩公愛甘棠。", "惟魏子孫實無斁，敬奉其盈如升克。"]'),
('e1f7c0c9-b9b8-4319-b28c-03fa0769dc7c','贈劉虛谷','朱熹','宋','宋诗','song-poetry','','[]','細讀還丹一百篇，先生信筆亦多言。',64,'全唐诗/poet.song.148000.json','["細讀還丹一百篇，先生信筆亦多言。", "玄機謾向經書覓，至理端於目睫存。", "二馬果能爲我馭，五芽應自長家園。", "明朝駕鶴登山去，此話更從誰與論。"]'),
('7b28045a-6ab4-4b5d-b049-9bf8e8301233','贈傅得一','朱熹','宋','宋诗','song-poetry','','[]','到處逢人說傅顛，相看知是幾生前。',32,'全唐诗/poet.song.148000.json','["到處逢人說傅顛，相看知是幾生前。", "直携北斗傾天漢，去年龍宮第二仙。"]'),
('29512ed8-bce3-4fa1-8b79-f7533490978a','追和李士舉徐氏山居韻','朱熹','宋','宋诗','song-poetry','','[]','山岫孤雲意自閑，不妨王事似連環。',32,'全唐诗/poet.song.148000.json','["山岫孤雲意自閑，不妨王事似連環。", "解鞍盤礴忘歸去，碧澗修筠似故山。"]'),
('5ca53538-95f5-4265-846b-c26a31cf1421','挽崔嘉彥二首  其一','朱熹','宋','宋诗','song-poetry','','[]','關陝遺耆老，天資得勇多。',48,'全唐诗/poet.song.148000.json','["關陝遺耆老，天資得勇多。", "雙瞳光射日，寸舌辯傾河。", "居俯三江近，鄰從五老過。", "廬空人不見，猿鶴奈愁何。"]'),
('10953550-c7a4-454b-b754-7beea9952104','挽崔嘉彥二首  其二','朱熹','宋','宋诗','song-poetry','','[]','林下相從舊，回頭一十年。',48,'全唐诗/poet.song.148000.json','["林下相從舊，回頭一十年。", "君論金鼎訣，我賦白雲篇。", "泉石無閑意，丹砂結世緣。", "康山空葬骨，已作洞中仙。"]'),
('1ce7a271-a458-4e47-b3a9-53bb705df473','紅梅','朱熹','宋','宋诗','song-poetry','','[]','似桃非桃杏非杏，獨與江梅相早晚。',64,'全唐诗/poet.song.148000.json','["似桃非桃杏非杏，獨與江梅相早晚。", "天姿約略带春酲，便覺花容太柔婉。", "霞觴瀲艷玉妃醉，應誤劉郎來閬苑。", "會須參作比紅詩，莫學牆頭等閑見。"]'),
('1f80a9fb-1a45-460a-bb2e-930afb0dae79','春日過上天竺','朱熹','宋','宋诗','song-poetry','','[]','竺國古招提，飛甍碧瓦齊。',48,'全唐诗/poet.song.148000.json','["竺國古招提，飛甍碧瓦齊。", "林深忘日午，山迥覺天低。", "琪樹殊方色，珍禽別院啼。", "沙門有文暢，啜茗漫留題。"]'),
('12447e8c-62b9-443f-b0f3-6fbf3976cdf1','淳熙戊戌七月廿九日早發潭溪西登雲谷取道芹溪友人丘子野留宿因題芹溪小隠以貽之作此以紀其事','朱熹','宋','宋诗','song-poetry','','[]','我來屏山下，奔走倦僮僕。',180,'全唐诗/poet.song.148000.json','["我來屏山下，奔走倦僮僕。", "亭亭日已中，冠中濕如沐。", "訪我芹溪翁，解裝留憩宿。", "茗碗瀹甘寒，溫泉試新浴。", "抖擻神氣清，散步搘筇竹。", "蘆峰在瞻望，隠隠見雲谷。", "頓覺塵慮空，豁然洗心目。", "君居峴山西，高隠志不俗。", "窗几列琴書，庭皋富花木。", "往來數相過，主賓情意熟。", "開樽酌香醪，謦欬話衷曲。", "從容出妙句，滿幅粲珠玉。", "邀約登赫曦，襟期伴幽獨。", "茲遊得良朋，道義推前夙。", "扁字爲留題，深愧毛錐禿。"]'),
('0da85124-0d73-44f7-8737-432ccdb062ac','華蓋石','朱熹','宋','宋诗','song-poetry','','[]','醉扶藜杖少盤桓，四遠烟蘿手自捫。',32,'全唐诗/poet.song.148000.json','["醉扶藜杖少盤桓，四遠烟蘿手自捫。", "此石至今無處問，祇因來自太微垣。"]'),
('efc60380-c6d2-4467-b71b-2c56bc375ea8','昭德源','朱熹','宋','宋诗','song-poetry','','[]','景幽人蹟少，惟有此源長。',48,'全唐诗/poet.song.148000.json','["景幽人蹟少，惟有此源長。", "水接天池綠，花分繡谷香。", "僧閑多老大，寺古半荒凉。", "却怪尋山客，何由到上方。"]'),
('7ceb1b08-bc9f-498f-810f-27825391d09e','廬山雙劍峰二首  其一','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山神呵護寶雲遮，儼若騰空兩鏌鋣。',32,'全唐诗/poet.song.148000.json','["山神呵護寶雲遮，儼若騰空兩鏌鋣。", "光彩飛名鎮千古，望中肝膽落奸邪。"]'),
('6e4f3fbc-91c1-4ad3-9f5b-0a9360c2799c','廬山雙劍峰二首  其二','朱熹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雙劍峰高削玉成，芒寒色淬曉霜清。',32,'全唐诗/poet.song.148000.json','["雙劍峰高削玉成，芒寒色淬曉霜清。", "腦脂壓眼人高卧，誰斬天驕致太平。"]'),
('25210a84-f6a3-44fc-9551-7e17145eb6a5','鶴鳴峰','朱熹','宋','宋诗','song-poetry','','[]','不見山頭夜鶴鳴，空遺山下瀑泉聲。',32,'全唐诗/poet.song.148000.json','["不見山頭夜鶴鳴，空遺山下瀑泉聲。", "野人惆悵空無寐，一曲瑶琴分外清。"]'),
('9ae1a54e-b04d-40d0-a606-2dc8faf0fb18','獅子峰','朱熹','宋','宋诗','song-poetry','','[]','石骨苔衣雖賦形，蹲空獨逞忒猙獰。',32,'全唐诗/poet.song.148000.json','["石骨苔衣雖賦形，蹲空獨逞忒猙獰。", "威尊百獸終何用，寧解當年吼一聲。"]'),
('ca8285bc-3640-4902-8e56-0c2f7a5f0cd9','登福山遠眺','朱熹','宋','宋诗','song-poetry','','[]','迢迢百里外，望望皆閩山。',24,'全唐诗/poet.song.148000.json','["迢迢百里外，望望皆閩山。", "皎日中天揭，浮雲也有閑。"]'),
('c59dfeab-7f7b-4e55-8a97-ef87829afdc5','次牧馬侯廟','朱熹','宋','宋诗','song-poetry','','[]','此日觀風海上馳，殷勤父老遠相隨。',64,'全唐诗/poet.song.148000.json','["此日觀風海上馳，殷勤父老遠相隨。", "野饒稻黍輸王賦，地接扶桑擁帝基。", "雲樹葱蘢神女寶，崗巒連搶聖侯祠。", "黄昏更上豐山望，四際天光蘸碧漪。"]'),
('385a0fbe-1a7a-4d89-a909-37bc00930aff','何君飛仙','朱熹','宋','宋诗','song-poetry','','[]','大地何人鑿小空，翛然一榻卧相容。',64,'全唐诗/poet.song.148000.json','["大地何人鑿小空，翛然一榻卧相容。", "巨靈擘破三千丈，西竺飛來第二峰。", "出洞風來疑有虎，藏舟夜半忽乘龍。", "怪來索我題詩句，稽首何君六石供。"]'),
('f591416c-c496-4cd6-86be-72d529cfe0f1','崇真觀','朱熹','宋','宋诗','song-poetry','','[]','磴道千尋風滿林，洞門無鎖下秋蔭。',64,'全唐诗/poet.song.148000.json','["磴道千尋風滿林，洞門無鎖下秋蔭。", "紫臺鳳去天關遠，丹井龍歸地軸深。", "野老尋真渾有意，道人謝客亦何心。", "一樽底處酬佳節，俯仰山林慨古今。"]'),
('66fa3e5a-b183-4ceb-ac15-93c77a2910ac','北雙劍峰','朱熹','宋','宋诗','song-poetry','','[]','雙劍名峰也逼真，品題拍拍滿懷春。',32,'全唐诗/poet.song.148000.json','["雙劍名峰也逼真，品題拍拍滿懷春。", "鉛刀自別干將利，折檻應須表直臣。"]'),
('c4bf6251-fc58-406e-b9a5-c0558aa62834','夜宿洪亭長家','朱熹','宋','宋诗','song-poetry','','[]','纔到秋來氣便高，雁聲天地總寥寥。',32,'全唐诗/poet.song.148000.json','["纔到秋來氣便高，雁聲天地總寥寥。", "客懷今夜不成寐，風細月明江自潮。"]'),
('1f030829-001c-47cb-ab81-070e6714e583','對菊','朱熹','宋','宋诗','song-poetry','','[]','解印歸來嘆寂寥，黄花難覓舊根苗。',32,'全唐诗/poet.song.148000.json','["解印歸來嘆寂寥，黄花難覓舊根苗。", "祇緣三徑荒凉後，移向洪門不姓陶。"]'),
('67693fe6-e347-49d8-8e01-e365c293069f','題東嶼書房','朱熹','宋','宋诗','song-poetry','','[]','書房在東嶼，編簡亂抽尋。',48,'全唐诗/poet.song.148000.json','["書房在東嶼，編簡亂抽尋。", "曙色千山曉，寒燈午夜深。", "江湖勤會面，坐卧獨觀心。", "秋浦瓜期近，何當寄此吟。"]'),
('45be0da5-d528-442f-8d37-ae8f010c97db','題陶淵明小像','朱熹','宋','宋诗','song-poetry','','[]','慧遠無此冠，靖節無此巾。',24,'全唐诗/poet.song.148000.json','["慧遠無此冠，靖節無此巾。", "此巾要亦有，無此漉酒人。"]'),
('ada256e9-9254-49bd-a441-36ed603caec0','芹溪九曲詩  其一','朱熹','宋','宋诗','song-poetry','','[]','一曲移舟采澗芹，市聲只隔一江雲。',32,'全唐诗/poet.song.148000.json','["一曲移舟采澗芹，市聲只隔一江雲。", "沙頭喚渡人歸晚，回首蘆峰月一輪。"]'),
('d0d1c4a2-9d4c-4ec7-bc94-6fc3e9e1160a','芹溪九曲詩  其二','朱熹','宋','宋诗','song-poetry','','[]','二曲溪邊萬木林，水環竹石四時清。',32,'全唐诗/poet.song.148000.json','["二曲溪邊萬木林，水環竹石四時清。", "漁歌櫂入斜陽裏，隔岸時聞一兩聲。"]'),
('366cd8ac-c6c3-4ed3-90d7-094db2aef03c','芹溪九曲詩  其三','朱熹','宋','宋诗','song-poetry','','[]','三曲舟行龍尾灘，推蓬把酒見南山。',32,'全唐诗/poet.song.148000.json','["三曲舟行龍尾灘，推蓬把酒見南山。", "回頭點檢仙蹤跡，萬頃白雲時自閑。"]'),
('e9eb6b02-d699-4227-b8ab-b87be0b39a68','芹溪九曲詩  其四','朱熹','宋','宋诗','song-poetry','','[]','四曲煙雲鎖小樓，寺臨喬木古溪頭。',32,'全唐诗/poet.song.148000.json','["四曲煙雲鎖小樓，寺臨喬木古溪頭。", "僧歸林下柴門靜，麋鹿啣花自在遊。"]'),
('313cdbd9-5346-49bc-ba13-62c11ae719cc','芹溪九曲詩  其五','朱熹','宋','宋诗','song-poetry','','[]','五曲峰巒列翠屏，白雲深處隠仙亭。',32,'全唐诗/poet.song.148000.json','["五曲峰巒列翠屏，白雲深處隠仙亭。", "子期一去無消息，惟有喬松萬古清。"]'),
('f9a72232-cf24-41ca-a76b-1c695a1a8be4','芹溪九曲詩  其六','朱熹','宋','宋诗','song-poetry','','[]','六曲溪環處士家，鼓樓樓下樹槎枒。',32,'全唐诗/poet.song.148000.json','["六曲溪環處士家，鼓樓樓下樹槎枒。", "龍去潭空名不朽，惟見平汀湧白沙。"]'),
('8b86acf7-223d-4c99-93ae-f1c7856545b8','芹溪九曲詩  其七','朱熹','宋','宋诗','song-poetry','','[]','七曲靈祠近水濱，聚魚石上躍金鱗。',32,'全唐诗/poet.song.148000.json','["七曲靈祠近水濱，聚魚石上躍金鱗。", "林凹路入桃源近，時有漁郎來問津。"]'),
('2730920c-7630-4ba2-937e-9e8d90106a18','芹溪九曲詩  其八','朱熹','宋','宋诗','song-poetry','','[]','八曲硯峰倚碧虛，泉流瀑布世間無。',32,'全唐诗/poet.song.148000.json','["八曲硯峰倚碧虛，泉流瀑布世間無。", "憑誰染就丹青筆，寫出芹溪九曲圖。"]'),
('e860c6b4-1329-4d8b-9f77-adb6cf274342','芹溪九曲詩  其九','朱熹','宋','宋诗','song-poetry','','[]','九曲悠悠景最幽，巉巖峽石束寒流。',32,'全唐诗/poet.song.148000.json','["九曲悠悠景最幽，巉巖峽石束寒流。", "源深自是舟難到，更有龍池在上頭。"]'),
('63f85025-b4a0-4f1e-b4b9-11c39781dc04','廌山書院','朱熹','宋','宋诗','song-poetry','','[]','三十年來宿草廬，五年三第世間無。',32,'全唐诗/poet.song.148000.json','["三十年來宿草廬，五年三第世間無。", "門前獬廌山常在，只恐兒孫不讀書。"]'),
('f101d0fe-43ab-40c2-b506-39ac6bdd2fee','小均四景詩  其一','朱熹','宋','宋诗','song-poetry','','[]','曉起坐書齋，落花堆滿徑。',24,'全唐诗/poet.song.148000.json','["曉起坐書齋，落花堆滿徑。", "只此是文章，揮毫有餘興。"]'),
('0df31963-5b64-484d-ab18-f7ee1c4ab876','小均四景詩  其二','朱熹','宋','宋诗','song-poetry','','[]','古木被高蔭，晝坐不知暑。',24,'全唐诗/poet.song.148000.json','["古木被高蔭，晝坐不知暑。", "會得古人心，開襟靜無語。"]'),
('e369c55e-b571-4004-ab09-68924e20c02b','小均四景詩  其三','朱熹','宋','宋诗','song-poetry','','[]','蟋蟀鳴牀頭，夜眠不成寐。',24,'全唐诗/poet.song.148000.json','["蟋蟀鳴牀頭，夜眠不成寐。", "起閲案前書，西風拂庭桂。"]'),
('d1f36922-49ed-4ddf-9310-953d5667f99a','小均四景詩  其四','朱熹','宋','宋诗','song-poetry','','[]','瑞雪飛瓊瑶，梅花靜相倚。',24,'全唐诗/poet.song.148000.json','["瑞雪飛瓊瑶，梅花靜相倚。", "獨占三春魁，深涵太極理。"]'),
('8b4461b2-58b9-470f-bdd2-2b054b8dd992','水濂洞','朱熹','宋','宋诗','song-poetry','','[]','水濂幽谷我來遊，拂面飛泉最醒眸。',32,'全唐诗/poet.song.148000.json','["水濂幽谷我來遊，拂面飛泉最醒眸。", "一片水簾遮洞口，何人捲得上簾鈎。"]'),
('55415dc2-502d-4bb8-82b5-aa09d893eced','寄石斗文','朱熹','宋','宋诗','song-poetry','','[]','病枕經年卧沃洲，滿庭楓葉又吟秋。',64,'全唐诗/poet.song.148000.json','["病枕經年卧沃洲，滿庭楓葉又吟秋。", "書來如見舊人面，讀了還見塵世愁。", "憂國至今遺白髮，窮經空自愧前修。", "武夷休作相思夢，我已甘心老此丘。"]'),
('abc8bcea-9ebe-423e-be6a-b38a8746321f','題清虛庵來月軒','朱熹','宋','宋诗','song-poetry','','[]','夜吟唯覺月來遲，正憶先生獨坐時。',32,'全唐诗/poet.song.148000.json','["夜吟唯覺月來遲，正憶先生獨坐時。", "離緒幾多無著處，不堪清氣入詩脾。"]'),
('0c902eb7-487d-42b8-88b4-aba3ce86c3a7','曇山題詩','朱熹','宋','宋诗','song-poetry','','[]','頹然見此山，一一皆天作。',24,'全唐诗/poet.song.148000.json','["頹然見此山，一一皆天作。", "信手銘巖牆，所願君不鑿。"]'),
('a39e4baa-3006-4d7d-abc7-c4614c18efc7','題米敷文瀟湘圖卷','朱熹','宋','宋诗','song-poetry','','[]','閑雲無四時，散漫此山谷。',24,'全唐诗/poet.song.148000.json','["閑雲無四時，散漫此山谷。", "幸乏霖雨姿，何妨媚幽獨。"]'),
('63e05fac-ffcb-431f-8b24-f5599135b825','跋睢陽五老圖卷','朱熹','宋','宋诗','song-poetry','','[]','同支派別胄遥遥，南渡衣冠尚北朝。',64,'全唐诗/poet.song.148000.json','["同支派別胄遥遥，南渡衣冠尚北朝。", "千載圖畫文獻在，兩朝開濟政明昭。", "公卿倡和遵皇運，嗣子傳家念祖饒。", "幸得慶源流自遠，匡扶人世釋塵囂。"]'),
('d7a21d94-6e41-40a3-ba38-18679c422f38','方池','朱熹','宋','宋诗','song-poetry','','[]','武夷之境多神僊，我亦駐此臨風軒。',112,'全唐诗/poet.song.148000.json','["武夷之境多神僊，我亦駐此臨風軒。", "方池清夜墮碧玉，重簾白日垂洞門。", "暗泉湧地紫波動，微雨在藻金魚翻。", "倚檻照影清見底，拄杖卓石尋無源。", "洗頭玉女去不返，遺此丈八芙蓉盤。", "溪船明月泛九曲，出入紫微聽潺湲。", "便欲此地覓真隠，何必商山求綺園。"]'),
('0cdffdd1-1071-4fb9-84cb-696460124495','山茶','朱熹','宋','宋诗','song-poetry','','[]','江南池館厭深紅，零落荒煙山雨中。',32,'全唐诗/poet.song.148000.json','["江南池館厭深紅，零落荒煙山雨中。", "却是北人偏愛惜，數枝和雪上屏風。"]'),
('63174523-bec5-4bb0-94fb-5ff282df7176','廓然亭','朱熹','宋','宋诗','song-poetry','','[]','遲留訪隠古祠旁，眼底樛松老更蒼。',32,'全唐诗/poet.song.148000.json','["遲留訪隠古祠旁，眼底樛松老更蒼。", "山得吾儕應改觀，坐無惡客自生凉。"]'),
('641c2475-3e2b-44af-ad7e-394f292af8a6','遊會稽東山','朱熹','宋','宋诗','song-poetry','','[]','江路經由數十回，無因到此爲潮催。',64,'全唐诗/poet.song.148000.json','["江路經由數十回，無因到此爲潮催。", "嘗聆文靖曾遊後，欲問薔薇幾度開。", "今日掣身推案去，暫時秉燭入山來。", "高僧不問誰家客，獨計雲軒自把懷。"]'),
('68ffa1b9-003a-41ae-9b86-e2207857e6dc','題程燁程燧兄弟雙桂書院','朱熹','宋','宋诗','song-poetry','','[]','君家構屋積玉堆，兩種天香手自栽。',32,'全唐诗/poet.song.148000.json','["君家構屋積玉堆，兩種天香手自栽。", "清影一簾秋澹蕩，任渠艷冶斗春開。"]'),
('c118aa9a-0fa1-41a1-8816-e8e4bb2c9187','豐城榮光書院','朱熹','宋','宋诗','song-poetry','','[]','一道榮光带碧山，天風吹雨渡雲關。',64,'全唐诗/poet.song.148000.json','["一道榮光带碧山，天風吹雨渡雲關。", "樹浮空翠迷村塢，泉落飛虹瀉石灣。", "赤嶺豹栖朝氣隠，劍潭龍起夜光寒。", "咿唔何處經年韻，多在湖東喬木間。"]'),
('9076976b-f67b-4f69-b7b5-143713867965','隆岡書院四景詩  其一','朱熹','宋','宋诗','song-poetry','','[]','卜築隆岡遠市朝，個中風景總堪描。',64,'全唐诗/poet.song.148000.json','["卜築隆岡遠市朝，個中風景總堪描。", "溪雲带雨來茅屋，澗水浮花出石橋。", "綠遍莎汀牛腹飽，青歸麥壠鳥聲嬌。", "東鄰西舍渾相似，半是漁入半是樵。"]'),
('d617eada-01c4-4593-9614-70478cfe5890','隆岡書院四景詩  其二','朱熹','宋','宋诗','song-poetry','','[]','簾捲薰風半掩扉，五侯車馬往來稀。',64,'全唐诗/poet.song.148000.json','["簾捲薰風半掩扉，五侯車馬往來稀。", "綠楊門巷鶑鶑語，青草池塘燕燕飛。", "掃石圍棋銷白晝，解衣沽酒醉斜暉。", "山園莫道多寥落，梅子初黄杏子肥。"]'),
('5b2a69cf-34d8-4cb3-9d8b-294e3c5210ce','隆岡書院四景詩  其三','朱熹','宋','宋诗','song-poetry','','[]','水繞荒村竹繞牆，儼然風景似柴桑。',64,'全唐诗/poet.song.148000.json','["水繞荒村竹繞牆，儼然風景似柴桑。", "車繅白雪絲盈軸，銍刈黄雲稻滿場。", "幾樹斜暉楓葉赤，一籬疏雨菊花黄。", "東鄰畫鼓西鄰笛，共慶豐年樂有常。"]'),
('e8890252-c5d8-46f4-a9b1-4e5fe015685c','隆岡書院四景詩  其四','朱熹','宋','宋诗','song-poetry','','[]','土築低牆草結庵，尋常愛客伴清談。',64,'全唐诗/poet.song.148000.json','["土築低牆草結庵，尋常愛客伴清談。", "地爐有火湯初沸，布被無寒夢亦酣。", "風卷翠松鳴晚笛，雪飄疏竹響春蠶。", "閉門不管榮枯事，坐傍梅花讀二南。"]'),
('1c533ede-d699-4022-be3c-cd8b0e4fb882','德興縣葉元愷家題','朱熹','宋','宋诗','song-poetry','','[]','葱湯麥飯兩相宜，葱暖丹田麥療饑。',32,'全唐诗/poet.song.148000.json','["葱湯麥飯兩相宜，葱暖丹田麥療饑。", "莫道儒家風味薄，隔鄰猶有未炊時。"]'),
('3615f694-bcf9-44bb-b6d8-a543b1e2b0bf','過飛泉嶺','朱熹','宋','宋诗','song-poetry','','[]','梯雲石磴羊腸繞，轉壑飛泉碧玉斜。',32,'全唐诗/poet.song.148000.json','["梯雲石磴羊腸繞，轉壑飛泉碧玉斜。", "一路風烟春淡泊，數聲鷄犬野人家。"]'),
('29ed52d7-785d-41f2-9308-781bb0782fe7','遊靈石','朱熹','宋','宋诗','song-poetry','','[]','百尺樓臺九疊山，個中風景脫塵寰。',64,'全唐诗/poet.song.148000.json','["百尺樓臺九疊山，個中風景脫塵寰。", "危亭勢枕蒼霞古，靈石香沾碧蘚斑。", "佳景每因勞企仰，勝遊未及費躋攀。", "何當酬却詩書債，遂我浮生半日閑。"]'),
('f7ca469c-2470-4ffe-a0a1-1fdc386055a9','岱山巖訪陳世德光同年','朱熹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','一錢一劍出新州，五柳憑誰添酒籌。',64,'全唐诗/poet.song.148000.json','["一錢一劍出新州，五柳憑誰添酒籌。", "岱壑何嫌松共老，碧波偏向桂招遊。", "不爲身後百年計，自是人間第一流。", "我欲門前張雀網，先將車轍到山頭。"]'),
('86bbb3f4-9582-4de6-8240-990d0984ac04','右軍宅','朱熹','宋','宋诗','song-poetry','','[]','因山盛起浮屠舍，遺像仍留內史祠。',64,'全唐诗/poet.song.148000.json','["因山盛起浮屠舍，遺像仍留內史祠。", "筆冢近應爲塔冢，墨池今已化蓮池。", "書樓觀在人隨遠，蘭渚亭存世幾移。", "數紙黄庭誰不重，退之猶笑博鵝時。"]'),
('998f23c3-bc62-4531-b642-cc6b3a8d9e24','送汪大猷歸里','朱熹','宋','宋诗','song-poetry','','[]','濯濯才華耀禁林，翩然忽起故園心。',64,'全唐诗/poet.song.148000.json','["濯濯才華耀禁林，翩然忽起故園心。", "九天得請恩方重，一舸東歸春未深。", "照眼湖山非昨夢，及時詩酒合同襟。", "不應便作真狂客，講殿行思聽履音。"]'),
('13e1f2e4-e16f-450f-862f-99878f4f5d1a','汪端彥聽雨軒','朱熹','宋','宋诗','song-poetry','','[]','詩問池堂春草夢，何如風雨對床詩。',64,'全唐诗/poet.song.148000.json','["詩問池堂春草夢，何如風雨對床詩。", "三薰三沐事斯語，難弟難兄此一時。", "爲母靜彈琴幾曲，遣盃同舉酒千卮。", "蘇公感寓多遊宦，豈不臨風尚爾思。"]'),
('83fd5dbe-4d24-4306-b26f-76c130ddb027','金榜山','朱熹','宋','宋诗','song-poetry','','[]','陳場老子讀書處，金榜山前石室中。',64,'全唐诗/poet.song.148000.json','["陳場老子讀書處，金榜山前石室中。", "人去石存猶昨日，鶑啼花落幾春風。", "藏修洞口雲空集，舒嘯巖幽草自茸。", "應喜斯文今不泯，紫陽秉筆紀前功。"]'),
('0c13eec7-63a0-49ee-ae9e-18dca4b0fa64','桃溪','朱熹','宋','宋诗','song-poetry','','[]','澗裏春泉響，種桃泉上頭。',24,'全唐诗/poet.song.148000.json','["澗裏春泉響，種桃泉上頭。", "爛紅紛委地，未肯出山流。"]'),
('d6ae4134-59df-4137-9121-e4c7c3132096','南塘','朱熹','宋','宋诗','song-poetry','','[]','南塘舊是尚書宅，今作僧居水石清。',32,'全唐诗/poet.song.148000.json','["南塘舊是尚書宅，今作僧居水石清。", "半夜月明禪定後，松風猶带管弦聲。"]'),
('c37f691e-53bc-4cba-b8b4-7751240e563e','詠南巖','朱熹','宋','宋诗','song-poetry','','[]','南巖兜率境，形勝自天成。',48,'全唐诗/poet.song.148000.json','["南巖兜率境，形勝自天成。", "崖雨楹前下，山雲殿後生。", "泉堪清病目，井可濯塵纓。", "五級峰頭立，何須步玉京。"]'),
('a73dd493-f541-4cfb-b3fe-e72c585c7827','挽王德修','朱熹','宋','宋诗','song-poetry','','[]','不到湖潭二十年，湖潭依舊故山川。',32,'全唐诗/poet.song.148000.json','["不到湖潭二十年，湖潭依舊故山川。", "聊將盃酒奠青草，風雨蕭蕭憶昔賢。"]'),
('eec9bd74-819b-41f6-a260-e3c0b1a77d36','仙霞嶺','朱熹','宋','宋诗','song-poetry','','[]','道出夷山鄉思生，霞峰重疊面前迎。',32,'全唐诗/poet.song.148000.json','["道出夷山鄉思生，霞峰重疊面前迎。", "嶺頭雲散丹梯聳，步到天衢眼更明。"]'),
('4f52fb35-0676-473a-80db-aa09e5c21190','重過南塘吊徐一平先生','朱熹','宋','宋诗','song-poetry','','[]','不到南塘久，重來二十年。',48,'全唐诗/poet.song.148000.json','["不到南塘久，重來二十年。", "山如龜背厚，地與馬鞍連。", "徐子舊書址，毛公新墓田。", "青松似相識，無語重凄然。"]'),
('5973df24-2313-4a71-a87c-ebc24cad0107','訪昂山支公故址','朱熹','宋','宋诗','song-poetry','','[]','支公肯與世相違，故結高堂在翠微。',64,'全唐诗/poet.song.148000.json','["支公肯與世相違，故結高堂在翠微。", "青菜漫隨流水去，黄彪時逐暮雲歸。", "喬林掛月猿來嘯，幽草生風鳥自飛。", "八萬妙門能測度，個中獨露祖師機。"]'),
('45c917a9-491e-4c35-9874-d6543438e002','詠一滴泉','朱熹','宋','宋诗','song-poetry','','[]','遥望南巖百尺崗，青山疊疊樹蒼蒼。',64,'全唐诗/poet.song.148000.json','["遥望南巖百尺崗，青山疊疊樹蒼蒼。", "題詩壁上雲生石，入定巖前石作房。", "一竅有靈通地脈，半空無雨滴天漿。", "鵝湖此去無多路，肯借山間結草堂。"]'),
('7ceadcf0-1cad-4e4b-af17-5d5645a416e7','題景范廬','朱熹','宋','宋诗','song-poetry','','[]','非棄清明樂隠居，特因景范面鴛湖。',64,'全唐诗/poet.song.148000.json','["非棄清明樂隠居，特因景范面鴛湖。", "觀瀾興罷春風軟，濯足歌殘夜月孤。", "照貌不須臨玉鏡，洗心常得近冰壺。", "幾回魚躍鳶飛際，識破中庸率性圖。"]'),
('bb267f00-8c45-4d35-86c6-bfeb22d7e7df','題爛柯山','朱熹','宋','宋诗','song-poetry','','[]','局上閑爭戰，人間任是非。',24,'全唐诗/poet.song.148000.json','["局上閑爭戰，人間任是非。", "空教採樵客，柯爛不知歸。"]'),
('9a0fcd03-ac0c-4cbd-a26e-32b9c19277ba','書邵子堯夫遊伊洛四首  其一','朱熹','宋','宋诗','song-poetry','','[]','六日驅車出上陽，初程便宿水雲鄉。',32,'全唐诗/poet.song.148000.json','["六日驅車出上陽，初程便宿水雲鄉。", "更聞數弄神仙曲，始信壺中日月長。"]'),
('632a6b2d-d51d-4d8a-a293-13a762d25de7','書邵子堯夫遊伊洛四首  其二','朱熹','宋','宋诗','song-poetry','','[]','七日南觀噴玉泉，千峰萬峰遥相連。',32,'全唐诗/poet.song.148000.json','["七日南觀噴玉泉，千峰萬峰遥相連。", "中間一道長如雪，飛落寒潭不記年。"]'),
('b1bc6edb-fe4d-42eb-afcb-40f5d0f87e5f','書邵子堯夫遊伊洛四首  其三','朱熹','宋','宋诗','song-poetry','','[]','秋日□秋禾黍邊，農家富貴自豐年。',32,'全唐诗/poet.song.148000.json','["秋日□秋禾黍邊，農家富貴自豐年。", "一簞鷄黍一瓢飲，誰羨王侯食萬錢。"]'),
('2cfdfa76-8221-4a49-817f-e7efc4f26fb2','書邵子堯夫遊伊洛四首  其四','朱熹','宋','宋诗','song-poetry','','[]','烟嵐一簇峙崔嵬，到此令人心自灰。',32,'全唐诗/poet.song.148000.json','["烟嵐一簇峙崔嵬，到此令人心自灰。", "上有神仙不知姓，洞門閑倚白雲開。"]'),
('ff6500b0-4d85-4f87-b0d5-c2f8f96b3c75','訪竹溪先生','朱熹','宋','宋诗','song-poetry','','[]','路逢個老翁，自負柴一束。',48,'全唐诗/poet.song.148000.json','["路逢個老翁，自負柴一束。", "烏巾插在腰，背手牽黄犢。", "借問何處居，指點破茅屋。", "午鷄啼短牆，麥飯方炊熟。"]'),
